// Transform FDA FAERS response into signals_mesh format (robust)
const items = $input.all();
const results = [];
const runCtx = $('🔧 Init Run Context').first()?.json || {};
const watchlist = Array.isArray(runCtx.oncology_drugs) ? runCtx.oncology_drugs.map(w => String(w).toLowerCase()) : [];

// Helpers
function asString(v) {
  if (v === undefined || v === null) return '';
  if (Array.isArray(v)) return v.join(' ');
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

function safeLower(s) {
  return asString(s).toLowerCase();
}

for (const item of items) {
  const events = item?.json?.results;
  if (!Array.isArray(events) || events.length === 0) continue;

  for (const evt of events) {
    const safetyReportId = asString(evt.safetyreportid);
    if (!safetyReportId) continue; // skip unusable events

    const patient = evt.patient || {};

    // Drugs (array of strings)
    const drugs = Array.isArray(patient.drug)
      ? patient.drug.map(d => {
          const med = d?.medicinalproduct;
          const gen = d?.openfda?.generic_name?.[0];
          const brand = d?.openfda?.brand_name?.[0];
          return asString(med || gen || brand || 'unknown').trim();
        }).filter(Boolean)
      : [];

    // Reactions (array of strings)
    const reactions = Array.isArray(patient.reaction)
      ? patient.reaction.map(r => asString(r.reactionmeddrapt).trim()).filter(Boolean)
      : [];

    // Seriousness flags – normalize to string
    const seriousRaw = asString(evt.serious);
    const isSerious = seriousRaw === '1' || seriousRaw === '2' || seriousRaw === '3'; // FAERS codes
    const isDeath = asString(evt.seriousnessdeath) === '1';
    const isLifeThreatening = asString(evt.seriousnesslifethreatening) === '1';
    const isHospitalization = asString(evt.seriousnesshospitalization) === '1';

    // Impact level & score
    let impactLevel = 'LOW';
    let impactScore = 3.0;

    if (isDeath) { impactLevel = 'HIGH'; impactScore = 9.5; }
    else if (isLifeThreatening) { impactLevel = 'HIGH'; impactScore = 8.5; }
    else if (isHospitalization) { impactLevel = 'MED'; impactScore = 6.0; }
    else if (isSerious) { impactLevel = 'MED'; impactScore = 5.0; }

    // Watchlist check (any suspect drug contains any watchlist term)
    const drugLower = drugs.map(d => safeLower(d));
    const isWatchlisted = drugLower.some(d =>
      watchlist.some(w => d.includes(w))
    );
    if (isWatchlisted) impactScore += 1.5;

    // Cap score
    impactScore = Math.min(impactScore, 10.0);

    // Route tier
    let routeTier = 'T3_MONITOR';
    if (impactLevel === 'HIGH') routeTier = 'T1_CRITICAL';
    else if (impactLevel === 'MED') routeTier = 'T2_REVIEW';

    // Notification priority
    let notifPriority = 'P5';
    if (isDeath && isWatchlisted) notifPriority = 'P0';
    else if (isDeath) notifPriority = 'P1';
    else if (isLifeThreatening) notifPriority = 'P2';
    else if (isHospitalization) notifPriority = 'P3';
    else if (isSerious) notifPriority = 'P4';

    // Core fields
    const primaryDrug = drugs[0] || 'Unknown';
    const primaryReaction = reactions[0] || 'Unknown reaction';

    const title = `FAERS: ${primaryDrug} — ${primaryReaction}`;
    const summary =
      `Serious AE report #${safetyReportId}: ${drugs.join(', ') || 'No drugs'} ` +
      `→ ${reactions.join(', ') || 'No reactions'}. ` +
      `Death: ${isDeath ? 'Yes' : 'No'}, Life-threatening: ${isLifeThreatening ? 'Yes' : 'No'}, ` +
      `Hospitalization: ${isHospitalization ? 'Yes' : 'No'}`;

    const occurCountry = asString(evt.occurcountry);
    const receiveDate = asString(evt.receivedate);

    // Fingerprint & dedup hash
    const fpRaw = `safety|${primaryDrug}|safety_signal|faers|${safetyReportId}`;
    const dedupRaw = `faers_${safetyReportId}|${reactions.slice(0, 3).join(',')}`;

    // Quality score = count of important fields * 2
    const qualityScore = [
      safetyReportId,
      primaryDrug,
      primaryReaction,
      occurCountry,
      receiveDate
    ].filter(Boolean).length * 2;

    // Score breakdown
    const score_breakdown = {
      seriousness: isSerious ? 3 : 0,
      death: isDeath ? 4 : 0,
      watchlisted: isWatchlisted ? 1.5 : 0,
      quality: qualityScore,
      source_weight: 1.0
    };

    results.push({
      json: {
        signal_domain: 'safety',
        signal_type: 'safety_signal',
        source_id: `faers_${safetyReportId}`,
        source: 'faers',
        title,
        summary,
        entity_name: primaryDrug,
        drug_name: primaryDrug,
        indication: reactions.join('; '),
        sponsor: evt.companynumb ? `Mfr #${evt.companynumb}` : '',
        geography: occurCountry,
        url: `https://api.fda.gov/drug/event.json?search=safetyreportid:${safetyReportId}`,
        impact_level: impactLevel,
        impact_score: impactScore,
        route_tier: routeTier,
        notif_priority: notifPriority,
        competitor_flag: isWatchlisted,
        is_urgent: isDeath || isLifeThreatening,
        confidence: isSerious ? 'high' : 'medium',
        fingerprint: fpRaw,
        dedup_hash: dedupRaw,
        quality_score: qualityScore,
        score_breakdown,
        raw_text: JSON.stringify(evt).substring(0, 2000)
      }
    });
  }
}

return results;

const items = $input.all();
const newCount = items.filter(i => i.json.is_new === true).length;
const updatedCount = items.filter(i => i.json.is_new === false).length;
return [{
  json: {
    source: 'fda_faers',
    fetched: items.length,
    new: newCount,
    updated: updatedCount,
    deduped: updatedCount,
    errors: 0
  }
}];

// Log error to dead letter queue via next PG node
const error = $input.first();
return [{
  json: {
    source_workflow: 'WF1_Ingestion',
    source_node: 'FDA FAERS API',
    failed_payload: JSON.stringify(error.json || {}),
    error_message: error.json?.message || error.json?.error || 'FAERS API call failed',
    source: 'fda_faers'
  }
}];

const items = $input.all();
const results = [];
const watchlist = $('🔧 Init Run Context').first().json.oncology_drugs || [];

for (const item of items) {
  const events = item.json.results || [];
  for (const evt of events) {
    const recallId = evt.recall_number || evt.event_id || '';
    const drugName = (evt.openfda?.generic_name?.[0]) || evt.product_description?.split(' ')[0] || '';
    const classification = evt.classification || '';

    let impactLevel = 'LOW';
    let impactScore = 3.0;
    if (classification === 'Class I') { impactLevel = 'HIGH'; impactScore = 9.0; }
    else if (classification === 'Class II') { impactLevel = 'MED'; impactScore = 6.0; }
    else if (classification === 'Class III') { impactLevel = 'LOW'; impactScore = 3.0; }

    const isWatchlisted = watchlist.some(w => drugName.toLowerCase().includes(w));
    if (isWatchlisted) impactScore += 1.5;

    let routeTier = 'T3_MONITOR';
    if (impactLevel === 'HIGH') routeTier = 'T1_CRITICAL';
    else if (impactLevel === 'MED') routeTier = 'T2_REVIEW';

    results.push({ json: {
      signal_domain: 'safety', signal_type: 'recall',
      source_id: 'recall_' + recallId, source: 'fda_enforcement',
      title: `FDA Recall (${classification}): ${evt.product_description?.substring(0,100) || drugName}`,
      summary: `${classification} recall. Reason: ${evt.reason_for_recall || 'N/A'}. Status: ${evt.status || 'Ongoing'}. Distribution: ${evt.distribution_pattern || 'N/A'}`,
      entity_name: drugName, drug_name: drugName,
      geography: evt.state || evt.country || 'US',
      sponsor: evt.recalling_firm || '',
      url: 'https://api.fda.gov/drug/enforcement.json?search=recall_number:' + recallId,
      impact_level: impactLevel, impact_score: Math.min(impactScore, 10.0),
      route_tier: routeTier,
      notif_priority: impactLevel === 'HIGH' ? 'P1' : impactLevel === 'MED' ? 'P3' : 'P5',
      competitor_flag: isWatchlisted, is_urgent: classification === 'Class I',
      confidence: 'high',
      fingerprint: 'safety|' + drugName + '|recall|fda_enforcement|' + recallId,
      dedup_hash: 'recall_' + recallId,
      quality_score: 8,
      score_breakdown: { classification_weight: impactLevel === 'HIGH' ? 4 : 2, watchlisted: isWatchlisted ? 1.5 : 0 },
      raw_text: JSON.stringify(evt).substring(0, 2000)
    }});
  }
}
return results;

const items = $input.all();
const results = [];
const watchlist = $('🔧 Init Run Context').first().json.oncology_drugs || [];

for (const item of items) {
  const studies = item.json.studies || [];
  for (const study of studies) {
    const proto = study.protocolSection || {};
    const id_module = proto.identificationModule || {};
    const status_module = proto.statusModule || {};
    const design_module = proto.designModule || {};
    const sponsor_module = proto.sponsorCollaboratorsModule || {};
    const conditions_module = proto.conditionsModule || {};
    const interventions_module = proto.armsInterventionsModule || {};

    const nctId = id_module.nctId || '';
    const title = id_module.briefTitle || id_module.officialTitle || '';
    const status = status_module.overallStatus || '';
    const phase = (design_module.phases || []).join(', ') || 'N/A';
    const sponsor = sponsor_module.leadSponsor?.name || '';
    const conditions = (conditions_module.conditions || []).join('; ');
    const interventions = (interventions_module.interventions || []).map(i => i.name).join('; ');

    // Impact scoring based on phase
    let impactScore = 3.0;
    let impactLevel = 'LOW';
    if (phase.includes('3') || phase.includes('PHASE3')) { impactScore = 7.0; impactLevel = 'MED'; }
    else if (phase.includes('2') || phase.includes('PHASE2')) { impactScore = 5.0; impactLevel = 'MED'; }
    else if (phase.includes('4') || phase.includes('PHASE4')) { impactScore = 6.0; impactLevel = 'MED'; }
    else if (phase.includes('1') || phase.includes('PHASE1')) { impactScore = 3.5; impactLevel = 'LOW'; }

    // Check watchlist
    const interventionLower = interventions.toLowerCase();
    const isWatchlisted = watchlist.some(w => interventionLower.includes(w) || title.toLowerCase().includes(w));
    if (isWatchlisted) { impactScore += 2.0; if (impactLevel === 'LOW') impactLevel = 'MED'; }

    // Status-based boost
    if (status === 'NOT_YET_RECRUITING') impactScore += 0.5;

    let routeTier = 'T3_MONITOR';
    if (impactScore >= 7) routeTier = 'T1_CRITICAL';
    else if (impactScore >= 5) routeTier = 'T2_REVIEW';

    results.push({ json: {
      signal_domain: 'ci', signal_type: 'trial_update',
      source_id: nctId, source: 'clinicaltrials',
      title: `CT: [${phase}] ${title.substring(0,200)}`,
      summary: `${status} | Phase: ${phase} | Sponsor: ${sponsor} | Conditions: ${conditions} | Interventions: ${interventions}`,
      entity_name: interventions.split(';')[0]?.trim() || '',
      drug_name: interventions.split(';')[0]?.trim() || '',
      nct_id: nctId,
      indication: conditions,
      sponsor: sponsor,
      phase: phase,
      status: status,
      url: 'https://clinicaltrials.gov/study/' + nctId,
      impact_level: impactLevel, impact_score: Math.min(impactScore, 10.0),
      route_tier: routeTier,
      notif_priority: impactLevel === 'HIGH' ? 'P2' : impactLevel === 'MED' ? 'P4' : 'P5',
      competitor_flag: isWatchlisted, is_urgent: false,
      confidence: 'high',
      fingerprint: 'ci|' + (interventions.split(';')[0]?.trim() || '') + '|trial_update|clinicaltrials|' + nctId,
      dedup_hash: nctId + '|' + status,
      quality_score: [nctId, title, status, phase, sponsor, conditions].filter(Boolean).length + 2,
      score_breakdown: { phase_weight: impactScore - (isWatchlisted ? 2 : 0), watchlisted: isWatchlisted ? 2 : 0, status_boost: status === 'NOT_YET_RECRUITING' ? 0.5 : 0 },
      raw_text: JSON.stringify(study).substring(0, 2000)
    }});
  }
}
return results;

// ============================================================
// NODE: ⚙️ Extract PubMed IDs (Robust, for data.esearchresult)
// ============================================================

const item = $input.first();
const body = item.json || {};

// 0) Unwrap esearchresult
const result = body.data?.esearchresult || {};

// 0a) Handle explicit NCBI ERROR
if (typeof result.ERROR === 'string' && result.ERROR.trim()) {
  return [{
    json: {
      skip: true,
      skip_reason: 'esearch_error',
      api_error: result.ERROR,
      search_term: body.search_term || '',
      pmids: [],
      pmid_count: 0,
      total_count: 0,
      extracted_at: new Date().toISOString(),
    }
  }];
}

// 1) Core fields
const rawIdList = Array.isArray(result.idlist) ? result.idlist : [];

const totalCount = Number.isFinite(Number(result.count))
  ? Number(result.count)
  : 0;

const retmax   = Number.isFinite(Number(result.retmax))   ? Number(result.retmax)   : rawIdList.length;
const retstart = Number.isFinite(Number(result.retstart)) ? Number(result.retstart) : 0;

const webEnv   = result.webenv   || '';
const queryKey = result.querykey || '1';

// 2) Warnings / errors metadata
const phraseErrors   = Array.isArray(result.errorlist?.phraseerrors)
  ? result.errorlist.phraseerrors
  : [];

const quotedPhrases  = Array.isArray(result.warninglist?.quotedphrasesnotfound)
  ? result.warninglist.quotedphrasesnotfound
  : [];

const outputMessages = Array.isArray(result.warninglist?.outputmessages)
  ? result.warninglist.outputmessages
  : [];

// 3) Normalise PMIDs (numeric, unique, capped)
const MAX_PMIDS = 200;
const cleanPmids = Array.from(
  new Set(
    rawIdList
      .map(id => String(id).trim())
      .filter(id => id.length > 0 && /^\d+$/.test(id))
  )
).slice(0, MAX_PMIDS);

// 4) Skip logic
let skip = false;
let skip_reason = null;

if (phraseErrors.length > 0) {
  skip = true;
  skip_reason = 'ncbi_phrase_error';
} else if (totalCount === 0) {
  skip = true;
  skip_reason = 'no_results';
} else if (cleanPmids.length === 0 && totalCount > 0) {
  skip = true;
  skip_reason = 'idlist_empty_inconsistent';
}

const has_more = totalCount > (retstart + retmax);

// 5) Batch for EFetch (20 per call)
const BATCH_SIZE = 20;
const all_batches = [];
for (let i = 0; i < cleanPmids.length; i += BATCH_SIZE) {
  all_batches.push(cleanPmids.slice(i, i + BATCH_SIZE));
}

const current_batch_index = 0;
const current_batch = all_batches[0] || [];
const current_batch_str = current_batch.join(',');

// 6) SINGLE getContext function
function getContext() {
  try {
    const ctxNode = $('build search term code').first().json;
    return {
      asset_id:    ctxNode.asset_id    || ctxNode.id || 'unknown',
      asset_name:  ctxNode.asset_name  || ctxNode.name || '',
      drug_name:   ctxNode.drug_name   || ctxNode.name || '',
      indication:  ctxNode.indication  || '',
      search_term: ctxNode.search_term || '',
    };
  } catch (e) {
    return {
      asset_id:    body.asset_id    || 'unknown',
      asset_name:  body.asset_name  || '',
      drug_name:   body.drug_name   || body.name || '',
      indication:  body.indication  || '',
      search_term: body.search_term || '',
    };
  }
}

// Call it ONCE
const ctx = getContext();

// 7) Build final output
const out = {
  skip,
  skip_reason,

  pmids: cleanPmids,
  pmid_count: cleanPmids.length,
  total_count: totalCount,

  all_batches,
  batch_count: all_batches.length,
  current_batch_index,
  current_batch,
  current_batch_str,

  retmax,
  retstart,
  has_more,

  webEnv,
  queryKey,

  ncbi_phrase_errors: phraseErrors,
  ncbi_quoted_issues: quotedPhrases,
  ncbi_warnings: outputMessages,

  asset_id:    ctx.asset_id,
  asset_name:  ctx.asset_name,
  drug_name:   ctx.drug_name,
  indication:  ctx.indication,
  search_term: ctx.search_term,

  esearch_raw: {
    count: result.count,
    retmax: result.retmax,
    retstart: result.retstart,
    querytranslation: result.querytranslation,
  },
  extracted_at: new Date().toISOString(),
};

return [{ json: out }];

const mergedItems = $('🔗 Merge All Counts').all();
const runCtx = $('🔧 Init Run Context').first().json;

let totalFetched = 0, totalNew = 0, totalUpdated = 0, totalErrors = 0;
const sourceDetails = [];

for (const item of mergedItems) {
  const d = item.json;
  totalFetched += (d.fetched || 0);
  totalNew += (d.new || 0);
  totalUpdated += (d.updated || 0);
  totalErrors += (d.errors || 0);
  sourceDetails.push(`• ${d.source}: ${d.fetched} fetched, ${d.new} new, ${d.updated} updated`);
}

const status = totalErrors > 0 ? '⚠️ PARTIAL' : '✅ SUCCESS';

return [{
  json: {
    run_id: runCtx.run_id,
    status: status,
    total_fetched: totalFetched,
    total_new: totalNew,
    total_updated: totalUpdated,
    total_errors: totalErrors,
    source_details: sourceDetails,
    summary_text: `${status} | WF1 Run ${runCtx.run_id}\nFetched: ${totalFetched} | New: ${totalNew} | Updated: ${totalUpdated} | Errors: ${totalErrors}\n\n${sourceDetails.join('\n')}`,
    finished_at: new Date().toISOString()
  }
}];

// ============================================================
// 🧬 Transform FDA Labels — v3.1.0
// PharmaOS Pipeline | Domain: regulatory
// Scoring Engine: Multi-dimensional weighted scoring
// Handles: NDA/BLA/ANDA/OTC/Homeopathic/REMS/Boxed Warning
// Schema Target: signals_mesh v2.0.0
// ============================================================

const PIPELINE_VERSION = '3.1.0';
const SCORING_VERSION  = 2;

// ─────────────────────────────────────────────────────────────
// SECTION 1: CONSTANTS & DICTIONARIES
// ─────────────────────────────────────────────────────────────

const HIGH_VALUE_INDICATIONS = new Set([
  'cancer','carcinoma','tumor','tumour','leukemia','lymphoma',
  'melanoma','myeloma','sarcoma','glioma','glioblastoma',
  'nsclc','lung cancer','breast cancer','colorectal','ovarian',
  'prostate cancer','hepatocellular','renal cell','bladder cancer',
  'pancreatic cancer','cervical cancer','endometrial','cholangiocarcinoma',
  'autoimmune','multiple sclerosis','rheumatoid arthritis',
  'psoriasis','crohn','ulcerative colitis','alzheimer','dementia',
  'parkinson','rare disease','orphan','aml','cll','cml',
  'atrial fibrillation','heart failure','stroke prevention',
  'hiv','hepatitis','tuberculosis','covid'
]);

const HIGH_RISK_SAFETY_TERMS = new Set([
  'black box warning','boxed warning','rems','risk evaluation',
  'fatal','death','serious adverse','life-threatening',
  'contraindicated','contraindication','severe hepatotoxicity',
  'anaphylaxis','suicidal ideation','suicide','embryo-fetal toxicity',
  'teratogenic','carcinogenicity','cardiac arrest','torsade de pointes',
  'agranulocytosis','stevens-johnson','toxic epidermal necrolysis',
  'hepatic failure','renal failure','respiratory failure',
  'withdrawal seizure','serotonin syndrome','neuroleptic malignant',
  'qT prolongation','sudden death','pulmonary embolism',
  'severe cutaneous','drug reaction with eosinophilia'
]);

const STRATEGIC_SPONSORS = new Set([
  'merck','pfizer','bristol-myers','bms','roche','genentech',
  'astrazeneca','novartis','sanofi','abbvie','johnson & johnson',
  'janssen','eli lilly','lilly','boehringer','amgen','biogen',
  'regeneron','gilead','moderna','biontech','takeda',
  'daiichi sankyo','seagen','incyte','blueprint medicines',
  'agenus','immunomedics','spectrum pharmaceuticals','exelixis',
  'exact sciences','mirati','g1 therapeutics','athenex'
]);

const MODALITY_MAP = [
  ['monoclonal antibody',   'biologic'],
  ['checkpoint inhibitor',  'biologic'],
  ['pd-1',                  'biologic'],
  ['pd-l1',                 'biologic'],
  ['fusion protein',        'biologic'],
  ['enzyme replacement',    'biologic'],
  ['car-t',                 'cell_therapy'],
  ['cell therapy',          'cell_therapy'],
  ['gene therapy',          'gene_therapy'],
  ['antisense oligonucle',  'RNA'],
  ['sirna',                 'RNA'],
  ['mrna',                  'RNA'],
  ['kinase inhibitor',      'small_molecule'],
  ['small molecule',        'small_molecule'],
  ['hormone',               'small_molecule'],
  ['radiopharmaceutical',   'radiopharmaceutical'],
  ['vaccine',               'biologic'],
];

const LABEL_SECTION_KEYS = [
  'indications_and_usage','warnings','contraindications',
  'adverse_reactions','drug_interactions','dosage_and_administration',
  'mechanism_of_action','pharmacokinetics','clinical_studies',
  'use_in_specific_populations','overdosage','description',
  'active_ingredient','pregnancy_or_breast_feeding',
  'stop_use','do_not_use','storage_and_handling',
  'package_label_principal_display_panel','boxed_warning'
];

const OTC_SKIP_WORDS = new Set([
  'mini-label','label-pellets','blister-pack','carton-pack',
  'tablet','capsule','pack','label','pellets','blister','carton'
]);

const TIER_TO_PRIORITY = {
  T1_CRITICAL: 'P1',
  T2_REVIEW:   'P3',
  T3_MONITOR:  'P5',
};

const TIER_TO_CHANNELS = {
  T1_CRITICAL: ['pharmaos-critical','pharmaos-executive','medical-affairs'],
  T2_REVIEW:   ['pharmaos-regulatory','ci-team'],
  T3_MONITOR:  ['pharmaos-digest'],
};

const TIER_TTL = {
  T1_CRITICAL: 90,
  T2_REVIEW:   60,
  T3_MONITOR:  30,
};

// ─────────────────────────────────────────────────────────────
// SECTION 2: UTILITY HELPERS
// ─────────────────────────────────────────────────────────────

const safe = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  return String(v).replace(/[\x00-\x1F\x7F-\x9F]/g, '').trim() || fallback;
};

const safeArr = (v) => {
  if (Array.isArray(v)) return v.map(String).filter(Boolean);
  if (typeof v === 'string' && v.trim()) return [v.trim()];
  return [];
};

const joinArr = (arr, sep = ' ') =>
  safeArr(arr).join(sep).trim();

const clamp = (n, min, max) =>
  Math.max(min, Math.min(max, Number(n) || 0));

const truncate = (str, len) =>
  !str ? '' : String(str).length > len ? String(str).slice(0, len) : String(str);

const containsAny = (text, termSet) => {
  const lower = String(text).toLowerCase();
  for (const term of termSet) {
    if (lower.includes(term)) return true;
  }
  return false;
};

const countMatches = (text, termSet) => {
  const lower = String(text).toLowerCase();
  let n = 0;
  for (const term of termSet) {
    if (lower.includes(term)) n++;
  }
  return n;
};

const extractNctId = (text) => {
  const m = String(text).match(/NCT\d{8}/i);
  return m ? m[0].toUpperCase() : null;
};

const daysFromNow = (days) => {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.toISOString();
};

const formatEffectiveDate = (raw) =>
  safe(raw).replace(/^(\d{4})(\d{2})(\d{2})$/, '$1-$2-$3');

// ─────────────────────────────────────────────────────────────
// SECTION 3: FIELD EXTRACTORS
// ─────────────────────────────────────────────────────────────

function extractDrugName(raw, ofda) {
  // Priority 1: standard openFDA paths
  const standard =
    safeArr(ofda.brand_name)[0]     ||
    safeArr(ofda.generic_name)[0]   ||
    safeArr(ofda.substance_name)[0] ||
    safe(raw.brand_name)            ||
    safe(raw.generic_name);
  if (standard) return standard.toUpperCase().trim();

  // Priority 2: active_ingredient (OTC / homeopathic)
  // e.g. "ACTIVE INGREDIENT SILICEA HPUS 2X and higher"
  const activeIngText = joinArr(raw.active_ingredient || []);
  if (activeIngText) {
    const cleaned = activeIngText
      .replace(/active\s+ingredient[s]?/gi, '')
      .replace(/HPUS\s*[\dXCMQ]+[A-Z]*/gi, '')
      .replace(/and\s+higher/gi, '')
      .replace(/\d+%/g, '')
      .replace(/\s+/g, ' ')
      .trim();
    if (cleaned.length > 1) return cleaned.toUpperCase();
  }

  // Priority 3: package_label (last resort)
  const pkgLabel = joinArr(raw.package_label_principal_display_panel || []);
  if (pkgLabel) {
    const token = pkgLabel.split(/[\s\-]+/)
      .find(t => t.length > 3 && !OTC_SKIP_WORDS.has(t.toLowerCase()));
    if (token) return token.toUpperCase();
  }

  return 'Unknown';
}

function extractSponsor(raw, ofda) {
  return safe(
    safeArr(ofda.manufacturer_name)[0] ||
    safeArr(ofda.labeler_name)[0]      ||
    safeArr(ofda.applicant)[0]         ||
    raw.labeler_name                   ||
    raw.sponsor_name                   ||
    raw.manufacturer                   ||
    ''
  );
}

function extractIndication(raw, drugName, isHomeopathic) {
  // Standard paths
  const standard = [
    joinArr(raw.indications_and_usage),
    joinArr(raw.purpose),
    joinArr(raw.indications),
  ].find(s => s.length > 10 && !s.toLowerCase().includes('condition listed'));

  if (standard) return truncate(standard, 500);

  // Homeopathic OTC fallback
  if (isHomeopathic) {
    const activeIng = joinArr(raw.active_ingredient || []);
    const substance = activeIng
      .replace(/active\s+ingredient[s]?/gi, '')
      .replace(/HPUS.*/gi, '')
      .trim();
    const stopUse   = joinArr(raw.stop_use || []);
    const purpose   = joinArr(raw.purpose  || []);
    const parts     = [
      substance  ? `Homeopathic: ${substance}` : '',
      purpose,
      stopUse,
    ].filter(Boolean).join('. ');
    return truncate(parts, 500);
  }

  // Generic OTC: use stop_use + do_not_use as proxy
  const otcProxy = [
    joinArr(raw.purpose || []),
    joinArr(raw.stop_use || []),
  ].filter(Boolean).join('. ');
  return truncate(otcProxy, 500);
}

function extractMoa(raw) {
  return truncate(joinArr(raw.mechanism_of_action || []), 500);
}

function extractUrl(raw, ofda) {
  const setId  = safe(raw.set_id || raw.id);
  const appNum = safe(safeArr(ofda.application_number)[0] || '');
  if (setId)  return `https://dailymed.nlm.nih.gov/dailymed/lookup.cfm?setid=${setId}`;
  if (appNum) {
    const digits = appNum.replace(/[^0-9]/g, '');
    return `https://www.accessdata.fda.gov/scripts/cder/daf/index.cfm?event=overview.process&ApplNo=${digits}`;
  }
  return '';
}

function extractPhase(appNum, raw, isHomeopathic) {
  if (appNum.startsWith('NDA'))  return 'Approved (NDA)';
  if (appNum.startsWith('BLA'))  return 'Approved (BLA)';
  if (appNum.startsWith('ANDA')) return 'Approved (Generic)';
  if (appNum.startsWith('IND'))  return 'Investigational';
  if (appNum)                    return 'Approved';
  if (isHomeopathic)             return 'OTC Homeopathic';
  return 'OTC';
}

function extractNctIdFromRaw(raw) {
  const sources = [
    joinArr(raw.clinical_studies  || []),
    joinArr(raw.clinical_trials   || []),
    safe(raw.raw_text              || ''),
    joinArr(raw.description        || []),
  ];
  for (const src of sources) {
    const nct = extractNctId(src);
    if (nct) return nct;
  }
  return null;
}

function resolveModality(pharmClasses) {
  const combined = pharmClasses.join(' ').toLowerCase();
  for (const [key, val] of MODALITY_MAP) {
    if (combined.includes(key)) return val;
  }
  return '';
}

// ─────────────────────────────────────────────────────────────
// SECTION 4: SCORING ENGINE
// ─────────────────────────────────────────────────────────────
//
//  Dimension              Max     What Drives It
//  ─────────────────────────────────────────────
//  1. Field Completeness  2.0     drug/indication/sponsor/moa/url
//  2. Regulatory Weight   2.0     NDA/BLA + boxed warning + REMS
//  3. Indication Value    2.0     match vs 30+ strategic areas
//  4. Safety Risk         2.0     match vs 25+ high-risk terms
//  5. Competitor Signal   1.0     sponsor in strategic list
//  6. Content Richness    1.0     raw_text length + label sections
//  OTC/Homeopathic penalty -0.5   (waived if safety signal exists)
//  ─────────────────────────────────────────────
//  TOTAL (max)            10.0
// ─────────────────────────────────────────────────────────────

function scoreSignal({
  drug_name, indication, sponsor, moa, url,
  appNum, hasBoxedWarning, remsRequired,
  pharmClasses, rawText, labelSections,
  adverseReactions, isHomeopathic, hpusPotency,
}) {
  const bd = {}; // breakdown

  const fullSafetyText =
    `${rawText} ${joinArr(adverseReactions)}`.toLowerCase();
  const fullIndText =
    `${indication} ${rawText}`.toLowerCase();

  // ── 1. Field Completeness (0–2.0) ──────────────────────
  let completeness = 0;
  if (drug_name && drug_name !== 'Unknown') completeness += 0.5;
  if (indication && indication.length > 20)  completeness += 0.5;
  if (sponsor    && sponsor.length > 2)      completeness += 0.3;
  if (moa        && moa.length > 20)         completeness += 0.4;
  if (url)                                   completeness += 0.3;
  completeness = clamp(completeness, 0, 2.0);
  bd.completeness = +completeness.toFixed(2);

  // ── 2. Regulatory Weight (0–2.0) ───────────────────────
  let regWeight = 0;
  if      (appNum.startsWith('NDA') || appNum.startsWith('BLA')) regWeight += 1.0;
  else if (appNum.startsWith('ANDA'))                              regWeight += 0.4;
  else if (appNum)                                                 regWeight += 0.2;
  if (hasBoxedWarning) regWeight += 0.7;
  if (remsRequired)    regWeight += 0.3;
  regWeight = clamp(regWeight, 0, 2.0);
  bd.regulatory_weight = +regWeight.toFixed(2);

  // ── 3. Indication Value (0–2.0) ─────────────────────────
  const indHits = countMatches(fullIndText, HIGH_VALUE_INDICATIONS);
  const indValue =
    indHits >= 3         ? 2.0 :
    indHits === 2        ? 1.5 :
    indHits === 1        ? 1.0 :
    indication.length > 50 ? 0.5 : 0;
  bd.indication_value = +indValue.toFixed(2);
  bd.indication_hits  = indHits;

  // ── 4. Safety Risk (0–2.0) ──────────────────────────────
  const safetyHits = countMatches(fullSafetyText, HIGH_RISK_SAFETY_TERMS);
  let safetyScore =
    safetyHits >= 4  ? 2.0 :
    safetyHits >= 2  ? 1.5 :
    safetyHits === 1 ? 1.0 :
    hasBoxedWarning  ? 1.0 : 0;
  safetyScore = clamp(safetyScore, 0, 2.0);
  bd.safety_risk        = +safetyScore.toFixed(2);
  bd.safety_terms_found = safetyHits;
  bd.has_boxed_warning  = hasBoxedWarning;
  bd.rems_required      = remsRequired;

  // ── 5. Competitor Signal (0–1.0) ────────────────────────
  const sponsorLower = sponsor.toLowerCase();
  let compScore = 0;
  for (const s of STRATEGIC_SPONSORS) {
    if (sponsorLower.includes(s)) { compScore = 1.0; break; }
  }
  bd.competitor_signal = +compScore.toFixed(2);

  // ── 6. Content Richness (0–1.0) ─────────────────────────
  let richness =
    rawText.length > 3000  ? 1.0 :
    rawText.length > 1500  ? 0.7 :
    rawText.length > 500   ? 0.4 :
    rawText.length > 100   ? 0.2 : 0;
  if (labelSections >= 7)       richness = Math.min(1.0, richness + 0.3);
  else if (labelSections >= 4)  richness = Math.min(1.0, richness + 0.1);
  bd.content_richness = +richness.toFixed(2);
  bd.label_sections   = labelSections;
  bd.raw_text_length  = rawText.length;

  // ── OTC / Homeopathic Penalty ────────────────────────────
  let otcPenalty = 0;
  if (isHomeopathic) {
    // Waive penalty if genuine safety signal exists
    otcPenalty = (hasBoxedWarning || safetyScore >= 1.0) ? 0 : -0.5;
  }
  bd.otc_homeopathic = isHomeopathic;
  bd.hpus_potency    = hpusPotency || null;
  bd.otc_penalty     = +otcPenalty.toFixed(2);
  bd.app_number      = appNum || null;

  // ── Composite Score ──────────────────────────────────────
  const rawScore =
    completeness + regWeight + indValue +
    safetyScore  + compScore + richness +
    otcPenalty;

  const impact_score = clamp(parseFloat(rawScore.toFixed(2)), 0, 10);
  bd.total = impact_score;

  // ── Quality Score (0–10 int, field completeness) ─────────
  const quality_score = clamp(
    (drug_name !== 'Unknown' ? 2 : 0) +
    (indication.length > 20  ? 2 : 0) +
    (sponsor                 ? 1 : 0) +
    (moa.length > 20         ? 1 : 0) +
    (url                     ? 1 : 0) +
    (appNum                  ? 1 : 0) +
    (rawText.length > 200    ? 1 : 0) +
    (labelSections >= 3      ? 1 : 0),
    0, 10
  );

  // ── Impact Level (safety floor: boxed warning → min MED) ─
  const impact_level =
    impact_score >= 7.0              ? 'HIGH' :
    impact_score >= 4.0              ? 'MED'  :
    hasBoxedWarning                  ? 'MED'  : 'LOW';

  // ── Route Tier ───────────────────────────────────────────
  const route_tier =
    (impact_level === 'HIGH') ||
    (hasBoxedWarning && compScore > 0) ? 'T1_CRITICAL' :
    (impact_level === 'MED') ||
    hasBoxedWarning                    ? 'T2_REVIEW'   : 'T3_MONITOR';

  // ── Derived flags ────────────────────────────────────────
  const is_urgent      = hasBoxedWarning && safetyScore >= 1.5;
  const competitor_flag = compScore > 0;
  const confidence =
    quality_score >= 7 ? 'high'   :
    quality_score >= 4 ? 'medium' : 'low';

  return {
    impact_score, impact_level, quality_score,
    route_tier, is_urgent, competitor_flag,
    confidence, score_breakdown: bd,
  };
}

// ─────────────────────────────────────────────────────────────
// SECTION 5: MAIN TRANSFORM LOOP
// ─────────────────────────────────────────────────────────────

const output      = [];
const labelRecords = [];

// ── Unwrap openFDA API response ───────────────────────────────
for (const item of $input.all()) {
  const body = item.json || {};
  if      (Array.isArray(body.results) && body.results.length > 0)
    labelRecords.push(...body.results);
  else if (body.set_id || body.id || body.active_ingredient || body.openfda)
    labelRecords.push(body);
  else if (Array.isArray(body))
    labelRecords.push(...body);
  else
    output.push({
      json: {
        _error:           true,
        _error_message:   'Unknown FDA label structure',
        _received_keys:   Object.keys(body).join(', '),
        signal_domain:    'regulatory',
        signal_type:      'label_update',
        source:           'fda_labels',
        impact_level:     'LOW',
        impact_score:     0,
        quality_score:    0,
        route_tier:       'T3_MONITOR',
        notif_priority:   'P5',
        alert_channels:   ['pharmaos-digest'],
        pipeline_version: PIPELINE_VERSION,
      }
    });
}

// ── Process each individual label ─────────────────────────────
for (const raw of labelRecords) {
  try {
    const ofda = raw.openfda || {};

    // IDs
    const setId  = safe(raw.set_id || raw.id);
    const appNum = safe(safeArr(ofda.application_number)[0] || '').toUpperCase();

    // Homeopathic detection
    const activeIngText = joinArr(raw.active_ingredient || []);
    const isHomeopathic = activeIngText.toUpperCase().includes('HPUS');
    const potencyMatch  = activeIngText.match(/HPUS\s*([\dXCMQ]+[A-Z]*)/i);
    const hpusPotency   = potencyMatch ? potencyMatch[1].toUpperCase() : null;

    // Core fields
    const drug_name  = extractDrugName(raw, ofda);
    const sponsor    = extractSponsor(raw, ofda);
    const indication = extractIndication(raw, drug_name, isHomeopathic);
    const moa        = extractMoa(raw);
    const url        = extractUrl(raw, ofda);
    const nct_id     = extractNctIdFromRaw(raw);
    const phase      = extractPhase(appNum, raw, isHomeopathic);
    const status     = appNum ? 'Approved' : (isHomeopathic ? 'OTC' : '');
    const geography  = 'US';

    // Modality
    const pharmClasses = [
      ...safeArr(ofda.pharm_class_epc),
      ...safeArr(ofda.pharm_class_cs),
      ...safeArr(ofda.pharm_class_moa),
    ];
    const modality = resolveModality(pharmClasses);

    // Effective date
    const effectiveDate = formatEffectiveDate(raw.effective_time || '');

    // Safety meta
    const boxedText      = joinArr(raw.boxed_warning || []);
    const warningsText   = joinArr(raw.warnings || raw.warnings_and_cautions || []);
    const hasBoxedWarning =
      boxedText.length > 10 ||
      containsAny(warningsText, new Set(['black box','boxed warning']));
    const remsRequired = containsAny(
      joinArr([
        ...(raw.patient_medication_information || []),
        ...(raw.medication_guide               || []),
        ...(raw.warnings                       || []),
      ]),
      new Set(['rems','risk evaluation and mitigation strategy'])
    );

    // OTC sections
    const pregnancyText = joinArr(raw.pregnancy_or_breast_feeding || []);
    const stopUseText   = joinArr(raw.stop_use                    || []);
    const doNotUseText  = joinArr(raw.do_not_use                  || []);
    const storageText   = joinArr(raw.storage_and_handling        || []);

    // Adverse reactions
    const adverseReactions = [
      ...(raw.adverse_reactions       || []),
      ...(raw.adverse_reactions_table || []),
    ];

    // Label section count
    const labelSections = LABEL_SECTION_KEYS.filter(k =>
      Array.isArray(raw[k]) ? raw[k].length > 0 : !!raw[k]
    ).length;

    // Raw text
    const rawTextParts = [
      `DRUG: ${drug_name}`,
      appNum            ? `APPLICATION: ${appNum}`                           : '',
      effectiveDate     ? `EFFECTIVE DATE: ${effectiveDate}`                  : '',
      indication        ? `INDICATION: ${indication}`                         : '',
      moa               ? `MOA: ${moa}`                                       : '',
      sponsor           ? `MANUFACTURER: ${sponsor}`                          : '',
      pharmClasses.length ? `PHARM CLASS: ${pharmClasses.slice(0,3).join('; ')}` : '',
      isHomeopathic     ? `HPUS POTENCY: ${hpusPotency || 'Unknown'}`        : '',
      activeIngText     ? `ACTIVE INGREDIENT: ${activeIngText}`               : '',
      hasBoxedWarning   ? `BOXED WARNING: ${truncate(boxedText||warningsText,800)}` : '',
      remsRequired      ? 'REMS: YES'                                         : '',
      pregnancyText     ? `PREGNANCY/NURSING: ${pregnancyText}`               : '',
      stopUseText       ? `STOP USE: ${stopUseText}`                          : '',
      doNotUseText      ? `DO NOT USE: ${doNotUseText}`                       : '',
      storageText       ? `STORAGE: ${storageText}`                           : '',
      adverseReactions.length
        ? `ADVERSE REACTIONS: ${truncate(joinArr(adverseReactions), 1000)}`   : '',
      raw.drug_interactions?.length
        ? `DRUG INTERACTIONS: ${truncate(joinArr(raw.drug_interactions), 500)}` : '',
      raw.clinical_studies?.length
        ? `CLINICAL STUDIES: ${truncate(joinArr(raw.clinical_studies), 500)}` : '',
    ].filter(Boolean).join('\n\n');
    const raw_text = truncate(rawTextParts, 8000);

    // Title & Summary
    const labelTag = hasBoxedWarning ? 'Label Update ⚠️ BOXED WARNING' : 'Label Update';
    const title    = truncate(
      `FDA ${labelTag}: ${drug_name}${effectiveDate ? ` (${effectiveDate})` : ''}`, 512
    );
    const summary  = truncate(
      indication ||
      joinArr(raw.description || []) ||
      `FDA ${isHomeopathic ? 'OTC Homeopathic' : 'approved'} label for ${drug_name}.`,
      4000
    );

    // Score
    const scores = scoreSignal({
      drug_name, indication, sponsor, moa, url,
      appNum, hasBoxedWarning, remsRequired,
      pharmClasses, rawText: raw_text, labelSections,
      adverseReactions, isHomeopathic, hpusPotency,
    });

    // Routing
    const source_id      = `fda_label_${setId || appNum || drug_name.toLowerCase().replace(/\W+/g,'_')}`;
    const notif_priority = TIER_TO_PRIORITY[scores.route_tier] || 'P5';
    const alert_channels = TIER_TO_CHANNELS[scores.route_tier] || ['pharmaos-digest'];
    const ttl_expires_at = daysFromNow(TIER_TTL[scores.route_tier] || 30);

    // Dedup
    const fingerprint = `regulatory|${drug_name}|label_update|fda_labels|${setId}`;
    const dedup_hash  = `${setId}|${effectiveDate || appNum || drug_name}`;

    output.push({
      json: {
        source_id,  source: 'fda_labels',
        signal_domain: 'regulatory',  signal_type: 'label_update',
        drug_name,  entity_name: drug_name,  asset_id: null,
        indication, sponsor, geography, nct_id, phase, status, moa, modality,
        title, summary, url, raw_text,
        impact_score:    scores.impact_score,
        impact_level:    scores.impact_level,
        quality_score:   scores.quality_score,
        priority_score:  scores.impact_score,
        score_breakdown: scores.score_breakdown,
        scoring_version: SCORING_VERSION,
        route_tier:      scores.route_tier,
        notif_priority,  alert_channels,  ttl_expires_at,
        competitor_flag: scores.competitor_flag,
        is_urgent:       scores.is_urgent,
        confidence:      scores.confidence,
        fingerprint,     dedup_hash,
        has_boxed_warning: hasBoxedWarning,
        rems_required:     remsRequired,
        is_homeopathic:    isHomeopathic,
        hpus_potency:      hpusPotency,
        label_sections:    labelSections,
        effective_date:    effectiveDate,
        app_number:        appNum || null,
        pipeline_version:  PIPELINE_VERSION,
      }
    });

  } catch (err) {
    output.push({
      json: {
        _error:           true,
        _error_message:   err.message,
        _error_stack:     err.stack?.slice(0, 500) || null,
        signal_domain:    'regulatory',
        signal_type:      'label_update',
        source:           'fda_labels',
        impact_level:     'LOW',
        impact_score:     0,
        quality_score:    0,
        route_tier:       'T3_MONITOR',
        notif_priority:   'P5',
        alert_channels:   ['pharmaos-digest'],
        pipeline_version: PIPELINE_VERSION,
      }
    });
  }
}

return output;

const items = $input.all();
return [{
  json: {
    source: 'fda_labels',
    fetched: items.length,
    new: items.filter(i => i.json.is_new === true).length,
    updated: items.filter(i => i.json.is_new === false).length,
    deduped: items.filter(i => i.json.is_new === false).length,
    errors: 0
  }
}];

// ============================================================
// 🧬 Transform DailyMed SPL — v2.0.0
// PharmaOS Pipeline | Domain: regulatory
// Source: DailyMed /spls API
// Scoring Engine: Multi-dimensional weighted scoring
// Schema Target: signals_mesh v2.0.0
// ============================================================

const PIPELINE_VERSION = '2.0.0';
const SCORING_VERSION  = 2;

// ─────────────────────────────────────────────────────────────
// SECTION 1: CONSTANTS & DICTIONARIES
// ─────────────────────────────────────────────────────────────

const HIGH_VALUE_INDICATIONS = new Set([
  'cancer','carcinoma','tumor','tumour','leukemia','lymphoma',
  'melanoma','myeloma','sarcoma','glioma','glioblastoma',
  'nsclc','lung cancer','breast cancer','colorectal','ovarian',
  'prostate cancer','hepatocellular','renal cell','bladder cancer',
  'pancreatic cancer','cervical cancer','endometrial','cholangiocarcinoma',
  'autoimmune','multiple sclerosis','rheumatoid arthritis','psoriasis',
  'crohn','ulcerative colitis','alzheimer','dementia','parkinson',
  'rare disease','orphan','aml','cll','cml',
  'atrial fibrillation','heart failure','stroke prevention',
  'hiv','hepatitis','covid','immunodeficiency'
]);

const HIGH_RISK_TERMS = new Set([
  'black box','boxed warning','rems','risk evaluation',
  'fatal','death','serious adverse','life-threatening',
  'contraindicated','severe hepatotoxicity','anaphylaxis',
  'suicidal','embryo-fetal','teratogenic','carcinogenicity',
  'cardiac arrest','torsade','agranulocytosis','stevens-johnson',
  'toxic epidermal','hepatic failure','renal failure',
  'respiratory failure','serotonin syndrome','neuroleptic malignant',
  'qt prolongation','sudden death','pulmonary embolism'
]);

// Strategic sponsors (competitor flag trigger)
const STRATEGIC_SPONSORS = new Set([
  'merck','pfizer','bristol-myers','bms','roche','genentech',
  'astrazeneca','novartis','sanofi','abbvie','johnson & johnson',
  'janssen','eli lilly','lilly','boehringer','amgen','biogen',
  'regeneron','gilead','moderna','biontech','takeda',
  'daiichi sankyo','seagen','incyte','blueprint medicines',
  'agenus','exelixis','mirati','g1 therapeutics'
]);

// DailyMed SPL type codes → signal_type mapping
const SPL_TYPE_MAP = {
  'C73600':  'label_update',        // Prescription Drug Label
  'C73601':  'label_update',        // OTC Drug Label
  'C73602':  'label_update',        // Homeopathic OTC
  'C73603':  'label_update',        // Vaccine Label
  'C73606':  'label_update',        // Biologics
  'C73607':  'label_update',        // Plasma Derivative
  'C73608':  'label_update',        // Cellular/Gene Therapy
  'C73609':  'safety',              // Medication Guide
  'C73610':  'safety',              // Patient Package Insert
  'C73611':  'safety',              // Boxed Warning Label
  'C73612':  'regulatory',          // NDA Submission
};

// SPL type code → human label
const SPL_TYPE_LABEL = {
  'C73600':  'Prescription',
  'C73601':  'OTC',
  'C73602':  'Homeopathic',
  'C73603':  'Vaccine',
  'C73606':  'Biologic',
  'C73607':  'Plasma Derivative',
  'C73608':  'Cell/Gene Therapy',
  'C73609':  'Medication Guide',
  'C73610':  'Patient Package Insert',
  'C73611':  'Boxed Warning',
};

// Routing
const TIER_TO_PRIORITY = {
  T1_CRITICAL: 'P1',
  T2_REVIEW:   'P3',
  T3_MONITOR:  'P5',
};

const TIER_TO_CHANNELS = {
  T1_CRITICAL: ['pharmaos-critical','pharmaos-executive','medical-affairs'],
  T2_REVIEW:   ['pharmaos-regulatory','ci-team'],
  T3_MONITOR:  ['pharmaos-digest'],
};

const TIER_TTL = {
  T1_CRITICAL: 90,
  T2_REVIEW:   60,
  T3_MONITOR:  30,
};

// ─────────────────────────────────────────────────────────────
// SECTION 2: UTILITY HELPERS
// ─────────────────────────────────────────────────────────────

const safe = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  return String(v).replace(/[\x00-\x1F\x7F-\x9F]/g, '').trim() || fallback;
};

const safeArr = (v) => {
  if (Array.isArray(v)) return v.map(String).filter(Boolean);
  if (typeof v === 'string' && v.trim()) return [v.trim()];
  return [];
};

const joinArr = (arr, sep = ' ') => safeArr(arr).join(sep).trim();

const clamp = (n, min, max) =>
  Math.max(min, Math.min(max, Number(n) || 0));

const truncate = (str, len) =>
  !str ? '' : String(str).length > len ? String(str).slice(0, len) : String(str);

const containsAny = (text, termSet) => {
  const lower = String(text).toLowerCase();
  for (const t of termSet) if (lower.includes(t)) return true;
  return false;
};

const countMatches = (text, termSet) => {
  const lower = String(text).toLowerCase();
  let n = 0;
  for (const t of termSet) if (lower.includes(t)) n++;
  return n;
};

const daysFromNow = (days) => {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.toISOString();
};

// Normalize date strings from DailyMed
// Handles: "20210902", "2021-09-02", "Sep 02, 2021", "2021/09/02"
const normalizeDate = (raw) => {
  const s = safe(raw);
  if (!s) return '';
  // YYYYMMDD
  if (/^\d{8}$/.test(s)) return `${s.slice(0,4)}-${s.slice(4,6)}-${s.slice(6,8)}`;
  // Already ISO
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0,10);
  // YYYY/MM/DD
  if (/^\d{4}\/\d{2}\/\d{2}/.test(s)) return s.replace(/\//g,'-').slice(0,10);
  // Try native parse
  const d = new Date(s);
  return isNaN(d.getTime()) ? s.slice(0,20) : d.toISOString().slice(0,10);
};

// Extract drug name from SPL title
// e.g. "KEYTRUDA (pembrolizumab) injection" → "KEYTRUDA"
// e.g. "pembrolizumab 100 MG/4ML" → "pembrolizumab"
const parseDrugFromTitle = (title) => {
  if (!title) return '';
  // Brand name is typically before parenthesis
  const parenMatch = title.match(/^([^(]+)\s*\(/);
  if (parenMatch) return parenMatch[1].trim();
  // Strip strength/form suffixes
  return title
    .replace(/\d+\s*(mg|mcg|ml|%|iu|unit|tablet|capsule|injection|solution|cream|ointment|patch|spray|drop|suspension|powder|gel)/gi, '')
    .replace(/\s+/g, ' ')
    .trim()
    .split(/[,\-]/)[0]
    .trim();
};

// Extract generic name from SPL title
// e.g. "KEYTRUDA (pembrolizumab) injection" → "pembrolizumab"
const parseGenericFromTitle = (title) => {
  if (!title) return '';
  const match = title.match(/\(([^)]+)\)/);
  return match ? match[1].trim() : '';
};

// Extract sponsor from SPL labeler field
const resolveSponsor = (spl) => {
  return safe(
    spl.labeler            ||
    spl.manufacturer       ||
    spl.sponsor            ||
    safeArr(spl.labelers)[0] ||
    ''
  );
};

// Detect application type from application_number or title
const resolveAppType = (spl) => {
  const appNum = safe(spl.application_number || spl.application_numbers || '').toUpperCase();
  if (appNum.startsWith('NDA'))  return { appNum, appType: 'NDA',  isRx: true,   isOtc: false, isHomeopathic: false };
  if (appNum.startsWith('BLA'))  return { appNum, appType: 'BLA',  isRx: true,   isOtc: false, isHomeopathic: false };
  if (appNum.startsWith('ANDA')) return { appNum, appType: 'ANDA', isRx: false,  isOtc: true,  isHomeopathic: false };
  // Detect from SPL type code
  const splType = safe(spl.marketing_category || spl.type || spl.document_type || '');
  const isHomeo  = splType === 'C73602' ||
    safe(spl.title || '').toLowerCase().includes('homeopathic') ||
    safe(spl.title || '').toUpperCase().includes('HPUS');
  const isOtc    = splType === 'C73601' || (!appNum && !isHomeo);
  return { appNum, appType: '', isRx: !!appNum, isOtc, isHomeopathic: isHomeo };
};

// Detect boxed warning from SPL fields
const detectBoxedWarning = (spl) => {
  return !!(
    spl.boxed_warning_flag === true              ||
    spl.boxed_warning_flag === 'Y'               ||
    spl.has_boxed_warning === true               ||
    (spl.type && spl.type === 'C73611')          ||
    safe(spl.marketing_category).includes('BOX') ||
    safe(spl.title).toLowerCase().includes('boxed warning') ||
    safe(spl.title).toLowerCase().includes('black box')
  );
};

// ─────────────────────────────────────────────────────────────
// SECTION 3: SCORING ENGINE
// ─────────────────────────────────────────────────────────────
//
//  Dimension                Max    What Drives It
//  ──────────────────────────────────────────────
//  1. Field Completeness    2.0    drug/sponsor/indication/url/date
//  2. Regulatory Weight     2.0    NDA/BLA + boxed warning + REMS
//  3. Indication Value      2.0    match vs 30+ high-value areas
//  4. Safety Risk           2.0    match vs 25+ high-risk terms
//  5. Competitor Signal     1.0    sponsor in strategic sponsor list
//  6. Watchlist Boost       1.0    drug matched in run-context watchlist
//  OTC/Homeopathic penalty  -0.5   waived if genuine safety signal
//  ──────────────────────────────────────────────
//  TOTAL (max)              10.0

function scoreSignal({
  drugName, sponsor, indication, url, published,
  appNum, appType, isRx, isOtc, isHomeopathic,
  hasBoxedWarning, remsDetected,
  titleText, rawText,
  isWatchlisted, watchlistMatchCount,
}) {
  const bd = {};

  const fullText = `${titleText} ${indication} ${rawText}`.toLowerCase();
  const safetyText = fullText;

  // ── 1. Field Completeness (0–2.0) ────────────────────────
  let completeness = 0;
  if (drugName && drugName !== 'Unknown') completeness += 0.5;
  if (sponsor  && sponsor.length > 2)    completeness += 0.5;
  if (indication && indication.length > 20) completeness += 0.5;
  if (url)                               completeness += 0.3;
  if (published)                         completeness += 0.2;
  completeness = clamp(completeness, 0, 2.0);
  bd.completeness = +completeness.toFixed(2);

  // ── 2. Regulatory Weight (0–2.0) ─────────────────────────
  let regWeight = 0;
  if (appType === 'NDA' || appType === 'BLA') regWeight += 1.0;
  else if (appType === 'ANDA')                regWeight += 0.4;
  else if (isRx)                              regWeight += 0.3;
  if (hasBoxedWarning)                        regWeight += 0.7;
  if (remsDetected)                           regWeight += 0.3;
  regWeight = clamp(regWeight, 0, 2.0);
  bd.regulatory_weight   = +regWeight.toFixed(2);
  bd.has_boxed_warning   = hasBoxedWarning;
  bd.rems_detected       = remsDetected;
  bd.app_number          = appNum || null;
  bd.app_type            = appType || null;

  // ── 3. Indication Value (0–2.0) ──────────────────────────
  const indHits  = countMatches(fullText, HIGH_VALUE_INDICATIONS);
  const indValue =
    indHits >= 3          ? 2.0 :
    indHits === 2         ? 1.5 :
    indHits === 1         ? 1.0 :
    indication.length > 50 ? 0.5 : 0;
  bd.indication_value = +indValue.toFixed(2);
  bd.indication_hits  = indHits;

  // ── 4. Safety Risk (0–2.0) ───────────────────────────────
  const safetyHits = countMatches(safetyText, HIGH_RISK_TERMS);
  let safetyScore  =
    safetyHits >= 4  ? 2.0 :
    safetyHits >= 2  ? 1.5 :
    safetyHits === 1 ? 1.0 :
    hasBoxedWarning  ? 1.0 : 0;
  safetyScore = clamp(safetyScore, 0, 2.0);
  bd.safety_risk        = +safetyScore.toFixed(2);
  bd.safety_terms_found = safetyHits;

  // ── 5. Competitor Signal (0–1.0) ─────────────────────────
  let compScore = 0;
  const sponsorLower = sponsor.toLowerCase();
  for (const s of STRATEGIC_SPONSORS) {
    if (sponsorLower.includes(s)) { compScore = 1.0; break; }
  }
  bd.competitor_signal = +compScore.toFixed(2);

  // ── 6. Watchlist Boost (0–1.0) ───────────────────────────
  let watchlistScore = 0;
  if (isWatchlisted) {
    watchlistScore = watchlistMatchCount >= 2 ? 1.0 : 0.7;
  }
  bd.watchlist_boost        = +watchlistScore.toFixed(2);
  bd.watchlist_match_count  = watchlistMatchCount;
  bd.is_watchlisted         = isWatchlisted;

  // ── OTC/Homeopathic Penalty ───────────────────────────────
  let otcPenalty = 0;
  if (isHomeopathic) {
    otcPenalty = (hasBoxedWarning || safetyScore >= 1.0) ? 0 : -0.5;
  } else if (isOtc && !isWatchlisted) {
    otcPenalty = (hasBoxedWarning || safetyScore >= 1.0) ? 0 : -0.3;
  }
  bd.otc_homeopathic = isHomeopathic;
  bd.is_otc          = isOtc;
  bd.otc_penalty     = +otcPenalty.toFixed(2);

  // ── Composite Score ───────────────────────────────────────
  const rawScore =
    completeness + regWeight + indValue +
    safetyScore  + compScore + watchlistScore +
    otcPenalty;

  const impact_score = clamp(parseFloat(rawScore.toFixed(2)), 0, 10);
  bd.total = impact_score;

  // ── Quality Score (0–10 int) ──────────────────────────────
  const quality_score = clamp(
    (drugName !== 'Unknown' ? 2 : 0) +
    (indication.length > 20 ? 2 : 0) +
    (sponsor                ? 1 : 0) +
    (url                    ? 1 : 0) +
    (appNum                 ? 1 : 0) +
    (published              ? 1 : 0) +
    (rawText.length > 200   ? 1 : 0) +
    (hasBoxedWarning        ? 1 : 0),
    0, 10
  );

  // ── Impact Level (safety floor for boxed warning) ─────────
  const impact_level =
    impact_score >= 7.0   ? 'HIGH' :
    impact_score >= 4.0   ? 'MED'  :
    hasBoxedWarning       ? 'MED'  : 'LOW';

  // ── Route Tier ────────────────────────────────────────────
  const route_tier =
    impact_level === 'HIGH' ||
    (hasBoxedWarning && compScore > 0)  ? 'T1_CRITICAL' :
    impact_level === 'MED' ||
    hasBoxedWarning || isWatchlisted    ? 'T2_REVIEW'   : 'T3_MONITOR';

  // ── Flags ─────────────────────────────────────────────────
  const is_urgent       = hasBoxedWarning && safetyScore >= 1.5;
  const competitor_flag = compScore > 0 || (isWatchlisted && compScore === 0);
  const confidence =
    quality_score >= 7 ? 'high'   :
    quality_score >= 4 ? 'medium' : 'low';

  return {
    impact_score, impact_level, quality_score,
    route_tier, is_urgent, competitor_flag,
    confidence, score_breakdown: bd,
  };
}

// ─────────────────────────────────────────────────────────────
// SECTION 4: WATCHLIST LOADER
// Reads from Init Run Context or falls back gracefully
// ─────────────────────────────────────────────────────────────

let watchlist = [];
try {
  const runCtx = $('🔧 Init Run Context').first().json;
  watchlist = (runCtx.oncology_drugs || runCtx.watchlist || [])
    .map(w => String(w).toLowerCase().trim())
    .filter(Boolean);
} catch (e) {
  // Run context not available — watchlist matching disabled
  watchlist = [];
}

const matchWatchlist = (text) => {
  const lower = String(text).toLowerCase();
  const matches = watchlist.filter(w => lower.includes(w));
  return { isWatchlisted: matches.length > 0, watchlistMatchCount: matches.length };
};

// ─────────────────────────────────────────────────────────────
// SECTION 5: MAIN TRANSFORM LOOP
// ─────────────────────────────────────────────────────────────

const output      = [];
const splRecords  = [];

// ── Unwrap DailyMed API response ─────────────────────────────
// Handles: { data: [...] } | { results: [...] } | [ ... ] | bare record
for (const item of $input.all()) {
  const body = item.json || {};

  if (Array.isArray(body.data)    && body.data.length > 0)    splRecords.push(...body.data);
  else if (Array.isArray(body.results) && body.results.length > 0) splRecords.push(...body.results);
  else if (Array.isArray(body.spls)    && body.spls.length > 0)    splRecords.push(...body.spls);
  else if (body.setid || body.title || body.drug_name)         splRecords.push(body);
  else if (Array.isArray(body))                                splRecords.push(...body);
  else {
    output.push({
      json: {
        _error:         true,
        _error_message: 'Unknown DailyMed SPL structure',
        _received_keys: Object.keys(body).join(', '),
        signal_domain:  'regulatory',
        signal_type:    'label_update',
        source:         'dailymed',
        impact_level:   'LOW',
        impact_score:   0,
        quality_score:  0,
        route_tier:     'T3_MONITOR',
        notif_priority: 'P5',
        alert_channels: ['pharmaos-digest'],
        pipeline_version: PIPELINE_VERSION,
      }
    });
  }
}

// ── Process each SPL record ───────────────────────────────────
for (const spl of splRecords) {
  try {

    // ── Identity ─────────────────────────────────────────────
    const setId     = safe(spl.setid || spl.set_id || spl.id);
    const published = normalizeDate(spl.published_date || spl.effective_time || spl.date || '');
    const version   = safe(spl.version || spl.spl_version || '');

    // ── Drug name extraction ──────────────────────────────────
    const rawTitle   = safe(spl.title || spl.drug_name || spl.name || '');
    const brandName  = parseDrugFromTitle(rawTitle);
    const genericName = safe(
      spl.generic_name ||
      spl.nonproprietary_name ||
      parseGenericFromTitle(rawTitle) ||
      ''
    );
    const drugName   = brandName || genericName || 'Unknown';
    const entity_name = drugName;

    // ── SPL type ──────────────────────────────────────────────
    const splTypeCode  = safe(spl.marketing_category || spl.type || spl.document_type || '');
    const splTypeLabel = SPL_TYPE_LABEL[splTypeCode] || 'Label';
    const signal_type  = SPL_TYPE_MAP[splTypeCode] || 'label_update';

    // ── App type & product class ──────────────────────────────
    const { appNum, appType, isRx, isOtc, isHomeopathic } = resolveAppType(spl);

    // ── Sponsor ───────────────────────────────────────────────
    const sponsor = resolveSponsor(spl);

    // ── Indication ────────────────────────────────────────────
    const indication = truncate(
      safe(
        spl.indication                                   ||
        joinArr(spl.indications_and_usage || [])         ||
        joinArr(spl.purpose || [])                       ||
        ''
      ),
      500
    );

    // ── Geography ─────────────────────────────────────────────
    const geography = 'US';

    // ── NCT ID ────────────────────────────────────────────────
    const nctSources = [
      safe(spl.nct_id || ''),
      joinArr(spl.clinical_studies || []),
      safe(spl.raw_text || ''),
    ].join(' ');
    const nctMatch = nctSources.match(/NCT\d{8}/i);
    const nct_id   = nctMatch ? nctMatch[0].toUpperCase() : null;

    // ── URL ───────────────────────────────────────────────────
    const url = setId
      ? `https://dailymed.nlm.nih.gov/dailymed/drugInfo.cfm?setid=${setId}`
      : '';

    // ── Phase / Status ────────────────────────────────────────
    const phase  = appType ? `Approved (${appType})` : isHomeopathic ? 'OTC Homeopathic' : isOtc ? 'OTC' : '';
    const status = appNum ? 'Approved' : isOtc ? 'OTC' : isHomeopathic ? 'OTC Homeopathic' : '';

    // ── MOA / Modality ────────────────────────────────────────
    const moa      = truncate(safe(spl.mechanism_of_action || ''), 500);
    const modality = truncate(safe(spl.pharm_class || spl.pharmacologic_class || ''), 100);

    // ── Safety flags ─────────────────────────────────────────
    const hasBoxedWarning = detectBoxedWarning(spl);
    const remsDetected    = containsAny(
      `${safe(spl.warnings || '')} ${safe(spl.medication_guide || '')}`,
      new Set(['rems','risk evaluation and mitigation'])
    );

    // ── Watchlist match ───────────────────────────────────────
    const titleAndDrug = `${rawTitle} ${drugName} ${genericName} ${indication}`;
    const { isWatchlisted, watchlistMatchCount } = matchWatchlist(titleAndDrug);

    // ── Raw text ──────────────────────────────────────────────
    const rawTextParts = [
      `DRUG: ${drugName}`,
      genericName       ? `GENERIC: ${genericName}`                   : '',
      appNum            ? `APPLICATION: ${appNum}`                    : '',
      published         ? `PUBLISHED: ${published}`                   : '',
      version           ? `VERSION: ${version}`                       : '',
      splTypeLabel      ? `SPL TYPE: ${splTypeLabel}`                 : '',
      indication        ? `INDICATION: ${indication}`                 : '',
      moa               ? `MOA: ${moa}`                               : '',
      sponsor           ? `LABELER: ${sponsor}`                       : '',
      modality          ? `PHARM CLASS: ${modality}`                  : '',
      isHomeopathic     ? `PRODUCT TYPE: Homeopathic OTC`             : '',
      hasBoxedWarning   ? 'BOXED WARNING: YES'                        : '',
      remsDetected      ? 'REMS: YES'                                 : '',
      isWatchlisted     ? `WATCHLISTED: YES (${watchlistMatchCount} matches)` : '',
      safe(spl.warnings          || '').length > 10
        ? `WARNINGS: ${truncate(safe(spl.warnings), 800)}`           : '',
      safe(spl.adverse_reactions || '').length > 10
        ? `ADVERSE REACTIONS: ${truncate(safe(spl.adverse_reactions), 800)}` : '',
      safe(spl.drug_interactions || '').length > 10
        ? `DRUG INTERACTIONS: ${truncate(safe(spl.drug_interactions), 500)}` : '',
      safe(spl.dosage_and_administration || '').length > 10
        ? `DOSAGE: ${truncate(safe(spl.dosage_and_administration), 300)}`    : '',
    ].filter(Boolean).join('\n\n');
    const raw_text = truncate(rawTextParts, 8000);

    // ── Score ─────────────────────────────────────────────────
    const scores = scoreSignal({
      drugName, sponsor, indication, url, published,
      appNum, appType, isRx, isOtc, isHomeopathic,
      hasBoxedWarning, remsDetected,
      titleText: rawTitle, rawText: raw_text,
      isWatchlisted, watchlistMatchCount,
    });

    // ── Title & Summary ───────────────────────────────────────
    const safetyTag = hasBoxedWarning ? ' ⚠️ BOXED WARNING' : '';
    const title     = truncate(
      `DailyMed ${splTypeLabel} Update${safetyTag}: ${drugName}${genericName && genericName !== drugName ? ` (${genericName})` : ''}${published ? ` — ${published}` : ''}`,
      512
    );
    const summary   = truncate(
      indication ||
      safe(spl.description || '') ||
      `DailyMed ${splTypeLabel.toLowerCase()} update for ${drugName}.${published ? ` Published: ${published}.` : ''}${hasBoxedWarning ? ' Contains boxed warning.' : ''}`,
      4000
    );

    // ── Routing ───────────────────────────────────────────────
    const source_id      = `dailymed_${setId || appNum || drugName.toLowerCase().replace(/\W+/g,'_')}`;
    const notif_priority = TIER_TO_PRIORITY[scores.route_tier] || 'P5';
    const alert_channels = TIER_TO_CHANNELS[scores.route_tier] || ['pharmaos-digest'];
    const ttl_expires_at = daysFromNow(TIER_TTL[scores.route_tier] || 30);

    // ── Dedup ─────────────────────────────────────────────────
    const fingerprint = `regulatory|${drugName}|label_update|dailymed|${setId}`;
    const dedup_hash  = `${setId}|${published || version || drugName}`;

    output.push({
      json: {
        // Identity
        source_id,
        source:         'dailymed',
        signal_domain:  'regulatory',
        signal_type,

        // Drug / Asset
        drug_name:      drugName,
        entity_name,
        asset_id:       null,   // Enriched by downstream Asset Lookup node

        // Clinical
        indication,
        sponsor,
        geography,
        nct_id,
        phase,
        status,
        moa,
        modality,

        // Content
        title,
        summary,
        url,
        raw_text,

        // Scoring
        impact_score:    scores.impact_score,
        impact_level:    scores.impact_level,
        quality_score:   scores.quality_score,
        priority_score:  scores.impact_score,
        score_breakdown: scores.score_breakdown,
        scoring_version: SCORING_VERSION,

        // Routing
        route_tier:      scores.route_tier,
        notif_priority,
        alert_channels,
        ttl_expires_at,

        // Flags
        competitor_flag: scores.competitor_flag,
        is_urgent:       scores.is_urgent,
        confidence:      scores.confidence,

        // Dedup
        fingerprint,
        dedup_hash,
      }
    });

  } catch (err) {
    // Dead-letter: never crash the batch
    output.push({
      json: {
        _error:           true,
        _error_message:   err.message,
        _error_stack:     err.stack?.slice(0, 500) || null,
        _raw_spl:         JSON.stringify(spl).slice(0, 500),
        signal_domain:    'regulatory',
        signal_type:      'label_update',
        source:           'dailymed',
        impact_level:     'LOW',
        impact_score:     0,
        quality_score:    0,
        route_tier:       'T3_MONITOR',
        notif_priority:   'P5',
        alert_channels:   ['pharmaos-digest'],
      }
    });
  }
}

return output;

const items = $input.all();
return [{
  json: {
    source: 'dailymed',
    fetched: items.length,
    new: items.filter(i => i.json.is_new === true).length,
    updated: items.filter(i => i.json.is_new === false).length,
    deduped: items.filter(i => i.json.is_new === false).length,
    errors: 0
  }
}];

const raw = $input.first().json || {};

function normStr(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function normYear(v) {
  const n = Number(v);
  if (!Number.isInteger(n)) return null;
  if (n < 1800 || n > 3000) return null;
  return n;
}

// Identity
const asset_id   = normStr(raw.asset_id || raw.id);
const asset_name = normStr(raw.asset_name || raw.name);

// Derive drug and indication from asset
const drug_name  = normStr(raw.name);
const indication = normStr(raw.indication || raw.therapeutic_area);

// Default date window: last 12 months
const now = new Date();
const year_to   = now.getFullYear();
const year_from = year_to - 1;

// Empty free text, author, journal for asset-based mode
const q       = '';
const author  = '';
const journal = '';

const mesh_terms = [];
const tags = [];

let study_type = '';
const allowedStudyTypes = ['clinical trial', 'meta-analysis', 'systematic review', 'cohort'];
if (!allowedStudyTypes.includes(study_type)) {
  study_type = '';
}

// Heuristics
const is_executive_query = false;
const is_high_priority_asset =
  normStr(raw.strategic_priority).toUpperCase() === 'CRITICAL';

const query_complexity_score =
  (drug_name ? 1 : 0) + (indication ? 1 : 0);

// Skip if no drug/indication
let skip = false;
let skip_reason = null;
if (!drug_name && !indication) {
  skip = true;
  skip_reason = 'no_drug_or_indication';
}

const search_fingerprint = [
  drug_name.toLowerCase(),
  indication.toLowerCase(),
  q.toLowerCase(),
  author.toLowerCase(),
  journal.toLowerCase(),
  year_from,
  year_to,
  mesh_terms.join(',').toLowerCase(),
  study_type,
].join('|');

const out = {
  asset_id: asset_id || 'unknown',
  asset_name,

  q,
  drug_name,
  indication,
  author,
  journal,
  year_from,
  year_to,
  mesh_terms,
  study_type,

  tags,
  strategic_priority: normStr(raw.strategic_priority || 'NORMAL').toUpperCase(),
  requested_by: '',

  is_executive_query,
  is_high_priority_asset,
  query_complexity_score,

  skip,
  skip_reason,

  search_fingerprint,

  _raw_source_type: normStr(raw._source_type || 'pharmaos_assets'),
  _raw_asset_id:    asset_id,
  _ingested_at:     new Date().toISOString(),
};

return [{ json: out }];

// ============================================================
// NODE: Build PubMed Search Term
// ============================================================

const d = $input.first().json;

const q           = (d.q || '').trim();
const drugName    = (d.drug_name || '').trim();
const indication  = (d.indication || '').trim();
const author      = (d.author || '').trim();
const journal     = (d.journal || '').trim();
const yearFrom    = d.year_from;
const yearTo      = d.year_to;
const meshTerms   = Array.isArray(d.mesh_terms) ? d.mesh_terms : [];
const studyType   = (d.study_type || '').toLowerCase();

const clauses = [];

// Free text
if (q) {
  clauses.push(`(${q}[tiab])`);
}

// Drug
if (drugName) {
  clauses.push(`("${drugName}"[tiab] OR "${drugName}"[mh])`);
}

// Indication
if (indication) {
  clauses.push(`("${indication}"[tiab] OR "${indication}"[mh])`);
}

// Author
if (author) {
  clauses.push(`"${author}"[au]`);
}

// Journal
if (journal) {
  clauses.push(`"${journal}"[ta]`);
}

// MeSH
if (meshTerms.length > 0) {
  const meshClause = meshTerms
    .filter(Boolean)
    .map(t => `"${t}"[mh]`)
    .join(' OR ');
  clauses.push(`(${meshClause})`);
}

// Study type
if (studyType === 'clinical trial') {
  clauses.push(`"clinical trial"[pt]`);
} else if (studyType === 'meta-analysis') {
  clauses.push(`"meta-analysis"[pt]`);
}

// Date range (Entry Normalizer already ensured sensible years)
const from = yearFrom;
const to   = yearTo;
const dateClause = `"${from}"[dp] : "${to}"[dp]`;
clauses.push(`(${dateClause})`);

const searchTerm = clauses.join(' AND ');

// Require at least one anchor (q, drug, indication)
if ((!q && !drugName && !indication) || !searchTerm.trim()) {
  return [{
    json: {
      ...d,
      skip: true,
      skip_reason: 'no_search_anchor',
      search_term: '',
    }
  }];
}

return [{
  json: {
    ...d,
    skip: false,
    search_term: searchTerm,
    built_at: new Date().toISOString(),
  }
}];

// ============================================================
// NODE: 🧬 Transform PubMed XML → Signals
// Input: EFetch HTTP node (XML as string)
// Output: one JSON per PubmedArticle, ready for signals_mesh
// ============================================================

const rawContainer = $input.first().json || {};
// Adjust depending on your HTTP Request config:
const xml = typeof rawContainer.data === 'string'
  ? rawContainer.data
  : (typeof rawContainer === 'string' ? rawContainer : rawContainer.body || '');

// Get context from Extract IDs node (asset + search info)
let ctx = {
  asset_id: 'unknown',
  asset_name: '',
  drug_name: '',
  indication: '',
  search_term: '',
};

try {
  const idsCtx = $('⚙️ Extract PubMed IDs').first().json;
  ctx = {
    asset_id:    idsCtx.asset_id    || 'unknown',
    asset_name:  idsCtx.asset_name  || '',
    drug_name:   idsCtx.drug_name   || '',
    indication:  idsCtx.indication  || '',
    search_term: idsCtx.search_term || '',
  };
} catch (e) {
  // keep defaults
}

// ── Helpers ──────────────────────────────────────────────────
function extractOnce(xmlStr, tag) {
  const m = xmlStr.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`, 'i'));
  return m ? m[1].replace(/<[^>]+>/g, '').trim() : '';
}

function extractAll(xmlStr, tag) {
  const re = new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`, 'gi');
  const out = [];
  let m;
  while ((m = re.exec(xmlStr)) !== null) {
    out.push(m[1].replace(/<[^>]+>/g, '').trim());
  }
  return out;
}

// Structured abstract: concatenate all AbstractText
function extractAbstract(xmlStr) {
  const re = /<AbstractText[^>]*>([\s\S]*?)<\/AbstractText>/gi;
  const parts = [];
  let m;
  while ((m = re.exec(xmlStr)) !== null) {
    const segment = m[1].replace(/<[^>]+>/g, '').trim();
    if (segment) parts.push(segment);
  }
  if (parts.length > 0) return parts.join('\n\n');
  // fallback to Abstract tag
  return extractOnce(xmlStr, 'Abstract');
}

// Authors (LastName + ForeName)
function extractAuthors(xmlStr, maxAuthors = 5) {
  const re = /<Author\b[^>]*>[\s\S]*?<LastName>(.*?)<\/LastName>[\s\S]*?<ForeName>(.*?)<\/ForeName>[\s\S]*?<\/Author>/gi;
  const names = [];
  let m;
  while ((m = re.exec(xmlStr)) !== null && names.length < maxAuthors) {
    const ln = m[1].trim();
    const fn = m[2].trim();
    if (ln || fn) names.push(`${ln} ${fn}`.trim());
  }
  return names.join(', ');
}

// Keywords
function extractKeywords(xmlStr) {
  return extractAll(xmlStr, 'Keyword').filter(Boolean);
}

// Journal title & year
function extractJournal(xmlStr) {
  const journalTitle = extractOnce(xmlStr, 'Title');
  const iso = extractOnce(xmlStr, 'ISOAbbreviation');
  const display = iso || journalTitle;
  return display || '';
}

function extractYear(xmlStr) {
  const y = extractOnce(xmlStr, 'Year');
  if (/^\d{4}$/.test(y)) return y;
  const medlineDate = extractOnce(xmlStr, 'MedlineDate');
  const m = medlineDate.match(/(\d{4})/);
  return m ? m[1] : '';
}

// DOI (ArticleId IdType="doi")
function extractDOI(xmlStr) {
  const re = /<ArticleId[^>]*IdType="doi"[^>]*>(.*?)<\/ArticleId>/i;
  const m = xmlStr.match(re);
  return m ? m[1].trim() : '';
}

// ── Split XML into PubmedArticle blocks ─────────────────────
const parts = xml.split('<PubmedArticle>').slice(1);

const signals = parts.map(block => {
  const article = '<PubmedArticle>' + block;

  const pmid     = extractOnce(article, 'PMID');
  const title    = extractOnce(article, 'ArticleTitle');
  const abstract = extractAbstract(article);
  const journal  = extractJournal(article);
  const year     = extractYear(article);
  const doi      = extractDOI(article);
  const authors  = extractAuthors(article);
  const keywords = extractKeywords(article);

  if (!pmid || (!title && !abstract)) return null;

  const source_id = `pubmed_${pmid}`;

  // Simple relevance scoring vs asset context
  const text = (title + ' ' + abstract).toLowerCase();
  const drugName = (ctx.drug_name || '').toLowerCase();
  const indication = (ctx.indication || '').toLowerCase();

  const drug_hit   = drugName && text.includes(drugName) ? 2 : 0;
  const ind_hit    = indication && text.includes((indication.split(' ')[0] || '').toLowerCase()) ? 1 : 0;
  const length_hit = abstract.length > 200 ? 2 : 0;

  const quality_score = Math.min(10, drug_hit + ind_hit + length_hit);

let impact_level;
if (quality_score >= 6) {
  impact_level = 'HIGH';
} else if (quality_score >= 3) {
  impact_level = 'MED';
} else {
  impact_level = 'LOW';
}


  const notif_priority =
    impact_level === 'HIGH' ? 'P2' :
    impact_level === 'MEDIUM' ? 'P3' :
    'P5';

  const url = doi
    ? `https://doi.org/${doi}`
    : `https://pubmed.ncbi.nlm.nih.gov/${pmid}/`;

  return {
    // Mesh signal schema
    signal_domain: 'ci',
    signal_type:   'publication',
    source_id,
    source:        'pubmed',

    title:        title.slice(0, 512),
    summary:      abstract.slice(0, 4000),
    entity_name:  (ctx.asset_name || '').slice(0, 255),
    drug_name:    (ctx.drug_name || '').slice(0, 255),
    indication:   (ctx.indication || '').slice(0, 4000),
    sponsor:      authors.slice(0, 255),
    geography:    '',
    url:          url.slice(0, 1024),

    impact_level,
    impact_score: quality_score,
    route_tier:   'pubmed',
    notif_priority,

    competitor_flag: false,
    is_urgent:       false,
    confidence:      abstract.length > 200 ? 'high' : 'medium',

    fingerprint: `pubmed_${pmid}`.slice(0, 255),
    dedup_hash:  `pubmed_${pmid}_${ctx.asset_id || 'na'}`.slice(0, 255),

    quality_score,
    score_breakdown: {
      drug_hit,
      ind_hit,
      length_hit,
      abstract_length: abstract.length,
    },
    raw_text: (title + '\n\n' + abstract).slice(0, 8000),

    // Extra metadata for debugging/analytics
    pmid,
    journal: journal.slice(0, 255),
    year,
    keywords,
    doi,

    asset_id:    ctx.asset_id || 'unknown',
    asset_name:  ctx.asset_name || '',
    search_term: ctx.search_term || '',
  };
}).filter(Boolean);

if (!signals.length) {
  return [{
    json: {
      skip: true,
      skip_reason: 'no_parseable_articles',
      asset_id: ctx.asset_id || 'unknown',
    }
  }];
}

return signals.map(s => ({ json: s }));

// 🔧 Build bioRxiv Query Params
const runCtx = $('🔧 Init Run Context').first().json;

// bioRxiv /details API format: YYYY-MM-DD
const today  = new Date();
const past   = new Date();
past.setDate(today.getDate() - (runCtx.lookback_days || 7));

const pad = n => String(n).padStart(2,'0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

return [{
  json: {
    date_from: fmt(past),
    date_to:   fmt(today),
    cursor:    0,
    server:    'biorxiv',   // or 'medrxiv' for clinical preprints
  }
}];

