const safe = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  const out = String(v).replace(/[\x00-\x1F\x7F-\x9F]/g, '').trim();
  return out || fallback;
};

const isNullish = (v) => !v || /^(na|n\/a|none|null|unknown|-)?$/i.test(String(v).trim());

const clamp = (n, min, max) => Math.max(min, Math.min(max, Number(n) || 0));

const truncate = (str, len) => {
  const s = safe(str);
  return s.length > len ? s.slice(0, len) : s;
};

const uniq = (arr) => [...new Set(arr.filter(Boolean))];

const normalizeDate = (raw) => {
  const s = safe(raw);
  if (isNullish(s)) return '';
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  if (/^\d{8}$/.test(s)) return `${s.slice(0,4)}-${s.slice(4,6)}-${s.slice(6,8)}`;
  const d = new Date(s);
  return Number.isNaN(d.getTime()) ? '' : d.toISOString().slice(0, 10);
};

const daysFromNow = (days) => {
  const d = new Date();
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString();
};

const countContains = (text, termSet) => {
  const lower = String(text).toLowerCase();
  let hits = 0;
  for (const t of termSet) if (lower.includes(t)) hits++;
  return hits;
};

const cleanAbstract = (raw) => {
  return safe(raw)
    .replace(/O_FIG[\s\S]*?C_FIG/g, ' ')
    .replace(/[OC]_(LI|LIST|SEC|TITLE|PARA|TABLE|FIG)\b/g, ' ')
    .replace(/\{[a-zA-Z0-9_]+\}/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/org\.highwire\.dtl\.[^\s]*/g, ' ')
    .replace(/FIGDIR\/[^\s"'`]*/g, ' ')
    .replace(/View larger version\s*\([^)]*\):/gi, ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();
};

const normalizeServer = (paper) => {
  const s = safe(paper.server || 'biorxiv').toLowerCase();
  return SERVERS.has(s) ? s : 'biorxiv';
};

const buildPrimaryUrl = ({ doi, jatsxml, server }) => {
  if (doi && DOI_RX.test(doi)) return `https://doi.org/${doi}`;
  if (safe(jatsxml)) return safe(jatsxml);
  return `https://www.${server}.org`;
};

const buildJatsUrl = (paper) => safe(paper.jatsxml || paper['jats xml path'] || '');

const parseAuthors = (paper) => {
  const raw = safe(paper.authors || paper.author || '');
  const arr = raw.split(/[;,]/).map(s => s.trim()).filter(Boolean);
  return {
    author_list: arr,
    author_count: arr.length,
    author_display: arr.length <= 3 ? arr.join(', ') : `${arr.slice(0,2).join(', ')} et al. (${arr.length} authors)`
  };
};

const extractGeography = (paper) => {
  const aff = safe(paper.author_corresponding_institution || paper.institution || '').toLowerCase();
  if (/united states|usa|\bu\.s\b|boston|philadelphia|new york|bethesda|seattle|san francisco/i.test(aff)) return 'US';
  if (/united kingdom|\buk\b|london|oxford|cambridge/i.test(aff)) return 'UK';
  if (/germany|berlin|munich|heidelberg/i.test(aff)) return 'DE';
  if (/france|paris|lyon/i.test(aff)) return 'FR';
  if (/china|beijing|shanghai|wuhan/i.test(aff)) return 'CN';
  if (/japan|tokyo|osaka/i.test(aff)) return 'JP';
  if (/india|delhi|mumbai|bangalore|hyderabad/i.test(aff)) return 'IN';
  if (/canada|toronto|vancouver|montreal/i.test(aff)) return 'CA';
  if (/switzerland|basel|zurich|geneva/i.test(aff)) return 'CH';
  return '';
};

const extractSponsor = (paper) => {
  const institution = safe(paper.author_corresponding_institution || paper.institution || '');
  if (!institution) return '';
  return truncate(institution, 255);
};

const detectStrategicSponsor = (sponsorText) => {
  const lower = String(sponsorText).toLowerCase();
  for (const s of STRATEGIC_SPONSORS) if (lower.includes(s)) return true;
  return false;
};

const extractIndication = (title, abstract, category) => {
  const text = `${title} ${abstract} ${category}`;
  for (const [pattern, label] of INDICATION_PATTERNS) {
    if (pattern.test(text)) return label;
  }
  const cat = safe(category).toLowerCase();
  if (cat.includes('developmental biology')) return 'Developmental Biology';
  if (cat.includes('cell biology')) return 'Cell Biology';
  if (cat.includes('neuroscience')) return 'Neuroscience';
  return '';
};

const extractModality = (text) => {
  const lower = ` ${String(text).toLowerCase()} `;
  for (const [k, v] of MODALITY_PATTERNS) {
    if (lower.includes(k)) return v;
  }
  return '';
};

const extractPhase = (text) => {
  const t = String(text);
  if (/phase\s*(iii|3)\b/i.test(t)) return 'Phase III';
  if (/phase\s*(ii|2)\/(iii|3)\b/i.test(t)) return 'Phase II/III';
  if (/phase\s*(ii|2)\b/i.test(t)) return 'Phase II';
  if (/phase\s*(i|1)\/(ii|2)\b/i.test(t)) return 'Phase I/II';
  if (/phase\s*(i|1)\b/i.test(t)) return 'Phase I';
  if (/randomized|double-blind|placebo-controlled/i.test(t)) return 'Clinical Study';
  if (/preclinical|xenograft|mouse model|in vivo/i.test(t)) return 'Preclinical';
  if (/in vitro/i.test(t)) return 'In Vitro';
  return '';
};

const detectEvidenceClass = (title, abstract, category) => {
  const t = `${title} ${abstract} ${category}`.toLowerCase();

  if (/phase\s*i|phase\s*ii|phase\s*iii|randomized|placebo|patient|cohort|subjects|dose escalation|nct\d{8}/i.test(t)) {
    return 'clinical_preprint';
  }
  if (/xenograft|mouse model|murine|organoid|patient-derived xenograft|pdx|in vivo|preclinical/i.test(t)) {
    return 'translational_preclinical';
  }
  if (/machine learning|deep learning|computational|bioinformatics|single-cell atlas|modeling|simulation/i.test(t)) {
    return 'computational_bio';
  }
  if (/mechanism|mechanical regulation|signaling network|gene regulatory network|morphogen|developmental biology|cell fate|pathway/i.test(t)) {
    return 'basic_mechanistic';
  }
  if (/toxicity|adverse event|safety|fatal|mortality/i.test(t)) {
    return 'safety_signal_like';
  }
  return 'general_biomedical';
};

const detectPublishedState = (published) => {
  return !isNullish(published) ? 'published_linked' : 'preprint_only';
};

const detectDrugCandidate = (title, abstract) => {
  const text = `${title} ${abstract}`;

  for (const rx of CELL_LINE_PATTERNS) {
    const m = text.match(rx);
    if (m) {
      return {
        drug_name: '',
        entity_name: m[0].toUpperCase(),
        entity_kind: 'cell_line',
        extraction_confidence: 0.15,
        extraction_method: 'cell_line_detected'
      };
    }
  }

  const suffixHits = uniq([...text.matchAll(DRUG_SUFFIX_RX)].map(m => m[1].toLowerCase()));
  if (suffixHits.length) {
    return {
      drug_name: suffixHits[0],
      entity_name: suffixHits[0],
      entity_kind: 'drug_like',
      extraction_confidence: 0.9,
      extraction_method: 'inn_suffix'
    };
  }

  const codeHits = uniq([...text.matchAll(CODE_COMPOUND_RX)].map(m => m[1]));
  if (codeHits.length) {
    return {
      drug_name: codeHits[0],
      entity_name: codeHits[0],
      entity_kind: 'compound_code',
      extraction_confidence: 0.82,
      extraction_method: 'compound_code'
    };
  }

  return {
    drug_name: '',
    entity_name: '',
    entity_kind: 'unknown',
    extraction_confidence: 0.1,
    extraction_method: 'none'
  };
};

const inferTherapeuticRelevance = ({ evidence_class, indication, modality, category, title, abstract }) => {
  let score = 0;
  const text = `${title} ${abstract} ${category} ${indication}`.toLowerCase();

  if (HIGH_VALUE_CATEGORIES.has(String(category).toLowerCase())) score += 1.5;
  if (countContains(text, HIGH_VALUE_INDICATIONS) >= 1) score += 2.0;
  if (modality) score += 1.0;

  if (evidence_class === 'clinical_preprint') score += 3.0;
  else if (evidence_class === 'translational_preclinical') score += 2.0;
  else if (evidence_class === 'computational_bio') score += 1.0;
  else if (evidence_class === 'basic_mechanistic') score += 0.75;
  else if (evidence_class === 'safety_signal_like') score += 2.5;

  if (/first.?in.?class|novel target|drug resistance|biomarker|combination therapy/i.test(text)) score += 1.0;

  return clamp(score, 0, 10);
};

const scoreSignal = (ctx) => {
  const {
    title, abstract, category, indication, modality, sponsor, doi, url, jatsxml,
    version_num, type, license, published_state, entity_kind,
    extraction_confidence, phase, has_nct_id, author_count,
    is_watchlisted, watchlist_match_count, evidence_class
  } = ctx;

  const fullText = `${title} ${abstract} ${category} ${indication}`.toLowerCase();
  const bd = {};

  let completeness = 0;
  if (title.length > 20) completeness += 0.4;
  if (abstract.length > 250) completeness += 0.8;
  if (doi) completeness += 0.3;
  if (url) completeness += 0.2;
  if (jatsxml) completeness += 0.2;
  if (author_count > 0) completeness += 0.1;
  completeness = clamp(completeness, 0, 2.0);
  bd.completeness = +completeness.toFixed(2);

  let maturity = 0;
  if (version_num >= 2) maturity += 0.4;
  if (version_num >= 3) maturity += 0.4;
  if (published_state === 'published_linked') maturity += 0.8;
  if (/confirmatory results/i.test(type)) maturity += 0.3;
  if (/cc_by|cc_by_nc|cc0|cc_no/i.test(license)) maturity += 0.1;
  maturity = clamp(maturity, 0, 1.8);
  bd.publication_maturity = +maturity.toFixed(2);

  let clinical = 0;
  if (phase === 'Phase III') clinical += 2.0;
  else if (phase === 'Phase II/III') clinical += 1.8;
  else if (phase === 'Phase II') clinical += 1.5;
  else if (phase === 'Phase I/II') clinical += 1.2;
  else if (phase === 'Phase I') clinical += 1.0;
  else if (phase === 'Clinical Study') clinical += 1.0;
  else if (phase === 'Preclinical') clinical += 0.5;
  else if (phase === 'In Vitro') clinical += 0.2;
  if (has_nct_id) clinical += 0.5;
  clinical = clamp(clinical, 0, 2.2);
  bd.clinical_relevance = +clinical.toFixed(2);

  let therapeutic = inferTherapeuticRelevance(ctx);
  bd.therapeutic_relevance = +therapeutic.toFixed(2);

  let sponsorScore = detectStrategicSponsor(sponsor) ? 1.0 : 0.2;
  bd.sponsor_signal = +sponsorScore.toFixed(2);

  let watchlist = is_watchlisted ? (watchlist_match_count >= 2 ? 1.2 : 0.8) : 0;
  bd.watchlist_boost = +watchlist.toFixed(2);

  let entityPenalty = 0;
  if (entity_kind === 'cell_line') entityPenalty = -1.0;
  else if (entity_kind === 'unknown') entityPenalty = -0.25;
  bd.entity_penalty = +entityPenalty.toFixed(2);

  let evidenceBoost = 0;
  if (evidence_class === 'clinical_preprint') evidenceBoost = 1.5;
  else if (evidence_class === 'translational_preclinical') evidenceBoost = 1.0;
  else if (evidence_class === 'safety_signal_like') evidenceBoost = 1.0;
  else if (evidence_class === 'basic_mechanistic') evidenceBoost = 0.3;
  bd.evidence_boost = +evidenceBoost.toFixed(2);

  const rawScore = completeness + maturity + clinical + (therapeutic / 2.5) + sponsorScore + watchlist + evidenceBoost + entityPenalty;
  const impact_score = clamp(+rawScore.toFixed(2), 0, 10);

  const quality_score = clamp(
    (title ? 2 : 0) +
    (abstract.length > 250 ? 2 : 0) +
    (doi ? 1 : 0) +
    (url ? 1 : 0) +
    (jatsxml ? 1 : 0) +
    (author_count > 1 ? 1 : 0) +
    (phase ? 1 : 0) +
    (indication ? 1 : 0) +
    (extraction_confidence >= 0.8 ? 1 : 0),
    0, 10
  );

  let impact_level = 'LOW';
  if (impact_score >= 7.2) impact_level = 'HIGH';
  else if (impact_score >= 4.2) impact_level = 'MED';

  const competitor_flag = detectStrategicSponsor(sponsor) || is_watchlisted;

  const is_urgent =
    evidence_class === 'clinical_preprint' &&
    (impact_level === 'HIGH' || /breakthrough|overall survival|phase iii|first-in-human/i.test(fullText));

  let route_tier = 'T3_MONITOR';
  if (
    impact_level === 'HIGH' ||
    (competitor_flag && evidence_class === 'clinical_preprint') ||
    (published_state === 'published_linked' && impact_score >= 6.5)
  ) {
    route_tier = 'T1_CRITICAL';
  } else if (
    impact_level === 'MED' ||
    competitor_flag ||
    evidence_class === 'translational_preclinical'
  ) {
    route_tier = 'T2_REVIEW';
  }

  let confidence = 'low';
  if (quality_score >= 8 && extraction_confidence >= 0.8) confidence = 'high';
  else if (quality_score >= 5) confidence = 'medium';

  bd.total = impact_score;
  bd.version = version_num;
  bd.type = type || '';
  bd.license = license || '';
  bd.evidence_class = evidence_class;
  bd.published_state = published_state;
  bd.entity_kind = entity_kind;

  return {
    impact_score,
    impact_level,
    quality_score,
    route_tier,
    competitor_flag,
    is_urgent,
    confidence,
    score_breakdown: bd
  };
};

// ─────────────────────────────────────────────────────────────
// 3. WATCHLIST
// ─────────────────────────────────────────────────────────────

let watchlist = [];
try {
  const runCtx = $('🔧 Init Run Context').first().json;
  watchlist = (runCtx.oncology_drugs || runCtx.watchlist || [])
    .map(v => String(v).toLowerCase().trim())
    .filter(Boolean);
} catch {
  watchlist = [];
}

const matchWatchlist = (text) => {
  const lower = String(text).toLowerCase();
  const hits = watchlist.filter(w => lower.includes(w));
  return { is_watchlisted: hits.length > 0, watchlist_match_count: hits.length, watchlist_hits: hits };
};

// ─────────────────────────────────────────────────────────────
// 4. UNWRAP INPUT
// ─────────────────────────────────────────────────────────────

const records = [];
const output = [];

for (const item of $input.all()) {
  const body = item.json || {};

  if (Array.isArray(body.collection)) records.push(...body.collection);
  else if (Array.isArray(body.results)) records.push(...body.results);
  else if (Array.isArray(body.data)) records.push(...body.data);
  else if (Array.isArray(body)) records.push(...body);
  else if (body.title || body.abstract || body.doi) records.push(body);
  else {
    output.push({
      json: {
        _error: true,
        _error_message: 'Unknown bioRxiv response structure',
        _received_keys: Object.keys(body).join(', '),
        source: 'biorxiv',
        signal_domain: 'ci',
        signal_type: 'publication',
        impact_level: 'LOW',
        impact_score: 0,
        quality_score: 0,
        route_tier: 'T3_MONITOR',
        notif_priority: 'P5',
        alert_channels: ['pharmaos-digest'],
      }
    });
  }
}

// ─────────────────────────────────────────────────────────────
// 5. MAIN LOOP
// ─────────────────────────────────────────────────────────────

for (const paper of records) {
  try {
    const doi = safe(paper.doi || paper.DOI || '');
    const title = truncate(cleanAbstract(paper.title || ''), 500);
    const abstract = truncate(cleanAbstract(paper.abstract || paper.description || ''), 8000);
    const server = normalizeServer(paper);
    const version_num = clamp(parseInt(safe(paper.version || '1'), 10) || 1, 1, 20);
    const type = safe(paper.type || '');
    const license = safe(paper.license || '');
    const category = safe(paper.category || paper.subject || '').toLowerCase();
    const jatsxml = buildJatsUrl(paper);
    const published_raw = safe(paper.published || paper.date || '');
    const published = normalizeDate(published_raw);
    const published_state = detectPublishedState(published_raw);
    const primary_url = buildPrimaryUrl({ doi, jatsxml, server });

    const { author_list, author_count, author_display } = parseAuthors(paper);
    const sponsor = extractSponsor(paper);
    const geography = extractGeography(paper);
    const funder = isNullish(paper.funder) ? '' : truncate(safe(paper.funder), 255);

    const entity = detectDrugCandidate(title, abstract);
    const indication = extractIndication(title, abstract, category);
    const modality = extractModality(`${title} ${abstract}`);
    const phase = extractPhase(`${title} ${abstract}`);
    const nct_id = (String(title + ' ' + abstract).match(NCT_RX) || [null])[0];
    const has_nct_id = !!nct_id;
    const evidence_class = detectEvidenceClass(title, abstract, category);

    const watchContext = `${title} ${abstract} ${indication} ${category} ${entity.drug_name} ${entity.entity_name}`;
    const { is_watchlisted, watchlist_match_count, watchlist_hits } = matchWatchlist(watchContext);

    const scores = scoreSignal({
      title,
      abstract,
      category,
      indication,
      modality,
      sponsor,
      doi,
      url: primary_url,
      jatsxml,
      version_num,
      type,
      license,
      published_state,
      entity_kind: entity.entity_kind,
      extraction_confidence: entity.extraction_confidence,
      phase,
      has_nct_id,
      author_count,
      is_watchlisted,
      watchlist_match_count,
      evidence_class
    });

    const signal_type = CATEGORY_TO_TYPE[category] || 'publication';
    const notif_priority = TIER_TO_PRIORITY[scores.route_tier] || 'P5';
    const alert_channels = TIER_TO_CHANNELS[scores.route_tier] || ['pharmaos-digest'];
    const ttl_expires_at = daysFromNow(TIER_TTL_DAYS[scores.route_tier] || 30);

    const source_id = doi
      ? `biorxiv_${doi.replace(/[\/\s]+/g, '_')}`
      : `biorxiv_${server}_${title.toLowerCase().replace(/\W+/g, '_').slice(0, 80)}`;

    const fingerprint = `ci|${entity.drug_name || entity.entity_name || 'unknown'}|publication|${server}|${doi || source_id}`;
    const dedup_hash = doi
      ? `${server}|${doi}`
      : `${server}|${title.toLowerCase().replace(/\W+/g, '_').slice(0, 120)}|v${version_num}`;

    const signalTitle = truncate(
      `${server === 'medrxiv' ? 'medRxiv' : 'bioRxiv'}: ${title}${phase ? ` [${phase}]` : ''}${published_state === 'published_linked' ? ' 📘' : ''}${is_watchlisted ? ' 🔍' : ''}`,
      512
    );

    const summaryParts = [
      indication ? `${indication}.` : '',
      evidence_class ? `Evidence: ${evidence_class.replace(/_/g, ' ')}.` : '',
      entity.entity_kind === 'cell_line' ? `Model system detected: ${entity.entity_name}.` : '',
      abstract
    ].filter(Boolean);

    const summary = truncate(summaryParts.join(' '), 4000);

    const rawText = truncate([
      `TITLE: ${title}`,
      doi ? `DOI: ${doi}` : '',
      `SERVER: ${server}`,
      `VERSION: ${version_num}`,
      type ? `TYPE: ${type}` : '',
      license ? `LICENSE: ${license}` : '',
      category ? `CATEGORY: ${category}` : '',
      published ? `PUBLISHED: ${published}` : '',
      published_state ? `PUBLISHED_STATE: ${published_state}` : '',
      jatsxml ? `JATS_XML: ${jatsxml}` : '',
      sponsor ? `SPONSOR/INSTITUTION: ${sponsor}` : '',
      funder ? `FUNDER: ${funder}` : '',
      geography ? `GEOGRAPHY: ${geography}` : '',
      author_display ? `AUTHORS: ${author_display}` : '',
      indication ? `INDICATION: ${indication}` : '',
      modality ? `MODALITY: ${modality}` : '',
      phase ? `PHASE: ${phase}` : '',
      nct_id ? `NCT_ID: ${nct_id}` : '',
      entity.entity_name ? `ENTITY_NAME: ${entity.entity_name}` : '',
      entity.drug_name ? `DRUG_NAME: ${entity.drug_name}` : '',
      `ENTITY_KIND: ${entity.entity_kind}`,
      `EXTRACTION_METHOD: ${entity.extraction_method}`,
      `EXTRACTION_CONFIDENCE: ${entity.extraction_confidence}`,
      `EVIDENCE_CLASS: ${evidence_class}`,
      is_watchlisted ? `WATCHLIST_HITS: ${watchlist_hits.join(', ')}` : '',
      '',
      'ABSTRACT:',
      abstract
    ].filter(Boolean).join('\n'), 9000);

    output.push({
      json: {
        source_id,
        source: server,
        signal_domain: 'ci',
        signal_type,

        drug_name: entity.drug_name || null,
        entity_name: entity.entity_name || null,
        asset_id: null,

        indication: indication || null,
        sponsor: sponsor || null,
        geography: geography || null,
        nct_id,
        phase: phase || 'NA',
        status: published_state === 'published_linked' ? 'Published-linked' : 'NA',
        moa: null,
        modality: modality || null,

        title: signalTitle,
        summary,
        url: primary_url || null,
        raw_text: rawText,

        impact_score: scores.impact_score,
        impact_level: scores.impact_level,
        quality_score: scores.quality_score,
        priority_score: scores.impact_score,
        score_breakdown: scores.score_breakdown,
        scoring_version: SCORING_VERSION,

        route_tier: scores.route_tier,
        notif_priority,
        alert_channels,
        ttl_expires_at,

        competitor_flag: scores.competitor_flag,
        is_urgent: scores.is_urgent,
        confidence: scores.confidence,

        fingerprint,
        dedup_hash,

        ai_processed: false,

        _source_meta: {
          pipeline_version: PIPELINE_VERSION,
          doi: doi || null,
          version: version_num,
          type: type || null,
          license: license || null,
          category: category || null,
          jatsxml: jatsxml || null,
          published: published || null,
          published_state,
          funder: funder || null,
          author_count,
          watchlist_hits,
          extraction_method: entity.extraction_method,
          extraction_confidence: entity.extraction_confidence,
          entity_kind: entity.entity_kind,
          evidence_class
        }
      }
    });

  } catch (err) {
    output.push({
      json: {
        _error: true,
        _error_message: err.message,
        _raw_title: truncate(safe(paper.title || ''), 120),
        _raw_doi: safe(paper.doi || ''),
        source: normalizeServer(paper),
        signal_domain: 'ci',
        signal_type: 'publication',
        impact_level: 'LOW',
        impact_score: 0,
        quality_score: 0,
        route_tier: 'T3_MONITOR',
        notif_priority: 'P5',
        alert_channels: ['pharmaos-digest'],
        first_seen_at: new Date().toISOString(),
        last_seen_at:  new Date().toISOString(),
        ingested_at:   new Date().toISOString(),
      }
    });
  }
}

return output;

const items = $input.all();
return [{
  json: {
    source: 'biorxiv',
    fetched: items.length,
    new: items.filter(i => i.json.is_new === true).length,
    updated: items.filter(i => i.json.is_new === false).length,
    deduped: items.filter(i => i.json.is_new === false).length,
    errors: 0
  }
}];

const PIPELINE_VERSION = '2.0.0';

// ─────────────────────────────────────────────────────────────
// SECTION 1: POLICY CONFIG
// ─────────────────────────────────────────────────────────────

const TIER_CONFIG = {
  T1_CRITICAL: {
    label:        'CRITICAL',
    emoji:        '🚨',
    color:        '#C0392B',
    notif_priority: 'P1',
    channels:     ['pharmaos-critical','pharmaos-executive','medical-affairs'],
    send_realtime: true,
    send_digest:   false,
  },
  T2_REVIEW: {
    label:        'REVIEW',
    emoji:        '⚠️',
    color:        '#E67E22',
    notif_priority: 'P3',
    channels:     ['pharmaos-regulatory','ci-team'],
    send_realtime: true,
    send_digest:   true,
  },
  T3_MONITOR: {
    label:        'MONITOR',
    emoji:        '📋',
    color:        '#2980B9',
    notif_priority: 'P5',
    channels:     ['pharmaos-digest'],
    send_realtime: false,
    send_digest:   true,
  },
};

const TIER_TTL = { T1_CRITICAL:90, T2_REVIEW:60, T3_MONITOR:30 };

const DOMAIN_EMOJI = {
  ci:         '🔬',
  regulatory: '📄',
  safety:     '⚕️',
  bd:         '🤝',
};

const SOURCE_LABEL = {
  clinicaltrials: 'ClinicalTrials.gov',
  pubmed:         'PubMed',
  faers:          'FDA FAERS',
  fda_labels:     'FDA Labels',
  fda_recalls:    'FDA Recalls',
  dailymed:       'DailyMed',
  biorxiv:        'bioRxiv',
  medrxiv:        'medRxiv',
  sec_edgar:      'SEC EDGAR',
  news:           'News Feed',
  conference:     'Conference',
};

const IMPACT_EMOJI = { HIGH:'🔴', MED:'🟡', LOW:'🟢' };
const ACTION_EMOJI = { ESCALATE:'🚨', MONITOR:'👁️', DISMISS:'✅', REVIEW:'🔍' };

// Domain-level hard policy (prevents misrouting)
// e.g. safety T1 always; BD seldom T1
const DOMAIN_POLICY = {
  safety: {
    min_tier_for_high: 'T1_CRITICAL',
    default_tier:      'T2_REVIEW',
  },
  regulatory: {
    min_tier_for_high: 'T1_CRITICAL',
    default_tier:      'T2_REVIEW',
  },
  ci: {
    min_tier_for_high: 'T1_CRITICAL',
    default_tier:      'T3_MONITOR',
  },
  bd: {
    min_tier_for_high: 'T2_REVIEW',  // BD rarely T1 by default
    default_tier:      'T2_REVIEW',
  },
};

// Impact score → base tier (before domain & override policy)
function baseTierFromImpact(level, score) {
  if (level === 'HIGH' || score >= 7.5) return 'T1_CRITICAL';
  if (level === 'MED'  || score >= 4.0) return 'T2_REVIEW';
  return 'T3_MONITOR';
}

// ─────────────────────────────────────────────────────────────
// SECTION 2: UTILITY HELPERS
// ─────────────────────────────────────────────────────────────

const safe = (v, fallback = 'N/A') => {
  if (v === null || v === undefined || v === '') return fallback;
  return String(v).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g,'').trim() || fallback;
};

const safeNum = (v, fallback = 0) => {
  const n = Number(v);
  return isNaN(n) ? fallback : n;
};

const truncate = (str, len) => {
  const s = safe(str, '');
  return s.length > len ? s.slice(0, len - 3) + '...' : s;
};

const safeArr = (v) => {
  if (Array.isArray(v)) return v.filter(x => x !== null && x !== undefined);
  return [];
};

const slackEsc = (text) =>
  safe(text, '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

const formatScore = (n) => `${safeNum(n, 0).toFixed(1)}/10`;

const formatDate = (iso) => {
  if (!iso) return 'N/A';
  try { return new Date(iso).toLocaleString('en-IN', { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit' }); }
  catch { return String(iso).slice(0, 16); }
};

const relativeTime = (iso) => {
  if (!iso) return '';
  const diffMs = Date.now() - new Date(iso).getTime();
  const hrs    = Math.floor(diffMs / 3600000);
  if (hrs < 1)  return 'just now';
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 7) return `${days}d ago`;
  const weeks = Math.floor(days / 7);
  return `${weeks}w ago`;
};

const isNullish = (v) =>
  v === null || v === undefined || v === '' ||
  /^(na|n\/a|none|null|unknown|-)$/i.test(String(v).trim());

// ─────────────────────────────────────────────────────────────
// SECTION 3: NORMALIZER & POLICY APPLICATION
// ─────────────────────────────────────────────────────────────

function normalizeSignal(raw) {
  const domain = safe(raw.signal_domain, 'ci').toLowerCase();
  const impactLevelRaw = String(raw.impact_level || '').toUpperCase();
  const impact_level = ['HIGH','MED','LOW'].includes(impactLevelRaw)
    ? impactLevelRaw : 'LOW';
  const impact_score = safeNum(raw.impact_score, 0);

  // Base tier by score
  let route_tier = baseTierFromImpact(impact_level, impact_score);

  // Domain policy: enforce minimum tier for HIGH signals
  const domPolicy = DOMAIN_POLICY[domain] || DOMAIN_POLICY.ci;
  if (impact_level === 'HIGH') {
    const order = { T1_CRITICAL:0, T2_REVIEW:1, T3_MONITOR:2 };
    const minTier = domPolicy.min_tier_for_high || 'T1_CRITICAL';
    if (order[route_tier] > order[minTier]) route_tier = minTier;
  }

  // Override-aware adjustment
  const override_status = safe(raw.override_status || raw.overridestatus, '');
  const override_by     = safe(raw.override_by     || raw.overrideby, '');
  const override_reason = safe(raw.override_reason || raw.overridereason, '');
  const hasOverride     = !!override_status && override_status !== 'null';

  if (hasOverride) {
    // Hard override: UPGRADE/DOWNGRADE/DISMISS/REOPEN
    if (override_status === 'DISMISS') {
      // Keep in DB, but suppress alerts/digest completely
      route_tier = 'T3_MONITOR';
    }
  }

  const tierCfg = TIER_CONFIG[route_tier];

  // Notif priority fallback if upstream didn't set or mismatch
  const notif_priority = safe(raw.notif_priority, tierCfg.notif_priority);

  // Alert channels: union of upstream + policy defaults
  const upstreamChannels = safeArr(raw.alert_channels || []);
  const alert_channels = upstreamChannels.length > 0
    ? Array.from(new Set([...upstreamChannels, ...tierCfg.channels]))
    : tierCfg.channels;

  // Recommended action & AI summary
  const ai_summary         = safe(raw.ai_summary, '');
  const recommended_action = safe(raw.recommended_action || raw.recommendedaction, '');

  // Derived risk heuristics from score_breakdown (if present)
  const sb = raw.score_breakdown || {};
  const hasSevereRisk =
    sb.safety_terms_found >= 3 ||
    sb.has_boxed_warning === true ||
    sb.rems_required === true ||
    /HIGH/i.test(sb.risk_level || '');

  const inferredIsUrgent = hasSevereRisk && (impact_level === 'HIGH' || impact_score >= 6.5);

  const normalized = {
    // Identity
    source_id:     safe(raw.source_id || raw.id, 'unknown'),
    source:        safe(raw.source, 'unknown'),
    signal_domain: domain,
    signal_type:   safe(raw.signal_type, 'unknown'),

    // Drug / Asset
    drug_name:     safe(raw.drug_name || raw.entity_name, 'Unknown'),
    indication:    safe(raw.indication, ''),
    sponsor:       safe(raw.sponsor, ''),
    geography:     safe(raw.geography, 'US'),
    phase:         safe(raw.phase, ''),
    status:        safe(raw.status, ''),
    moa:           safe(raw.moa, ''),
    modality:      safe(raw.modality, ''),
    asset_id:      raw.asset_id || null,

    // Content
    title:         truncate(raw.title || `Signal: ${raw.drug_name || 'Unknown'}`, 300),
    summary:       truncate(raw.summary || ai_summary, 800),
    url:           safe(raw.url, ''),
    raw_text:      safe(raw.raw_text, ''),

    // Scoring
    impact_level,
    impact_score,
    quality_score: safeNum(raw.quality_score, 0),
    priority_score: safeNum(raw.priority_score || impact_score, impact_score),
    score_breakdown: sb,
    scoring_version: raw.scoring_version || 2,

    // Routing
    route_tier,
    notif_priority,
    alert_channels,

    // Flags
    competitor_flag: Boolean(raw.competitor_flag),
    is_urgent:       Boolean(raw.is_urgent || inferredIsUrgent),
    confidence:      safe(raw.confidence, 'low'),

    // AI enrichment
    ai_summary,
    recommended_action,
    ai_processed: raw.ai_processed === true,

    // Overrides
    override_status,
    override_by,
    override_reason,
    has_override: hasOverride,

    // Lineage / dedup
    fingerprint: safe(raw.fingerprint, ''),
    dedup_hash:  safe(raw.dedup_hash, ''),
    parent_signal_id: raw.parent_signal_id || null,
    lineage_chain:    raw.lineage_chain || [],

    // Timestamps
    ingested_at:  raw.ingested_at || new Date().toISOString(),
    first_seen_at: raw.first_seen_at || raw.ingested_at || new Date().toISOString(),
    last_seen_at:  raw.last_seen_at || new Date().toISOString(),

    // TTL — allow upstream to override, else derive from tier
    ttl_expires_at: raw.ttl_expires_at || (
      TIER_TTL[route_tier]
        ? (() => { const d = new Date(); d.setDate(d.getDate() + TIER_TTL[route_tier]); return d.toISOString(); })()
        : null
    ),

    // Pipeline meta
    pipeline_version: PIPELINE_VERSION,
  };

  return normalized;
}

// ─────────────────────────────────────────────────────────────
// SECTION 4: SLACK BLOCK KIT BUILDERS
// ─────────────────────────────────────────────────────────────

// Real-time alert (T1/T2)
function buildRealtimeAlert(s) {
  const cfg      = TIER_CONFIG[s.route_tier];
  const domEmoji = DOMAIN_EMOJI[s.signal_domain] || '📡';
  const impEmoji = IMPACT_EMOJI[s.impact_level]  || '⚪';
  const srcLabel = SOURCE_LABEL[s.source] || s.source.toUpperCase();
  const actEmoji = ACTION_EMOJI[s.recommended_action] || '🔍';
  const confPct  = s.confidence === 'high' ? '90%' : s.confidence === 'medium' ? '65%' : '40%';

  const drivers = safeArr(s.score_breakdown?.drivers).slice(0, 4);
  const risks   = safeArr(s.score_breakdown?.risks).slice(0, 3);

  const overrideBadge = s.has_override
    ? `  ·  Override: *${slackEsc(s.override_status)}* by ${slackEsc(s.override_by)}`
    : '';

  const headerText = `${cfg.emoji} ${cfg.label} · ${impEmoji} ${s.impact_level} · ${domEmoji} ${slackEsc(s.drug_name)}${overrideBadge}`;

  const blocks = [
    {
      type: 'header',
      text: { type: 'plain_text', text: headerText, emoji: true }
    },
    { type: 'divider' },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Drug / Asset*\n${slackEsc(s.drug_name)}` },
        { type: 'mrkdwn', text: `*Indication*\n${truncate(s.indication, 80) || 'N/A'}` },
        { type: 'mrkdwn', text: `*Sponsor*\n${slackEsc(s.sponsor) || 'N/A'}` },
        { type: 'mrkdwn', text: `*Phase / Status*\n${slackEsc(s.phase) || '—'} ${s.status ? '· ' + slackEsc(s.status) : ''}` },
        { type: 'mrkdwn', text: `*Source*\n${srcLabel}` },
        { type: 'mrkdwn', text: `*Signal Type*\n${slackEsc(s.signal_type)}` },
      ]
    },
    { type: 'divider' },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Impact*\n${formatScore(s.impact_score)} ${impEmoji}` },
        { type: 'mrkdwn', text: `*Quality*\n${s.quality_score}/10` },
        { type: 'mrkdwn', text: `*Confidence*\n${confPct}` },
        { type: 'mrkdwn', text: `*Competitor*\n${s.competitor_flag ? '🔴 YES' : '⚪ No'}` },
        { type: 'mrkdwn', text: `*Urgent*\n${s.is_urgent ? '🚨 YES' : '—'}` },
        { type: 'mrkdwn', text: `*First Seen*\n${relativeTime(s.first_seen_at)}` },
      ]
    },
    { type: 'divider' },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*📌 ${slackEsc(s.title)}*` }
    },
    ...(s.summary ? [{
      type: 'section',
      text: { type: 'mrkdwn', text: truncate(s.summary, 700) }
    }] : []),
    ...(drivers.length > 0 || risks.length > 0 ? [
      { type: 'divider' },
      {
        type: 'section',
        fields: [
          {
            type: 'mrkdwn',
            text: `*🔺 Key Drivers*\n${drivers.length ? drivers.map(d => `• ${slackEsc(d)}`).join('\n') : '—'}`
          },
          {
            type: 'mrkdwn',
            text: `*⚠️ Risks / Caveats*\n${risks.length ? risks.map(r => `• ${slackEsc(r)}`).join('\n') : '—'}`
          },
        ]
      }
    ] : []),
    ...(s.recommended_action ? [
      { type: 'divider' },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `${actEmoji} *Recommended Action:* ${slackEsc(s.recommended_action)}`
        }
      }
    ] : []),
    ...(s.url ? [{
      type: 'actions',
      elements: [{
        type: 'button',
        text: { type: 'plain_text', text: '🔗 View Source', emoji: true },
        url:  s.url,
        style: s.route_tier === 'T1_CRITICAL' ? 'danger' : 'primary',
      }]
    }] : []),
    {
      type: 'context',
      elements: [{
        type: 'mrkdwn',
        text: [
          `📡 PharmaOS v${PIPELINE_VERSION}`,
          `🆔 ${s.source_id}`,
          `⏱ ${formatDate(s.last_seen_at)}`,
          s.asset_id ? `💊 Asset: ${slackEsc(s.asset_id)}` : '',
          s.dedup_hash ? `🔑 ${s.dedup_hash.slice(0, 18)}…` : '',
        ].filter(Boolean).join('  ·  ')
      }]
    }
  ];

  return {
    text: `${cfg.emoji} ${s.drug_name} — ${s.impact_level} ${srcLabel} signal`,
    blocks,
  };
}

// Digest entry (single signal line)
function buildDigestEntry(s, idx) {
  const impEmoji = IMPACT_EMOJI[s.impact_level] || '⚪';
  const srcLabel = SOURCE_LABEL[s.source] || s.source.toUpperCase();
  const cfg      = TIER_CONFIG[s.route_tier];

  const tags = [
    s.competitor_flag ? 'Competitor' : '',
    s.is_urgent       ? 'Urgent'     : '',
    s.asset_id        ? 'Linked Asset' : '',
    s.signal_domain   === 'safety' ? 'Safety' : '',
  ].filter(Boolean);

  const tagStr = tags.length ? `  ·  _${tags.join(', ')}_` : '';

  return {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: [
        `*${idx}. ${impEmoji} ${slackEsc(s.drug_name)}*  ${cfg.emoji} ${cfg.label}${tagStr}`,
        `${truncate(s.title, 140)}`,
        [
          s.indication ? `📌 ${truncate(s.indication, 60)}` : '',
          s.sponsor    ? `🏢 ${slackEsc(s.sponsor)}`        : '',
          `📊 ${formatScore(s.impact_score)}`,
          `🔍 ${srcLabel}`,
          `⏱ ${relativeTime(s.first_seen_at)}`,
          s.url ? `<${s.url}|View ↗>`                      : '',
        ].filter(Boolean).join('  ·  '),
      ].filter(Boolean).join('\n')
    }
  };
}

// Digest (batch of signals)
function buildBatchDigest(signals, runId) {
  const nowStr = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });

  // Sort inside digest by tier & score
  const sorted = [...signals].sort((a, b) => {
    const order = { T1_CRITICAL:0, T2_REVIEW:1, T3_MONITOR:2 };
    const tDiff = (order[a.route_tier] || 2) - (order[b.route_tier] || 2);
    return tDiff !== 0 ? tDiff : b.impact_score - a.impact_score;
  });

  const t1 = sorted.filter(s => s.route_tier === 'T1_CRITICAL');
  const t2 = sorted.filter(s => s.route_tier === 'T2_REVIEW');
  const t3 = sorted.filter(s => s.route_tier === 'T3_MONITOR');

  // Domain / source breakdown
  const domCounts = {};
  const srcCounts = {};
  const compCount = sorted.filter(s => s.competitor_flag).length;
  const urgCount  = sorted.filter(s => s.is_urgent).length;

  for (const s of sorted) {
    domCounts[s.signal_domain] = (domCounts[s.signal_domain] || 0) + 1;
    const srcLabel = SOURCE_LABEL[s.source] || s.source;
    srcCounts[srcLabel] = (srcCounts[srcLabel] || 0) + 1;
  }

  const domainSummary = Object.entries(domCounts)
    .map(([d,c]) => `${DOMAIN_EMOJI[d] || '📡'} ${d}: ${c}`)
    .join('  ·  ');

  const srcSummary = Object.entries(srcCounts)
    .map(([src,c]) => `${src} (${c})`).join(', ');

  const blocks = [
    {
      type: 'header',
      text: { type:'plain_text', text:`📊 PharmaOS Signal Digest — ${nowStr}`, emoji:true }
    },
    { type: 'divider' },
    {
      type: 'section',
      fields: [
        { type:'mrkdwn', text:`*Total Signals*\n${sorted.length}` },
        { type:'mrkdwn', text:`*🚨 Critical (T1)*\n${t1.length}` },
        { type:'mrkdwn', text:`*⚠️ Review (T2)*\n${t2.length}` },
        { type:'mrkdwn', text:`*📋 Monitor (T3)*\n${t3.length}` },
        { type:'mrkdwn', text:`*Competitor Flags*\n${compCount}` },
        { type:'mrkdwn', text:`*Urgent Signals*\n${urgCount}` },
      ]
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: [
          `*Domains:* ${domainSummary || 'N/A'}`,
          `*Sources:* ${srcSummary || 'N/A'}`,
        ].join('\n')
      }
    },
    ...(t1.length ? [
      { type:'divider' },
      { type:'section', text:{ type:'mrkdwn', text:`🚨 *CRITICAL SIGNALS (${t1.length})*` } },
      ...t1.slice(0,5).map((s,i) => buildDigestEntry(s,i+1)),
      ...(t1.length > 5 ? [{
        type:'context',
        elements:[{ type:'mrkdwn', text:`_...and ${t1.length-5} more critical signals (see dashboard)._` }]
      }] : []),
    ] : []),
    ...(t2.length ? [
      { type:'divider' },
      { type:'section', text:{ type:'mrkdwn', text:`⚠️ *REVIEW SIGNALS (${t2.length})*` } },
      ...t2.slice(0,10).map((s,i) => buildDigestEntry(s,i+1)),
      ...(t2.length > 10 ? [{
        type:'context',
        elements:[{ type:'mrkdwn', text:`_...and ${t2.length-10} more review signals._` }]
      }] : []),
    ] : []),
    ...(t3.length ? [
      { type:'divider' },
      { type:'section', text:{ type:'mrkdwn', text:`📋 *MONITOR SIGNALS (${t3.length})*` } },
      ...t3.slice(0,15).map((s,i) => buildDigestEntry(s,i+1)),
      ...(t3.length > 15 ? [{
        type:'context',
        elements:[{ type:'mrkdwn', text:`_...and ${t3.length-15} more monitor signals._` }]
      }] : []),
    ] : []),
    { type:'divider' },
    {
      type:'context',
      elements:[{
        type:'mrkdwn',
        text:`📡 PharmaOS Pipeline v${PIPELINE_VERSION}  ·  Run ID: ${runId || 'N/A'}  ·  Generated: ${nowStr}`
      }]
    }
  ];

  return {
    text: `📊 PharmaOS Signal Digest: ${sorted.length} signals — ${t1.length} T1, ${t2.length} T2, ${t3.length} T3`,
    blocks,
  };
}

// ─────────────────────────────────────────────────────────────
// SECTION 5: MAIN ROUTER LOGIC
// ─────────────────────────────────────────────────────────────

const output      = [];
const allSignals  = [];
const digestBatch = [];

// Run context (for run_id, noise throttling, etc.)
let runId = '';
let maxRealtimePerRun = { T1_CRITICAL: 20, T2_REVIEW: 50 };
try {
  const runCtx = $('🔧 Init Run Context').first().json;
  runId = runCtx.run_id || runCtx.runId || '';
  if (runCtx.max_realtime) {
    maxRealtimePerRun = {
      T1_CRITICAL: runCtx.max_realtime.T1 || maxRealtimePerRun.T1_CRITICAL,
      T2_REVIEW:   runCtx.max_realtime.T2 || maxRealtimePerRun.T2_REVIEW,
    };
  }
} catch { /* optional */ }

// Normalize all signals
for (const item of $input.all()) {
  const raw = item.json || {};
  if (raw._error) {
    output.push({ json: { ...raw, _routed:false, _skip_alert:true } });
    continue;
  }
  try {
    const s = normalizeSignal(raw);
    allSignals.push(s);
  } catch (e) {
    output.push({
      json: {
        _error:         true,
        _error_message: `Router normalize failed: ${e.message}`,
        _raw_source_id: raw.source_id || 'unknown',
        signal_domain:  raw.signal_domain || 'ci',
        source:         raw.source || 'unknown',
      }
    });
  }
}

// Sort by tier priority & impact_score
allSignals.sort((a,b) => {
  const order = { T1_CRITICAL:0, T2_REVIEW:1, T3_MONITOR:2 };
  const tDiff = (order[a.route_tier] || 2) - (order[b.route_tier] || 2);
  if (tDiff !== 0) return tDiff;
  return b.impact_score - a.impact_score;
});

// Noise throttling: cap T1/T2 real-time alerts per run
let t1Count = 0;
let t2Count = 0;

for (const s of allSignals) {
  const cfg = TIER_CONFIG[s.route_tier];
  let send_realtime = cfg.send_realtime;
  let send_digest   = cfg.send_digest;

  // Apply override-based suppression
  if (s.has_override && s.override_status === 'DISMISS') {
    send_realtime = false;
    send_digest   = false;
  }

  // Apply noise caps
  if (s.route_tier === 'T1_CRITICAL') {
    t1Count++;
    if (t1Count > maxRealtimePerRun.T1_CRITICAL) send_realtime = false;
  } else if (s.route_tier === 'T2_REVIEW') {
    t2Count++;
    if (t2Count > maxRealtimePerRun.T2_REVIEW) send_realtime = false;
  }

  // Build Slack alert only if needed
  const slackAlert = send_realtime ? buildRealtimeAlert(s) : null;

  // Accumulate digest candidates (T2 & T3) if enabled
  if (send_digest) digestBatch.push(s);

  output.push({
    json: {
      ...s,
      _routed:        true,
      _send_realtime: send_realtime,
      _send_digest:   send_digest,
      slack_alert:    slackAlert,
      slack_channels: s.alert_channels,
      slack_text:     slackAlert?.text || '',
      slack_blocks:   slackAlert ? JSON.stringify(slackAlert.blocks) : null,
    }
  });
}

// Emit one digest item if any digest-eligible signals
if (digestBatch.length > 0) {
  const digest = buildBatchDigest(digestBatch, runId);
  output.push({
    json: {
      _is_digest:       true,
      _routed:          true,
      _send_realtime:   false,
      _send_digest:     true,
      digest_signal_count: digestBatch.length,
      slack_text:       digest.text,
      slack_blocks:     JSON.stringify(digest.blocks),
      slack_channels:   ['pharmaos-digest'],
      run_id:           runId,
      generated_at:     new Date().toISOString(),
    }
  });
}

return output;

// 🧠 PharmaOS Report Builder v2.0 — G.O.A.T Edition
// Input: many items = normalized signals from Router
// Output: 1 item with { html_report }

const PIPELINE_VERSION = '2.0.0';

const items   = $input.all().map(i => i.json);
const signals = items.filter(s => !s._is_digest && !s._error);
const runId   = items[0]?.run_id || 'N/A';
const runSource = items[0]?.source || 'multi-source';

// Helpers
const esc = (s) => String(s || '').replace(/[&<>]/g, c =>
  c === '&' ? '&amp;' : c === '<' ? '&lt;' : '&gt;'
);

// Basic aggregates
const total = signals.length;
const byTier    = { T1_CRITICAL:0, T2_REVIEW:0, T3_MONITOR:0 };
const byDomain  = {};
const bySource  = {};
const byImpact  = { HIGH:0, MED:0, LOW:0 };
const competitorSignals = [];
const urgentSignals     = [];

for (const s of signals) {
  byTier[s.route_tier] = (byTier[s.route_tier] || 0) + 1;
  const d = (s.signal_domain || 'ci').toLowerCase();
  byDomain[d] = (byDomain[d] || 0) + 1;
  const src = s.source || 'unknown';
  bySource[src] = (bySource[src] || 0) + 1;
  const lvl = s.impact_level || 'LOW';
  byImpact[lvl] = (byImpact[lvl] || 0) + 1;
  if (s.competitor_flag) competitorSignals.push(s);
  if (s.is_urgent)       urgentSignals.push(s);
}

// Per-asset aggregation
const assetMap = {};
for (const s of signals) {
  const key = s.asset_id || s.drug_name || '(Unknown)';
  if (!assetMap[key]) {
    assetMap[key] = {
      asset_id: s.asset_id || null,
      name: key,
      total: 0,
      high: 0,
      med:  0,
      low:  0,
      domains: {},
      maxScore: 0,
      competitor: false,
      urgent: false,
      latestSeen: s.last_seen_at || s.ingested_at,
      signals: [],
    };
  }
  const a = assetMap[key];
  a.total += 1;
  if (s.impact_level === 'HIGH') a.high += 1;
  else if (s.impact_level === 'MED') a.med += 1;
  else a.low += 1;
  const d = (s.signal_domain || 'ci').toLowerCase();
  a.domains[d] = (a.domains[d] || 0) + 1;
  const sc = Number(s.impact_score || 0);
  if (sc > a.maxScore) a.maxScore = sc;
  if (s.competitor_flag) a.competitor = true;
  if (s.is_urgent)       a.urgent     = true;
  if (!a.latestSeen || (s.last_seen_at && s.last_seen_at > a.latestSeen)) {
    a.latestSeen = s.last_seen_at;
  }
  a.signals.push(s);
}

const assets = Object.values(assetMap);

// Top 10 assets by risk (maxScore, then high count)
const topAssets = [...assets].sort((a,b) => {
  if (b.maxScore !== a.maxScore) return b.maxScore - a.maxScore;
  if (b.high     !== a.high)     return b.high - a.high;
  return b.total - a.total;
}).slice(0, 10);

// Top 15 signals
const topSignals = [...signals].sort((a,b) => b.impact_score - a.impact_score).slice(0, 15);

// Domain labels
const domainLabels = Object.keys(byDomain);
const domainCounts = domainLabels.map(d => byDomain[d]);

// Source labels
const sourceLabels = Object.keys(bySource);
const sourceCounts = sourceLabels.map(s => bySource[s]);

// Impact distribution
const impactLabels = ['HIGH','MED','LOW'];
const impactCounts = impactLabels.map(l => byImpact[l] || 0);

// Simple qualitative executive summary (rule-based)
function buildExecSummary() {
  if (!total) return 'No signals ingested in this run.';
  const highPct  = total ? ((byImpact.HIGH || 0) / total * 100).toFixed(1) : '0.0';
  const compPct  = total ? ((competitorSignals.length / total) * 100).toFixed(1) : '0.0';
  const urgPct   = total ? ((urgentSignals.length / total) * 100).toFixed(1) : '0.0';
  const leadAsset = topAssets[0];

  let lines = [];

  lines.push(`This run ingested ${total} signals across ${domainLabels.length || 1} domains and ${sourceLabels.length || 1} data sources.`);
  if (byImpact.HIGH > 0) {
    lines.push(`${byImpact.HIGH} (${highPct}%) were classified as HIGH impact, requiring close monitoring and potential escalation.`);
  } else {
    lines.push(`No HIGH impact signals were detected; the portfolio is currently dominated by MED and LOW impact events.`);
  }

  if (competitorSignals.length > 0) {
    lines.push(`${competitorSignals.length} competitor-related signals (${compPct}%) were identified, indicating active movement in the external landscape.`);
  } else {
    lines.push(`No explicit competitor signals were detected in this run.`);
  }

  if (urgentSignals.length > 0) {
    lines.push(`${urgentSignals.length} urgent safety/regulatory signals (${urgPct}%) were flagged for immediate attention.`);
  }

  if (leadAsset && leadAsset.maxScore >= 7) {
    lines.push(`The most exposed asset in this run is ${leadAsset.name}, with a peak impact score of ${leadAsset.maxScore.toFixed(1)} and ${leadAsset.high} HIGH impact signals.`);
  }

  return lines.join(' ');
}

const executiveSummary = buildExecSummary();

// Asset table rows
const assetRowsHtml = topAssets.map((a, idx) => {
  const domainTags = Object.entries(a.domains)
    .map(([d,c]) => `${esc(d)} (${c})`).join(', ');
  const flags = [];
  if (a.competitor) flags.push('Competitor');
  if (a.urgent)     flags.push('Urgent');
  const flagStr = flags.length ? flags.join(' · ') : '-';

  return `
    <tr>
      <td>${idx + 1}</td>
      <td>${esc(a.name)}</td>
      <td>${a.total}</td>
      <td><span class="pill pill-high">${a.high}</span></td>
      <td><span class="pill pill-med">${a.med}</span></td>
      <td><span class="pill pill-low">${a.low}</span></td>
      <td>${a.maxScore.toFixed(1)}</td>
      <td>${esc(domainTags)}</td>
      <td>${esc(flagStr)}</td>
    </tr>
  `;
}).join('\n');

// Top signal rows
const signalRowsHtml = topSignals.map((s, idx) => {
  return `
    <tr>
      <td>${idx + 1}</td>
      <td>${esc(s.drug_name)}</td>
      <td>${esc(s.indication || '')}</td>
      <td>${esc(s.signal_domain || '')}</td>
      <td>${esc(s.source || '')}</td>
      <td class="tier-${esc(s.route_tier || '')}">${esc(s.impact_level || '')}</td>
      <td>${(s.impact_score ?? 0).toFixed(1)}</td>
      <td>${esc(s.route_tier || '')}</td>
      <td>${esc(s.title || '').slice(0,140)}</td>
    </tr>
  `;
}).join('\n');

// Asset spotlight sections (first 3 assets)
const spotlightHtml = topAssets.slice(0, 3).map(a => {
  const sortedSignals = [...a.signals].sort((x,y) => (x.last_seen_at || '') > (y.last_seen_at || '') ? -1 : 1).slice(0,5);
  const listHtml = sortedSignals.map(s => `
      <li>
        <strong>${esc(s.source || '')}</strong> · ${esc(s.impact_level || '')} (${(s.impact_score ?? 0).toFixed(1)}) ·
        ${esc(s.signal_domain || '')} · ${esc(s.title || '').slice(0,120)}
      </li>
  `).join('\n');

  return `
    <div class="spotlight-card">
      <h3>${esc(a.name)}</h3>
      <p class="spotlight-meta">
        Total signals: <strong>${a.total}</strong> · HIGH: <strong>${a.high}</strong> · MED: <strong>${a.med}</strong> · LOW: <strong>${a.low}</strong><br/>
        Peak impact score: <strong>${a.maxScore.toFixed(1)}</strong> · Domains: ${esc(Object.keys(a.domains).join(', ') || 'N/A')}
      </p>
      <ul>
        ${listHtml || '<li>No detailed signals available.</li>'}
      </ul>
    </div>
  `;
}).join('\n');

const now = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8" />
<title>PharmaOS Portfolio Signal Report</title>
<style>
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; margin: 24px; color: #111827; }
