const PIPELINE_VERSION = '2.0.0';

// ---------- Helpers ----------
const esc = (s) => String(s || '').replace(/[&<>]/g, c =>
  c === '&' ? '&amp;' : c === '<' ? '&lt;' : '&gt;'
);
const num = (v, d = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};
const fmt1 = (v) => num(v, 0).toFixed(1);

// ---------- Load signals ----------
const rows = $input.all().map(i => i.json);
const signals = rows || [];
const total = signals.length;

// ---------- Week window ----------
let minDate = null;
let maxDate = null;
for (const s of signals) {
  const d = s.last_seen_at || s.ingested_at;
  if (!d) continue;
  const t = new Date(d).getTime();
  if (!Number.isFinite(t)) continue;
  if (minDate === null || t < minDate) minDate = t;
  if (maxDate === null || t > maxDate) maxDate = t;
}
const windowLabel = (minDate !== null && maxDate !== null)
  ? `${new Date(minDate).toLocaleDateString('en-IN')} – ${new Date(maxDate).toLocaleDateString('en-IN')}`
  : 'Last 7 Days';

const now = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });

// ---------- Global aggregates ----------
const byTier   = { T1_CRITICAL:0, T2_REVIEW:0, T3_MONITOR:0 };
const byImpact = { HIGH:0, MED:0, LOW:0 };
const byDomain = {};
const bySource = {};
const dailyCounts = {};
const competitorSignals = [];
const urgentSignals     = [];

for (const s of signals) {
  const tier = s.route_tier || 'T3_MONITOR';
  const lvl  = s.impact_level || 'LOW';
  const dom  = (s.signal_domain || 'ci').toLowerCase();
  const src  = s.source || 'unknown';

  byTier[tier] = (byTier[tier] || 0) + 1;
  byImpact[lvl] = (byImpact[lvl] || 0) + 1;
  byDomain[dom] = (byDomain[dom] || 0) + 1;
  bySource[src] = (bySource[src] || 0) + 1;

  if (s.competitor_flag) competitorSignals.push(s);
  if (s.is_urgent)       urgentSignals.push(s);

  const dayKey = (s.last_seen_at || s.ingested_at || '').slice(0,10);
  if (dayKey) {
    dailyCounts[dayKey] = (dailyCounts[dayKey] || 0) + 1;
  }
}

const domainLabels = Object.keys(byDomain);
const domainCounts = domainLabels.map(d => byDomain[d]);
const sourceLabels = Object.keys(bySource);
const sourceCounts = sourceLabels.map(s => bySource[s]);
const impactLabels = ['HIGH','MED','LOW'];
const impactCounts = impactLabels.map(l => byImpact[l] || 0);
const dayKeysSorted = Object.keys(dailyCounts).sort();
const dayCountsSorted = dayKeysSorted.map(d => dailyCounts[d]);

// ---------- Per-asset aggregation ----------
const assetMap = {};
for (const s of signals) {
  const key = s.asset_id || s.drug_name || '(Unknown)';
  if (!assetMap[key]) {
    assetMap[key] = {
      asset_id: s.asset_id || null,
      name: key,
      total: 0,
      high: 0,
      med:  0,
      low:  0,
      domains: {},
      maxScore: 0,
      avgScore: 0,
      competitor: false,
      urgent: false,
      lastSeen: s.last_seen_at || s.ingested_at,
      signals: [],
    };
  }
  const a = assetMap[key];

  a.total += 1;
  if (s.impact_level === 'HIGH') a.high += 1;
  else if (s.impact_level === 'MED') a.med += 1;
  else a.low += 1;

  const d = (s.signal_domain || 'ci').toLowerCase();
  a.domains[d] = (a.domains[d] || 0) + 1;

  const sc = num(s.impact_score, 0);
  if (sc > a.maxScore) a.maxScore = sc;
  a.avgScore += sc;

  if (s.competitor_flag) a.competitor = true;
  if (s.is_urgent)       a.urgent     = true;

  if (!a.lastSeen || (s.last_seen_at && s.last_seen_at > a.lastSeen)) {
    a.lastSeen = s.last_seen_at || a.lastSeen;
  }
  a.signals.push(s);
}

// finalize avgScore
for (const k of Object.keys(assetMap)) {
  const a = assetMap[k];
  if (a.total > 0) a.avgScore = a.avgScore / a.total;
}

const assets = Object.values(assetMap);

// ---------- Top assets & signals ----------
const topAssets = [...assets].sort((a,b) => {
  if (b.maxScore !== a.maxScore) return b.maxScore - a.maxScore;
  if (b.high     !== a.high)     return b.high - a.high;
  return b.total - a.total;
}).slice(0, 15);

const topSignals = [...signals].sort((a,b) => num(b.impact_score) - num(a.impact_score)).slice(0, 25);

// ---------- Risk themes (simple rules) ----------
function buildRiskThemes() {
  const themes = [];

  if (byDomain['safety'] && byDomain['safety'] > 0 && byImpact.HIGH > 0) {
    themes.push('Safety risk is elevated with HIGH impact signals in the safety domain, requiring closer pharmacovigilance review.');
  }
  if (byDomain['regulatory'] && byDomain['regulatory'] > 0 && byTier.T1_CRITICAL > 0) {
    themes.push('Regulatory activity includes critical events; label updates or enforcement actions may be impacting key assets.');
  }
  if (competitorSignals.length >= 5) {
    themes.push('Multiple competitor-related signals indicate an active external landscape, particularly around priority indications.');
  }
  if (domainLabels.includes('ci') && byTier.T2_REVIEW > 0) {
    themes.push('Clinical development and competitive intelligence signals at REVIEW tier warrant triage for trial design and positioning impacts.');
  }
  if (!themes.length && total > 0) {
    themes.push('Risk is broadly distributed across domains with no single dominant theme; maintain routine monitoring with focus on MED tier items.');
  }
  return themes;
}

const riskThemes = buildRiskThemes();

// ---------- Executive summary ----------
function buildExecSummary() {
  if (!total) return 'No signals were ingested in the last 7 days.';

  const highPct  = ((byImpact.HIGH || 0) / total * 100).toFixed(1);
  const compPct  = ((competitorSignals.length / total) * 100).toFixed(1);
  const urgPct   = ((urgentSignals.length / total) * 100).toFixed(1);
  const leadAsset = topAssets[0];

  const lines = [];
  lines.push(`Over the period ${windowLabel}, PharmaOS ingested ${total} signals across ${domainLabels.length || 1} domains and ${sourceLabels.length || 1} sources.`);
  if (byImpact.HIGH > 0) {
    lines.push(`${byImpact.HIGH} (${highPct}%) were rated HIGH impact, representing the top of the weekly risk stack.`);
  } else {
    lines.push('No HIGH impact signals were detected; risk was dominated by MED and LOW severity items.');
  }
  if (competitorSignals.length > 0) {
    lines.push(`${competitorSignals.length} competitor-related signals (${compPct}%) suggest notable external activity in the competitive set.`);
  }
  if (urgentSignals.length > 0) {
    lines.push(`${urgentSignals.length} urgent signals (${urgPct}%) require prioritized review from safety, regulatory, or CI teams.`);
  }
  if (leadAsset && leadAsset.maxScore >= 7) {
    lines.push(`The most exposed asset this week is ${leadAsset.name}, with a peak impact score of ${fmt1(leadAsset.maxScore)} and ${leadAsset.high} HIGH impact signals.`);
  }

  return lines.join(' ');
}

const executiveSummary = buildExecSummary();

