// 🧮 Build Health + Run Log Payloads v2.0
// Input: run summary from WF1 (status, totals, source_details)
// Output: items tagged for health metric vs run log upsert

const PIPELINE_VERSION = 2;

// ── Load run summary ──────────────────────────────────────────
const raw = $input.first().json;

// ── Load run context (for run_id, started_at, domain) ────────
let runCtx = {};
try { runCtx = $('🔧 Init Run Context').first().json; } catch { /* optional */ }

// ── Safe extractors ───────────────────────────────────────────
const safe = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  return String(v).trim() || fallback;
};
const safeInt = (v, fallback = 0) => {
  const n = parseInt(v, 10);
  return Number.isFinite(n) ? n : fallback;
};
const safeFloat = (v, fallback = 0) => {
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : fallback;
};

// ── Core fields ───────────────────────────────────────────────
const runId       = safe(raw.run_id || runCtx.run_id || runCtx.runId, `wf1_${Date.now()}`);
const domain      = safe(raw.domain || runCtx.domain, 'ci');
const status      = safe(raw.status, 'UNKNOWN');
const finishedAt  = safe(raw.finished_at, new Date().toISOString());
const startedAt   = safe(raw.started_at || runCtx.started_at, finishedAt);

// Totals
const totalFetched = safeInt(raw.total_fetched, 0);
const totalNew     = safeInt(raw.total_new, 0);
const totalUpdated = safeInt(raw.total_updated, 0);
const totalDeduped = safeInt(raw.total_deduped, 0);
const totalErrors  = safeInt(raw.total_errors, 0);

// ── Per-source breakdown ──────────────────────────────────────
// raw.source_details is an array of strings like "• biorxiv: 100 fetched, 0 new, 0 updated"
// Parse each entry into a structured object
const sourceDetails = [];
const sourceNames   = [];

const rawDetails = Array.isArray(raw.source_details) ? raw.source_details : [];
for (const line of rawDetails) {
  const cleaned = String(line || '').replace(/^[•\-\s]+/, '').trim();
  if (!cleaned) continue;

  // Parse: "biorxiv: 100 fetched, 0 new, 0 updated"
  const nameMatch    = cleaned.match(/^([^:]+):/);
  const fetchMatch   = cleaned.match(/(\d+)\s+fetched/);
  const newMatch     = cleaned.match(/(\d+)\s+new/);
  const updMatch     = cleaned.match(/(\d+)\s+updated/);
  const errMatch     = cleaned.match(/(\d+)\s+error/);
  const dedupMatch   = cleaned.match(/(\d+)\s+dedup/);
  const latencyMatch = cleaned.match(/latency[:\s]+(\d+(?:\.\d+)?)\s*ms/i);

  const srcName = nameMatch ? nameMatch[1].trim() : 'unknown';
  sourceNames.push(srcName);

  sourceDetails.push({
    source:   srcName,
    fetched:  fetchMatch   ? parseInt(fetchMatch[1],10)   : 0,
    new:      newMatch     ? parseInt(newMatch[1],10)     : 0,
    updated:  updMatch     ? parseInt(updMatch[1],10)     : 0,
    deduped:  dedupMatch   ? parseInt(dedupMatch[1],10)   : 0,
    errors:   errMatch     ? parseInt(errMatch[1],10)     : 0,
    latency_ms: latencyMatch ? parseFloat(latencyMatch[1]) : null,
  });
}

// If no source_details parsed, infer from run-level fields
if (sourceDetails.length === 0) {
  const fallbackSrc = safe(runCtx.source, 'unknown');
  sourceNames.push(fallbackSrc);
  sourceDetails.push({
    source:  fallbackSrc,
    fetched: totalFetched,
    new:     totalNew,
    updated: totalUpdated,
    deduped: totalDeduped,
    errors:  totalErrors,
    latency_ms: null,
  });
}

const primarySource = sourceNames[0] || 'unknown';

// ── Error details JSONB ───────────────────────────────────────
const errorDetails = totalErrors > 0
  ? {
      total_errors:  totalErrors,
      error_summary: safe(raw.error_summary || raw.summary_text, ''),
      sources:       sourceDetails.filter(s => s.errors > 0),
    }
  : {};

// ── API latency JSONB ─────────────────────────────────────────
const apiLatencyMs = {};
for (const s of sourceDetails) {
  if (s.latency_ms !== null) {
    apiLatencyMs[s.source] = s.latency_ms;
  }
}

// ── Health metric values ──────────────────────────────────────
const isSuccess = /SUCCESS|OK|✅/i.test(status);
const latencyValues = sourceDetails.map(s => s.latency_ms).filter(v => v !== null);
const avgLatency = latencyValues.length
  ? latencyValues.reduce((a,b) => a+b, 0) / latencyValues.length
  : 0;

// Derive error rate
const errorRate = totalFetched > 0
  ? safeFloat(((totalErrors / totalFetched) * 100).toFixed(2))
  : 0;

// ── Build 4 health metric rows ────────────────────────────────
// 1. signals ingested count
// 2. HIGH signals count (if present in raw)
// 3. error rate %
// 4. run status (1=success, 0=fail)

const highSignalsCount  = safeInt(raw.total_high, 0);
const aiUnprocessed     = safeInt(raw.total_ai_unprocessed, 0);

const healthMetrics = [
  {
    metric_name:  'signals_fetched_per_run',
    metric_value: totalFetched,
    metric_unit:  'count',
    tags: {
      run_id: runId,
      domain,
      source: primarySource,
      status: isSuccess ? 'SUCCESS' : 'FAILURE',
    },
  },
  {
    metric_name:  'signals_new_per_run',
    metric_value: totalNew,
    metric_unit:  'count',
    tags: { run_id: runId, domain, source: primarySource },
  },
  {
    metric_name:  'error_rate_pct',
    metric_value: errorRate,
    metric_unit:  'percent',
    tags: { run_id: runId, domain, source: primarySource },
  },
  {
    metric_name:  'run_success',
    metric_value: isSuccess ? 1 : 0,
    metric_unit:  'bool',
    tags: { run_id: runId, domain, source: primarySource, status },
  },
  ...(highSignalsCount > 0 ? [{
    metric_name:  'high_impact_signals',
    metric_value: highSignalsCount,
    metric_unit:  'count',
    tags: { run_id: runId, domain, source: primarySource },
  }] : []),
  ...(aiUnprocessed > 0 ? [{
    metric_name:  'ai_unprocessed_signals',
    metric_value: aiUnprocessed,
    metric_unit:  'count',
    tags: { run_id: runId, domain },
  }] : []),
  ...(avgLatency > 0 ? [{
    metric_name:  'avg_api_latency_ms',
    metric_value: avgLatency,
    metric_unit:  'ms',
    tags: { run_id: runId, domain, sources: sourceNames.join(',') },
  }] : []),
];

// ── Run log payload ───────────────────────────────────────────
const runLogPayload = {
  run_id:           runId,
  domain,
  source:           primarySource,
  signals_fetched:  totalFetched,
  signals_new:      totalNew,
  signals_updated:  totalUpdated,
  signals_deduped:  totalDeduped,
  errors:           totalErrors,
  error_details:    JSON.stringify(errorDetails),
  api_latency_ms:   JSON.stringify(Object.keys(apiLatencyMs).length ? apiLatencyMs : {}),
  pipeline_version: PIPELINE_VERSION,
  started_at:       startedAt,
  finished_at:      finishedAt,
};

// ── Emit one item per health metric + one item for run log ────
const output = [];

for (const m of healthMetrics) {
  output.push({
    json: {
      _target:        'health_metric',
      metric_name:    m.metric_name,
      metric_value:   m.metric_value,
      metric_unit:    m.metric_unit,
      tags:           JSON.stringify(m.tags),
      recorded_at:    finishedAt,
    }
  });
}

output.push({
  json: {
    _target:         'run_log',
    ...runLogPayload,
  }
});

return output;

const itemsIn = $input.all();

function pick(obj, keys, fb = null) {
  for (const k of keys) {
    if (obj?.[k] !== undefined && obj[k] !== null && obj[k] !== '') return obj[k];
  }
  return fb;
}

function safe(v, fb = '') {
  if (v === null || v === undefined) return fb;
  return String(v)
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
    .trim() || fb;
}

function safeLower(v, fb = '') {
  return safe(v, fb).toLowerCase();
}

function num(v, fb = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
}

function clamp(n, lo, hi) {
  return Math.max(lo, Math.min(hi, n));
}

function shortHash(str) {
  let h = 0;
  const s = String(str || '');
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h).toString(16).padStart(16, '0');
}

function stripHtml(s) {
  return safe(s)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ');
}

function decodeBasicEntities(s) {
  return safe(s)
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'");
}

function cleanText(s) {
  return decodeBasicEntities(stripHtml(s))
    .replace(/\r/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .split('\n')
    .map(x => x.trim())
    .filter(Boolean)
    .filter((line, idx, arr) => idx === arr.findIndex(v => v.toLowerCase() === line.toLowerCase()))
    .join('\n')
    .trim();
}

function normalizeInline(s) {
  return cleanText(s).replace(/\n+/g, ' ').replace(/\s+/g, ' ').trim();
}

function addLabeled(blocks, label, value) {
  const v = cleanText(value);
  if (v) blocks.push(`${label}: ${v}`);
}

function buildRawText(r) {
  const raw = pick(r, ['raw_text', 'rawtext'], null);
  const blocks = [];

  addLabeled(blocks, 'TITLE', pick(r, ['title'], null));
  addLabeled(blocks, 'SOURCE', pick(r, ['source'], null));
  addLabeled(blocks, 'URL', pick(r, ['url'], null));
  addLabeled(blocks, 'DOMAIN', pick(r, ['signal_domain', 'signaldomain'], null));
  addLabeled(blocks, 'TYPE', pick(r, ['signal_type', 'signaltype'], null));
  addLabeled(blocks, 'DRUG', pick(r, ['drug_name', 'drugname', 'entity_name', 'entityname'], null));
  addLabeled(blocks, 'INDICATION', pick(r, ['indication'], null));
  addLabeled(blocks, 'SPONSOR', pick(r, ['sponsor'], null));
  addLabeled(blocks, 'PHASE', pick(r, ['phase'], null));
  addLabeled(blocks, 'STATUS', pick(r, ['status'], null));
  addLabeled(blocks, 'MOA', pick(r, ['moa'], null));
  addLabeled(blocks, 'MODALITY', pick(r, ['modality'], null));
  addLabeled(blocks, 'GEOGRAPHY', pick(r, ['geography'], null));
  addLabeled(blocks, 'NCT_ID', pick(r, ['nct_id', 'nctid'], null));
  addLabeled(blocks, 'DOI', pick(r, ['doi'], null));

  if (typeof raw === 'string' && raw.trim()) {
    addLabeled(blocks, 'CONTENT', raw);
  } else if (raw && typeof raw === 'object') {
    const orderedKeys = [
      'abstract', 'summary', 'description', 'body', 'text',
      'notes', 'reasonforrecall', 'reasonForRecall',
      'productdescription', 'productDescription',
      'reactions', 'outcomes', 'title'
    ];
    for (const k of orderedKeys) {
      if (raw[k]) addLabeled(blocks, k.toUpperCase(), raw[k]);
    }
    if (!blocks.some(Boolean)) addLabeled(blocks, 'CONTENT_JSON', JSON.stringify(raw));
  }

  addLabeled(blocks, 'SUMMARY', pick(r, ['summary'], null));
  addLabeled(blocks, 'AI_SUMMARY', pick(r, ['ai_summary', 'aisummary'], null));

  const joined = blocks.join('\n\n').trim();
  const raw_text = joined ? joined.slice(0, 16000) : null;

  const chars = raw_text ? raw_text.length : 0;
  const lines = raw_text ? raw_text.split('\n').filter(Boolean).length : 0;
  const quality =
    chars >= 8000 ? 'RICH' :
    chars >= 3000 ? 'ADEQUATE' :
    chars >= 800 ? 'SPARSE' : 'MINIMAL';

  return {
    raw_text,
    raw_text_stats: {
      chars,
      lines,
      quality,
      structured: !!(raw && typeof raw === 'object')
    }
  };
}

function extractContext(signal, builtRawTextValue) {
  const parts = [];

  if (builtRawTextValue) parts.push(builtRawTextValue);
  if (signal.summary) parts.push(signal.summary);
  if (signal.ai_summary) parts.push(signal.ai_summary);
  if (signal.title) parts.push(`Title: ${signal.title}`);

  return normalizeInline(parts.join(' '));
}

function scoreLength(len) {
  if (len >= 2000) return 3.0;
  if (len >= 800) return 2.5;
  if (len >= 300) return 2.0;
  if (len >= 120) return 1.0;
  if (len >= 40) return 0.5;
  return 0;
}

function classifyMatch(assetId, drug, entity, indication) {
  if (safe(assetId)) return { method: 'exact_asset', score: 3.0 };
  if (safe(drug)) return { method: 'drug_or_alias', score: 2.0 };
  if (safe(entity)) return { method: 'entity_fallback', score: 1.2 };
  if (safe(indication)) return { method: 'indication_cluster', score: 0.6 };
  return { method: 'unmatched', score: 0.0 };
}

return itemsIn.map(item => {
  const s = item.json || {};

  const signal_domain = safeLower(pick(s, ['signal_domain', 'signaldomain'], 'ci'), 'ci');
  const signal_type = safeLower(pick(s, ['signal_type', 'signaltype'], 'other'), 'other');
  const source = safeLower(s.source, 'unknown');
  const source_id = safe(pick(s, ['source_id', 'sourceid', 'id'], ''), '');
  const title = normalizeInline(pick(s, ['title'], ''));
  const summary = normalizeInline(pick(s, ['summary'], ''));
  const drug_name = safe(pick(s, ['drug_name', 'drugname'], ''), '');
  const entity_name = safe(pick(s, ['entity_name', 'entityname'], ''), '');
  const indication = safe(pick(s, ['indication'], ''), '');
  const sponsor = safe(pick(s, ['sponsor'], ''), '');
  const phase = safe(pick(s, ['phase'], ''), '');
  const status = safe(pick(s, ['status'], ''), '');
  const url = safe(pick(s, ['url'], ''), '');
  const nct_id = safe(pick(s, ['nct_id', 'nctid'], ''), '');
  const asset_id = safe(pick(s, ['asset_id', 'assetid'], ''), '');

  const built = buildRawText({
    ...s,
    signal_domain,
    signal_type,
    drug_name,
    entity_name,
    nct_id
  });

  const context = extractContext(
    {
      title,
      summary,
      ai_summary: pick(s, ['ai_summary', 'aisummary'], null)
    },
    built.raw_text
  );

  const contextLen = context.length;
  const qualityFlags = [];
  let rawScore = 0;

  if (source_id) rawScore += 2.5; else qualityFlags.push('missing_source_id');
  if (source && source !== 'unknown') rawScore += 1.0; else qualityFlags.push('missing_source');
  if (title) rawScore += 1.5; else qualityFlags.push('missing_title');

  if (drug_name) rawScore += 2.0; else qualityFlags.push('missing_drug');
  if (indication) rawScore += 1.75; else qualityFlags.push('missing_indication');
  if (sponsor) rawScore += 1.0; else qualityFlags.push('missing_sponsor');
  if (phase) rawScore += 0.75; else qualityFlags.push('missing_phase');
  if (status) rawScore += 0.5;
  if (nct_id) rawScore += 0.75;
  if (url) rawScore += 1.0; else qualityFlags.push('missing_url');

  rawScore += scoreLength(contextLen);
  if (contextLen < 120) qualityFlags.push('sparse_context');

  const match = classifyMatch(asset_id, drug_name, entity_name, indication);
  rawScore += match.score;
  if (match.method === 'unmatched') qualityFlags.push('no_match_anchor');

  const fingerprint = shortHash([
    signal_domain,
    source,
    safeLower(asset_id || drug_name || entity_name || indication),
    signal_type
  ].join('|'));

  const dedup_hash = shortHash([
    source_id,
    safeLower(title),
    safeLower(drug_name),
    safeLower(indication),
    safeLower(sponsor)
  ].join('|'));

  let duplicateRisk = 'LOW';
  if (!title && !drug_name && !indication) duplicateRisk = 'HIGH';
  else if (!source_id || contextLen < 80) duplicateRisk = 'MEDIUM';

  const qualityScore = clamp(Math.round((rawScore / 16.75) * 10 * 100) / 100, 0, 10);

  let qualityTier = 'QUARANTINE';
  if (qualityScore >= 8.5) qualityTier = 'PLATINUM';
  else if (qualityScore >= 7.0) qualityTier = 'GOLD';
  else if (qualityScore >= 5.0) qualityTier = 'SILVER';
  else if (qualityScore >= 3.0) qualityTier = 'BRONZE';

  let qualityDecision = 'INGEST';
  if (!source_id || !title) qualityDecision = 'REJECT_STRUCTURAL';
  else if (qualityScore < 3.0) qualityDecision = 'QUARANTINE';
  else if (qualityScore < 5.0) qualityDecision = 'INGEST_LOW_CONFIDENCE';

  const contextquality =
    contextLen >= 800 ? 'RICH' :
    contextLen >= 300 ? 'ADEQUATE' :
    contextLen >= 120 ? 'SPARSE' : 'MINIMAL';

  const triagehints = {
    qualitytier: qualityTier,
    qualitydecision: qualityDecision,
    matchmethod: match.method,
    duplicaterisk: duplicateRisk,
    contextevidencechars: contextLen,
    structurallycomplete: !!(source_id && source && title),
    needsreview: qualityDecision !== 'INGEST'
  };

  const mergedSourceMeta = {
    ...(typeof s._source_meta === 'object' && s._source_meta ? s._source_meta : {}),
    raw_text_stats: built.raw_text_stats
  };

  return {
    json: {
      ...s,

      signal_domain,
      signal_type,
      source_id,
      source,

      title,
      summary,
      drug_name,
      entity_name,
      indication,
      sponsor,
      phase,
      status,
      url,
      nct_id,
      asset_id: asset_id || null,

      raw_text: built.raw_text,
      rawtext: built.raw_text,

      quality_score: qualityScore,
      qualityscore: qualityScore,

      qualityflags: qualityFlags,
      qualitytier: qualityTier,
      qualitydecision: qualityDecision,

      matchmethod: match.method,
      assetmatchmethod: match.method,

      fingerprint,
      dedup_hash,
      deduphash: dedup_hash,

      duplicaterisk: duplicateRisk,
      duplicate_risk: duplicateRisk,

      contextquality,
      context_quality: contextquality,

      aiprocessed: false,
      ai_processed: false,

      triagehints,
      triage_hints: triagehints,

      _source_meta: mergedSourceMeta
    }
  };
});

