  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h).toString(16).padStart(16, '0');
}

function stripHtml(s) {
  return safe(s)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ');
}

function decodeBasicEntities(s) {
  return safe(s)
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'");
}

function cleanText(s) {
  return decodeBasicEntities(stripHtml(s))
    .replace(/\r/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .split('\n')
    .map(x => x.trim())
    .filter(Boolean)
    .filter((line, idx, arr) => idx === arr.findIndex(v => v.toLowerCase() === line.toLowerCase()))
    .join('\n')
    .trim();
}

function normalizeInline(s) {
  return cleanText(s).replace(/\n+/g, ' ').replace(/\s+/g, ' ').trim();
}

function addLabeled(blocks, label, value) {
  const v = cleanText(value);
  if (v) blocks.push(`${label}: ${v}`);
}

function buildRawText(r) {
  const raw = pick(r, ['raw_text', 'rawtext'], null);
  const blocks = [];

  addLabeled(blocks, 'TITLE', pick(r, ['title'], null));
  addLabeled(blocks, 'SOURCE', pick(r, ['source'], null));
  addLabeled(blocks, 'URL', pick(r, ['url'], null));
  addLabeled(blocks, 'DOMAIN', pick(r, ['signal_domain', 'signaldomain'], null));
  addLabeled(blocks, 'TYPE', pick(r, ['signal_type', 'signaltype'], null));
  addLabeled(blocks, 'DRUG', pick(r, ['drug_name', 'drugname', 'entity_name', 'entityname'], null));
  addLabeled(blocks, 'INDICATION', pick(r, ['indication'], null));
  addLabeled(blocks, 'SPONSOR', pick(r, ['sponsor'], null));
  addLabeled(blocks, 'PHASE', pick(r, ['phase'], null));
  addLabeled(blocks, 'STATUS', pick(r, ['status'], null));
  addLabeled(blocks, 'MOA', pick(r, ['moa'], null));
  addLabeled(blocks, 'MODALITY', pick(r, ['modality'], null));
  addLabeled(blocks, 'GEOGRAPHY', pick(r, ['geography'], null));
  addLabeled(blocks, 'NCT_ID', pick(r, ['nct_id', 'nctid'], null));
  addLabeled(blocks, 'DOI', pick(r, ['doi'], null));

  if (typeof raw === 'string' && raw.trim()) {
    addLabeled(blocks, 'CONTENT', raw);
  } else if (raw && typeof raw === 'object') {
    const orderedKeys = [
      'abstract', 'summary', 'description', 'body', 'text',
      'notes', 'reasonforrecall', 'reasonForRecall',
      'productdescription', 'productDescription',
      'reactions', 'outcomes', 'title'
    ];
    for (const k of orderedKeys) {
      if (raw[k]) addLabeled(blocks, k.toUpperCase(), raw[k]);
    }
    if (!blocks.some(Boolean)) addLabeled(blocks, 'CONTENT_JSON', JSON.stringify(raw));
  }

  addLabeled(blocks, 'SUMMARY', pick(r, ['summary'], null));
  addLabeled(blocks, 'AI_SUMMARY', pick(r, ['ai_summary', 'aisummary'], null));

  const joined = blocks.join('\n\n').trim();
  const raw_text = joined ? joined.slice(0, 16000) : null;

  const chars = raw_text ? raw_text.length : 0;
  const lines = raw_text ? raw_text.split('\n').filter(Boolean).length : 0;
  const quality =
    chars >= 8000 ? 'RICH' :
    chars >= 3000 ? 'ADEQUATE' :
    chars >= 800 ? 'SPARSE' : 'MINIMAL';

  return {
    raw_text,
    raw_text_stats: {
      chars,
      lines,
      quality,
      structured: !!(raw && typeof raw === 'object')
    }
  };
}

function scoreLength(len) {
  if (len >= 2000) return 3.0;
  if (len >= 800) return 2.5;
  if (len >= 300) return 2.0;
  if (len >= 120) return 1.0;
  if (len >= 40) return 0.5;
  return 0;
}

function classifyMatch(assetId, drug, entity, indication) {
  if (safe(assetId)) return { method: 'exact_asset', score: 3.0 };
  if (safe(drug)) return { method: 'drug_or_alias', score: 2.0 };
  if (safe(entity)) return { method: 'entity_fallback', score: 1.2 };
  if (safe(indication)) return { method: 'indication_cluster', score: 0.6 };
  return { method: 'unmatched', score: 0.0 };
}

return itemsIn.map(item => {
  const s = item.json || {};

  const signal_domain_raw = safeLower(pick(s, ['signal_domain', 'signaldomain', 'domain'], 'ci'), 'ci');
  const signal_domain = VALID_DOMAINS.has(signal_domain_raw) ? signal_domain_raw : 'ci';

  const signal_type_raw = safeLower(pick(s, ['signal_type', 'signaltype'], 'other'), 'other');
  const signal_type = VALID_TYPES.has(signal_type_raw) ? signal_type_raw : 'other';

  const source = safeLower(pick(s, ['source'], 'unknown'), 'unknown');

  const title = normalizeInline(pick(s, ['title'], ''));
  const summary = normalizeInline(pick(s, ['summary'], ''));
  const entity_name = safe(pick(s, ['entity_name', 'entityname'], ''), '');
  const asset_id = safe(pick(s, ['asset_id', 'assetid'], ''), '');
  const geography = safe(pick(s, ['geography'], ''), '');
  const indication = safe(pick(s, ['indication'], ''), '');
  const drug_name = safe(pick(s, ['drug_name', 'drugname'], ''), '');
  const sponsor = safe(pick(s, ['sponsor'], ''), '');
  const phase = safe(pick(s, ['phase'], ''), '');
  const status = safe(pick(s, ['status'], ''), '');
  const moa = safe(pick(s, ['moa'], ''), '');
  const modality = safe(pick(s, ['modality'], ''), '');
  const nct_id = safe(pick(s, ['nct_id', 'nctid'], ''), '');
  const url = safe(pick(s, ['url'], ''), '');
  const app_number = safe(pick(s, ['app_number', 'appnumber'], ''), '');
  const doi = safe(pick(s, ['doi'], ''), '');

  const source_id =
    safe(pick(s, ['source_id', 'sourceid', 'sourceId'], ''), '') ||
    nct_id ||
    doi ||
    app_number ||
    `auto_${shortHash([
      source,
      url,
      title,
      drug_name || entity_name,
      indication,
      signal_domain,
      signal_type
    ].filter(Boolean).join('|'))}`;

  const built = buildRawText({
    ...s,
    signal_domain,
    signal_type,
    drug_name,
    entity_name,
    nct_id
  });

  const context = normalizeInline([
    built.raw_text || '',
    summary || '',
    safe(pick(s, ['ai_summary', 'aisummary'], ''), ''),
    title ? `Title: ${title}` : ''
  ].join(' '));

  const contextLen = context.length;
  const qualityFlags = [];
  let rawScore = 0;

  if (source_id) rawScore += 2.5; else qualityFlags.push('missing_source_id');
  if (source && source !== 'unknown') rawScore += 1.0; else qualityFlags.push('missing_source');
  if (title) rawScore += 1.5; else qualityFlags.push('missing_title');
  if (drug_name) rawScore += 2.0; else qualityFlags.push('missing_drug');
  if (indication) rawScore += 1.75; else qualityFlags.push('missing_indication');
  if (sponsor) rawScore += 1.0; else qualityFlags.push('missing_sponsor');
  if (phase) rawScore += 0.75; else qualityFlags.push('missing_phase');
  if (status) rawScore += 0.5;
  if (nct_id) rawScore += 0.75;
  if (url) rawScore += 1.0; else qualityFlags.push('missing_url');

  rawScore += scoreLength(contextLen);
  if (contextLen < 120) qualityFlags.push('sparse_context');

  const match = classifyMatch(asset_id, drug_name, entity_name, indication);
  rawScore += match.score;
  if (match.method === 'unmatched') qualityFlags.push('no_match_anchor');

  const fingerprint = shortHash([
    signal_domain,
    source,
    safeLower(asset_id || drug_name || entity_name || indication),
    signal_type
  ].join('|'));

  const dedup_hash = shortHash([
    source_id,
    safeLower(title),
    safeLower(drug_name),
    safeLower(indication),
    safeLower(sponsor)
  ].join('|'));

  let duplicaterisk = 'LOW';
  if (!title && !drug_name && !indication) duplicaterisk = 'HIGH';
  else if (!source_id || contextLen < 80) duplicaterisk = 'MEDIUM';

  const quality_score = clamp(Math.round((rawScore / 16.75) * 10 * 100) / 100, 0, 10);

  let qualitytier = 'QUARANTINE';
  if (quality_score >= 8.5) qualitytier = 'PLATINUM';
  else if (quality_score >= 7.0) qualitytier = 'GOLD';
  else if (quality_score >= 5.0) qualitytier = 'SILVER';
  else if (quality_score >= 3.0) qualitytier = 'BRONZE';

  let qualitydecision = 'INGEST';
  if (!source_id || !title) qualitydecision = 'REJECT_STRUCTURAL';
  else if (quality_score < 3.0) qualitydecision = 'QUARANTINE';
  else if (quality_score < 5.0) qualitydecision = 'INGEST_LOW_CONFIDENCE';

  const contextquality =
    contextLen >= 800 ? 'RICH' :
    contextLen >= 300 ? 'ADEQUATE' :
    contextLen >= 120 ? 'SPARSE' : 'MINIMAL';

  const triagehints = {
    qualitytier,
    qualitydecision,
    matchmethod: match.method,
    duplicaterisk,
    contextevidencechars: contextLen,
    structurallycomplete: !!(source_id && source && title),
    needsreview: qualitydecision !== 'INGEST'
  };

  const impact_level_raw = safeUpper(pick(s, ['impact_level', 'impactlevel'], ''), '');
  const impact_level = VALID_IMPACTS.has(impact_level_raw) ? impact_level_raw : null;

  const confidence_raw = safeLower(pick(s, ['confidence'], ''), '');
  const confidence = VALID_CONFIDENCE.has(confidence_raw) ? confidence_raw : null;

  const mergedSourceMeta = {
    ...(typeof s._source_meta === 'object' && s._source_meta ? s._source_meta : {}),
    raw_text_stats: built.raw_text_stats
  };

  const mergedTriageMeta = {
    ...(typeof s._triage_meta === 'object' && s._triage_meta ? s._triage_meta : {}),
    normalized_at: new Date().toISOString(),
    qualitytier,
    qualitydecision,
    contextquality,
    matchmethod: match.method,
    duplicaterisk
  };

  const alert_channels = Array.isArray(s.alert_channels)
    ? s.alert_channels
    : Array.isArray(s.alertchannels)
      ? s.alertchannels
      : [];

  return {
    json: {
      ...s,

      signal_domain,
      signaldomain: signal_domain,

      signal_type,
      signaltype: signal_type,

      source_id,
      sourceid: source_id,

      source,
      title,
      summary,

      entity_name,
      entityname: entity_name,

      asset_id: asset_id || null,
      assetid: asset_id || null,

      geography,
      indication,

      drug_name,
      drugname: drug_name,

      sponsor,
      phase,
      status,
      moa,
      modality,

      nct_id: nct_id || null,
      nctid: nct_id || null,

      url,

      raw_text: built.raw_text,
      rawtext: built.raw_text,

      impact_level,
      impactlevel: impact_level,

      impact_score: num(pick(s, ['impact_score', 'impactscore'], null), null),
      impactscore: num(pick(s, ['impact_score', 'impactscore'], null), null),

      priority_score: num(pick(s, ['priority_score', 'priorityscore'], null), null),
      priorityscore: num(pick(s, ['priority_score', 'priorityscore'], null), null),

      route_tier: pick(s, ['route_tier', 'routetier'], null),
      notif_priority: pick(s, ['notif_priority', 'notifpriority'], null),
      alert_channels,

      ai_processed: bool(pick(s, ['ai_processed', 'aiprocessed'], false), false),
      aiprocessed: bool(pick(s, ['ai_processed', 'aiprocessed'], false), false),

      ai_summary: pick(s, ['ai_summary', 'aisummary'], null),
      aisummary: pick(s, ['ai_summary', 'aisummary'], null),

      ai_classification: pick(s, ['ai_classification', 'aiclassification'], null),
      aiclassification: pick(s, ['ai_classification', 'aiclassification'], null),

      recommended_action: pick(s, ['recommended_action', 'recommendedaction'], null),
      recommendedaction: pick(s, ['recommended_action', 'recommendedaction'], null),

      competitor_flag: bool(pick(s, ['competitor_flag', 'competitorflag'], false), false),
      competitorflag: bool(pick(s, ['competitor_flag', 'competitorflag'], false), false),

      is_urgent: bool(pick(s, ['is_urgent', 'isurgent'], false), false),
      isurgent: bool(pick(s, ['is_urgent', 'isurgent'], false), false),

      confidence,

      override_status: pick(s, ['override_status', 'overridestatus'], null),
      override_by: pick(s, ['override_by', 'overrideby'], null),
      override_reason: pick(s, ['override_reason', 'overridereason'], null),

      score_breakdown: pick(s, ['score_breakdown', 'scorebreakdown'], null),
      scorebreakdown: pick(s, ['score_breakdown', 'scorebreakdown'], null),

      scoring_version: num(pick(s, ['scoring_version', 'scoringversion'], 0), 0),
      scoringversion: num(pick(s, ['scoring_version', 'scoringversion'], 0), 0),

      version: num(pick(s, ['version'], 1), 1),

      quality_score,
      qualityscore: quality_score,

      qualityflags: qualityFlags,
      qualitytier,
      qualitydecision,

      matchmethod: match.method,
      assetmatchmethod: match.method,


      fingerprint,

      dedup_hash,
      deduphash: dedup_hash,

      duplicaterisk,
      duplicate_risk: duplicaterisk,

      contextquality,
      context_quality: contextquality,

      triagehints,
      triage_hints: triagehints,

      _source_meta: mergedSourceMeta,
      _triage_meta: mergedTriageMeta,

      first_seen_at: iso(pick(s, ['first_seen_at', 'firstseenat'], null), null),
      last_seen_at: iso(pick(s, ['last_seen_at', 'lastseenat'], null), null),
      ingested_at: iso(pick(s, ['ingested_at', 'ingestedat'], null), null),

      strategymemoryused: bool(pick(s, ['strategymemoryused', 'strategy_memory_used'], false), false),
      temperatureused: num(pick(s, ['temperatureused', 'temperature_used'], null), null),
      modelused: pick(s, ['modelused', 'model_used'], null),
      modelroutingreason: pick(s, ['modelroutingreason', 'model_routing_reason'], null),
      prompttokens: num(pick(s, ['prompttokens', 'prompt_tokens'], null), null),
      completiontokens: num(pick(s, ['completiontokens', 'completion_tokens'], null), null),
      totaltokens: num(pick(s, ['totaltokens', 'total_tokens'], null), null),
      mergeat: iso(pick(s, ['mergeat', 'merged_at', 'mergedat'], null), new Date().toISOString()),

      pipeline_version: pick(s, ['pipeline_version', 'pipelineversion'], null),
      app_number: app_number || null
    }
  };
});

"use strict";

const PIPELINE_VERSION = "6.1.0";

const VALID_DOMAINS = new Set(["ci", "regulatory", "safety", "bd"]);
const VALID_IMPACTS = new Set(["HIGH", "MED", "LOW"]);
const VALID_TYPES = new Set([
  "trialupdate",
  "regulatory",
  "publication",
  "conference",
  "safety",
  "safetysignal",
  "recall",
  "labelupdate",
  "materialevent",
  "news",
  "other"
]);
const VALID_ACTIONS = new Set(["ESCALATE", "MONITOR", "DISMISS", "REVIEW", "EXPEDITE"]);

function isObj(v) {
  return v && typeof v === "object" && !Array.isArray(v);
}

function deepClone(v) {
  return v == null ? v : JSON.parse(JSON.stringify(v));
}

function cleanStr(v, fb = null) {
  if (v === null || v === undefined) return fb;
  const s = String(v).replace(/[\u0000-\u001F\u007F-\u009F]/g, "").trim();
  return s === "" ? fb : s;
}

function lower(v, fb = null) {
  const s = cleanStr(v, fb);
  return s == null ? fb : s.toLowerCase();
}

function upper(v, fb = null) {
  const s = cleanStr(v, fb);
  return s == null ? fb : s.toUpperCase();
}

function toBool(v, fb = null) {
  if (v === true || v === false) return v;
  const s = lower(v, null);
  if (s == null) return fb;
  if (["true", "1", "t", "yes", "y"].includes(s)) return true;
  if (["false", "0", "f", "no", "n"].includes(s)) return false;
  return fb;
}

function toNum(v, fb = null) {
  if (v === null || v === undefined || v === "") return fb;
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
}

function toInt(v, fb = null) {
  const n = toNum(v, fb);
  return Number.isFinite(n) ? Math.trunc(n) : fb;
}

function clamp(n, lo, hi) {
  return Math.max(lo, Math.min(n, hi));
}

function round2(n) {
  return Math.round(n * 100) / 100;
}

function toJsonObject(v, fb = {}) {
  if (isObj(v)) return deepClone(v);
  if (typeof v === "string") {
    try {
      const parsed = JSON.parse(v);
      return isObj(parsed) ? parsed : fb;
    } catch {
      return fb;
    }
  }
  return fb;
}

function pick(obj, keys, consumed, fb = null) {
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null && obj[k] !== "") {
      consumed.add(k);
      return obj[k];
    }
  }
  return fb;
}

function mergeObjects(...objs) {
  const out = {};
  for (const obj of objs) {
    if (!isObj(obj)) continue;
    for (const [k, v] of Object.entries(obj)) {
      if (v !== undefined) out[k] = v;
    }
  }
  return out;
}

function uniqueArray(arr) {
  return [...new Set((arr || []).filter(v => v !== null && v !== undefined && v !== ""))];
}

function simpleHash(str) {
  const s = String(str || "");
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = (h << 5) - h + s.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h).toString(16).padStart(8, "0");
}

function deriveContextQuality(chars, structurallyComplete) {
  const c = toInt(chars, 0);
  if (structurallyComplete && c >= 2500) return "PLATINUM";
  if (structurallyComplete && c >= 1500) return "RICH";
  if (c >= 700) return "ADEQUATE";
  if (c >= 250) return "SPARSE";
  if (c > 0) return "MINIMAL";
  return null;
}

function deriveConfidence(chars, structurallyComplete, explicitConfidence) {
  const e = lower(explicitConfidence, null);
  if (["high", "medium", "low"].includes(e)) return e;
  const c = toInt(chars, 0);
  if (structurallyComplete && c >= 1000) return "high";
  if (c >= 300) return "medium";
  if (c > 0) return "low";
  return "low";
}

function deriveQualityScore(scoreBreakdown, chars, structurallyComplete, explicitScore) {
  const explicit = toInt(explicitScore, null);
  if (explicit !== null) return clamp(explicit, 0, 10);

  const q = toNum(scoreBreakdown?.quality, null);
  if (q !== null) return clamp(Math.round(q), 0, 10);

  const c = toInt(chars, 0);
  if (structurallyComplete && c >= 1500) return 9;
  if (structurallyComplete && c >= 800) return 8;
  if (c >= 300) return 6;
  if (c > 0) return 4;
  return 0;
}

function deriveQualityDecision(explicitDecision, needsReview, structurallyComplete) {
  const d = upper(explicitDecision, null);
  if (d) return d;
  if (needsReview) return "REVIEW";
  if (structurallyComplete) return "INGEST";
  return "HOLD";
}

function deriveSafetySeverity(domain, impactLevel, scoreBreakdown, explicitSeverity) {
  const e = upper(explicitSeverity, null);
  if (e) return e;
  if (domain !== "safety") return null;
  const death = toNum(scoreBreakdown?.death, 0);
  if (death >= 1) return "CRITICAL";
  if (impactLevel === "HIGH") return "SERIOUS";
  if (impactLevel === "MED") return "MODERATE";
  if (impactLevel === "LOW") return "MINOR";
  return "UNKNOWN";
}

function derivePatientImpact(domain, impactScore, scoreBreakdown, explicitImpact) {
  const e = upper(explicitImpact, null);
  if (e) return e;
  if (domain !== "safety") return null;
  const death = toNum(scoreBreakdown?.death, 0);
  if (death >= 1) return "SIGNIFICANT";
  if ((impactScore ?? 0) >= 8) return "SIGNIFICANT";
  if ((impactScore ?? 0) >= 5) return "LIMITED";
  return "MINIMAL";
}

function buildQualityFlags(data) {
  const flags = [];
  if (!data.source_id) flags.push("missing_source_id");
  if (!data.signal_domain) flags.push("missing_signal_domain");
  if (!data.structurally_complete) flags.push("structurally_incomplete");
  if (data.needs_review) flags.push("needs_review");
  if ((data.context_evidence_chars ?? 0) > 0 && (data.context_evidence_chars ?? 0) < 250) flags.push("low_context_evidence");
  if (!data.asset_id) flags.push("no_asset_match");
  if (!data.recommended_action) flags.push("no_recommended_action");
  return uniqueArray(flags);
}

function collectPassthrough(original, consumed) {
  const extras = {};
  for (const [k, v] of Object.entries(original || {})) {
    if (!consumed.has(k)) extras[k] = v;
  }
  return extras;
}

function normalizeOne(input) {
  if (!isObj(input)) {
    throw new Error("Rectification item must be an object.");
  }

  const original = deepClone(input);
  const consumed = new Set();

  const id = pick(original, ["id"], consumed, null);

  const source_id = cleanStr(pick(original, ["source_id", "sourceid"], consumed, null));
  const signal_domain_raw = lower(pick(original, ["signal_domain", "signaldomain"], consumed, "ci"), "ci");
  const signal_domain = VALID_DOMAINS.has(signal_domain_raw) ? signal_domain_raw : "ci";

  const signal_type_raw = lower(pick(original, ["signal_type", "signaltype"], consumed, "other"), "other");
  const signal_type = VALID_TYPES.has(signal_type_raw) ? signal_type_raw : "other";

  const source = cleanStr(pick(original, ["source"], consumed, null));
  const title = cleanStr(pick(original, ["title"], consumed, null));
  const summary = cleanStr(pick(original, ["summary"], consumed, null));
  const raw_text = pick(original, ["raw_text", "rawtext"], consumed, null);

  const entity_name = cleanStr(pick(original, ["entity_name", "entityname"], consumed, null));
  const asset_id = cleanStr(pick(original, ["asset_id", "assetid"], consumed, null));
  const geography = cleanStr(pick(original, ["geography"], consumed, null));
  const indication = cleanStr(pick(original, ["indication"], consumed, null));
  const drug_name = cleanStr(pick(original, ["drug_name", "drugname"], consumed, null)) || entity_name;
  const sponsor = cleanStr(pick(original, ["sponsor"], consumed, null));
  const phase = cleanStr(pick(original, ["phase"], consumed, null));
  const status = cleanStr(pick(original, ["status"], consumed, null));
  const moa = cleanStr(pick(original, ["moa"], consumed, null));
  const modality = cleanStr(pick(original, ["modality"], consumed, null));
  const nct_id = cleanStr(pick(original, ["nct_id", "nctid"], consumed, null));
  const url = cleanStr(pick(original, ["url"], consumed, null));

  const impact_level_raw = upper(pick(original, ["impact_level", "impactlevel"], consumed, "LOW"), "LOW");
  const impact_level = VALID_IMPACTS.has(impact_level_raw) ? impact_level_raw : "LOW";
  const impact_score = round2(clamp(toNum(pick(original, ["impact_score", "impactscore"], consumed, 0), 0), 0, 10));
  const priority_score = round2(clamp(toNum(pick(original, ["priority_score", "priorityscore"], consumed, 0), 0), 0, 10));

  const route_tier = cleanStr(pick(original, ["route_tier", "routetier"], consumed, null));
  const notif_priority = cleanStr(pick(original, ["notif_priority", "notifpriority"], consumed, null));
  const alert_channels = Array.isArray(pick(original, ["alert_channels", "alertchannels"], consumed, null))
    ? pick(original, ["alert_channels", "alertchannels"], consumed, null)
    : [];

  const ai_processed = toBool(pick(original, ["ai_processed", "aiprocessed"], consumed, null), null);
