const items = $input.all();

// ─────────────────────────────────────────────────────────────────────────────
// CONSTANTS & LOOKUP TABLES
// ─────────────────────────────────────────────────────────────────────────────

const SEVERITY_RANK   = { CRITICAL: 4, HIGH: 3, MODERATE: 2, LOW: 1, UNKNOWN: 0 };
const IMPACT_RANK     = { WIDESPREAD: 4, SIGNIFICANT: 3, LIMITED: 2, MINIMAL: 1, UNKNOWN: 0 };
const PRIORITY_RANK   = { P1: 4, P2: 3, P3: 2, P4: 1 };
const TIER_RANK       = { T1_URGENT: 4, T2_REVIEW: 3, T3_MONITOR: 2, T4_LOG: 1 };
const IMPACT_EMOJI    = { HIGH: '🔴', MED: '🟠', LOW: '🟡', MINIMAL: '🟢' };
const DOMAIN_EMOJI    = { safety: '🛡️', regulatory: '⚖️', clinical: '🧬', competitive: '🎯', market: '📊', pipeline: '🔬' };
const SIGNAL_EMOJI    = { recall: '⚠️', approval: '✅', trial: '🔬', label: '📋', warning: '🚨', enforcement: '🔒', submission: '📤' };

// ─────────────────────────────────────────────────────────────────────────────
// UTILITY FUNCTIONS
// ─────────────────────────────────────────────────────────────────────────────

const safe = (val, fallback = 'N/A') =>
  val === null || val === undefined || val === '' ? fallback : val;

const safeNum = (val, fallback = 0) =>
  isNaN(Number(val)) ? fallback : Number(val);

const formatDate = (iso) => {
  if (!iso) return 'Unknown';
  const d = new Date(iso);
  return isNaN(d) ? iso : d.toLocaleDateString('en-US', {
    year: 'numeric', month: 'short', day: '2-digit',
    hour: '2-digit', minute: '2-digit', timeZoneName: 'short'
  });
};

const formatDateShort = (iso) => {
  if (!iso) return '—';
  const d = new Date(iso);
  return isNaN(d) ? iso : d.toLocaleDateString('en-US', {
    year: 'numeric', month: 'short', day: '2-digit'
  });
};

const daysAgo = (iso) => {
  if (!iso) return null;
  const diff = Date.now() - new Date(iso).getTime();
  return Math.floor(diff / 86400000);
};

const truncate = (str, len = 200) => {
  if (!str) return '';
  return str.length > len ? str.substring(0, len).trim() + '…' : str;
};

const scoreBar = (score, max = 10, width = 10) => {
  const filled = Math.min(width, Math.max(0, Math.round((score / max) * width)));
  return '█'.repeat(filled) + '░'.repeat(width - filled);
};

const parseJSON = (val) => {
  if (typeof val === 'object' && val !== null) return val;
  try { return JSON.parse(val); } catch { return {}; }
};

const parseArray = (val) => {
  if (Array.isArray(val)) return val;
  try { const p = JSON.parse(val); return Array.isArray(p) ? p : []; } catch { return []; }
};

const urgencyLabel = (signal) => {
  if (signal.is_urgent)                        return '🚨 URGENT';
  if (signal.notif_priority === 'P1')          return '🔴 P1 CRITICAL';
  if (signal.notif_priority === 'P2')          return '🟠 P2 HIGH';
  if (signal.route_tier     === 'T1_URGENT')   return '⚡ ESCALATE NOW';
  return null;
};

const computeCompositeScore = (s) => {
  const sev   = SEVERITY_RANK[safe(s.safety_severity, 'UNKNOWN').toUpperCase()]   || 0;
  const imp   = IMPACT_RANK[safe(s.patient_impact_estimate,'UNKNOWN').toUpperCase()] || 0;
  const pri   = PRIORITY_RANK[safe(s.notif_priority,'P4')]                        || 0;
  const tier  = TIER_RANK[safe(s.route_tier,'T4_LOG')]                            || 0;
  const raw   = safeNum(s.impact_score);
  const qual  = safeNum(s.quality_score);
  return Math.round(((sev * 2) + (imp * 2) + (pri * 1.5) + (tier * 1) + raw + (qual * 0.5)) * 10) / 10;
};

// ─────────────────────────────────────────────────────────────────────────────
// SIGNAL ENRICHMENT — attach computed fields to each raw signal
// ─────────────────────────────────────────────────────────────────────────────

const enrichSignal = (raw) => {
  const s             = { ...raw };
  s._triage_meta      = parseJSON(s._triage_meta);
  s.triagehints       = parseJSON(s.triagehints);
  s.ai_classification = parseJSON(s.ai_classification);
  s.score_breakdown   = parseJSON(s.score_breakdown);
  s.qualityflags      = parseArray(s.qualityflags);
  s.alert_channels    = parseArray(s.alert_channels);

  s._compositeScore   = computeCompositeScore(s);
  s._daysAgo          = daysAgo(s.first_seen_at);
  s._urgencyLabel     = urgencyLabel(s);
  s._domainEmoji      = DOMAIN_EMOJI[s.signal_domain]  || '📌';
  s._signalEmoji      = SIGNAL_EMOJI[s.signal_type]    || '📎';
  s._impactEmoji      = IMPACT_EMOJI[s.impact_level]   || '⚪';
  s._qualityTier      = s._triage_meta?.qualitytier    || s.triagehints?.qualitytier || 'UNKNOWN';
  s._aiSeverity       = s.ai_classification?.safetyseverity    || s.safety_severity || 'UNKNOWN';
  s._aiPatientImpact  = s.ai_classification?.patientimpact     || s.patient_impact_estimate || 'UNKNOWN';
  s._rectification    = s._triage_meta?.rectification          || {};
  s._normalizedAt     = s._triage_meta?.normalized_at          || s._rectification?.normalizedat || null;
  s._pipelineVersion  = s._rectification?.pipelineversion      || s.pipelineversion || 'unknown';

  return s;
};

// ─────────────────────────────────────────────────────────────────────────────
// ANALYTICS ENGINE
// ─────────────────────────────────────────────────────────────────────────────

const buildAnalytics = (signals) => {
  const total = signals.length;

  // Domain distribution
  const byDomain = signals.reduce((acc, s) => {
    acc[s.signal_domain] = (acc[s.signal_domain] || 0) + 1;
    return acc;
  }, {});

  // Signal type distribution
  const byType = signals.reduce((acc, s) => {
    acc[s.signal_type] = (acc[s.signal_type] || 0) + 1;
    return acc;
  }, {});

  // Source distribution
  const bySource = signals.reduce((acc, s) => {
    acc[s.source] = (acc[s.source] || 0) + 1;
    return acc;
  }, {});

  // Geography distribution
  const byGeo = signals.reduce((acc, s) => {
    if (s.geography) acc[s.geography] = (acc[s.geography] || 0) + 1;
    return acc;
  }, {});

  // Drug/entity distribution
  const byDrug = signals.reduce((acc, s) => {
    const drug = s.drug_name || s.entity_name;
    if (drug) acc[drug] = (acc[drug] || 0) + 1;
    return acc;
  }, {});

  // Severity breakdown
  const bySeverity = signals.reduce((acc, s) => {
    const sev = s._aiSeverity?.toUpperCase() || 'UNKNOWN';
    acc[sev] = (acc[sev] || 0) + 1;
    return acc;
  }, {});

  // Merge status
  const byMergeStatus = signals.reduce((acc, s) => {
    acc[s.merge_status] = (acc[s.merge_status] || 0) + 1;
    return acc;
  }, {});

  // Quality tiers
  const byQualityTier = signals.reduce((acc, s) => {
    acc[s._qualityTier] = (acc[s._qualityTier] || 0) + 1;
    return acc;
  }, {});

  // Scoring stats
  const scores        = signals.map(s => safeNum(s.impact_score));
  const qualScores    = signals.map(s => safeNum(s.quality_score));
  const compScores    = signals.map(s => s._compositeScore);
  const avgScore      = scores.reduce((a, b) => a + b, 0) / (total || 1);
  const avgQuality    = qualScores.reduce((a, b) => a + b, 0) / (total || 1);
  const avgComposite  = compScores.reduce((a, b) => a + b, 0) / (total || 1);
  const maxComposite  = Math.max(...compScores);

  // AI processed ratio
  const aiProcessed   = signals.filter(s => s.ai_processed).length;
  const aiRatio       = total ? Math.round((aiProcessed / total) * 100) : 0;

  // Urgent signals
  const urgentCount   = signals.filter(s => s.is_urgent || s.notif_priority === 'P1').length;
  const p1Count       = signals.filter(s => s.notif_priority === 'P1').length;
  const p2Count       = signals.filter(s => s.notif_priority === 'P2').length;

  // Competitor flags
  const competitorHits = signals.filter(s => s.competitor_flag).length;

  // Duplicate risk
  const highDupRisk   = signals.filter(s => s.duplicaterisk === 'HIGH').length;

  // Needs review
  const needsReview   = signals.filter(s => s.triagehints?.needsreview === true).length;

  // Pipeline versions
  const pipelineVersions = [...new Set(signals.map(s => s._pipelineVersion))];

  // Top drugs by composite score
  const drugScores = {};
  signals.forEach(s => {
    const drug = s.drug_name || s.entity_name || 'Unknown';
    if (!drugScores[drug]) drugScores[drug] = { count: 0, totalScore: 0, signals: [] };
    drugScores[drug].count++;
    drugScores[drug].totalScore += s._compositeScore;
    drugScores[drug].signals.push(s.signal_type);
  });

  const topDrugs = Object.entries(drugScores)
    .map(([drug, data]) => ({
      drug,
      count: data.count,
      avgScore: Math.round(data.totalScore / data.count * 10) / 10,
      types: [...new Set(data.signals)]
    }))
    .sort((a, b) => b.avgScore - a.avgScore)
    .slice(0, 10);

  return {
    total, byDomain, byType, bySource, byGeo, byDrug, bySeverity,
    byMergeStatus, byQualityTier,
    avgScore: Math.round(avgScore * 10) / 10,
    avgQuality: Math.round(avgQuality * 10) / 10,
    avgComposite: Math.round(avgComposite * 10) / 10,
    maxComposite,
    aiProcessed, aiRatio,
    urgentCount, p1Count, p2Count,
    competitorHits, highDupRisk, needsReview,
    pipelineVersions, topDrugs
  };
};

