      lines.push(`  ${(DOMAIN_EMOJI[domain] || '📌')} ${domain.padEnd(15)} ${bar} ${count} signals (${pct}%)`);
    });

  return lines.join('\n');
};

const buildSignalMatrix = (signals) => {
  const lines = [
    ``,
    `  ┌─────────────────────────────────────────────────────────────────────────┐`,
    `  │                    📡  SIGNAL INTELLIGENCE MATRIX                       │`,
    `  └─────────────────────────────────────────────────────────────────────────┘`,
    ``,
    `  ${'ID'.padEnd(6)} ${'PRI'.padEnd(5)} ${'DOM'.padEnd(12)} ${'TYPE'.padEnd(12)} ${'DRUG'.padEnd(20)} ${'SEV'.padEnd(10)} ${'SCORE'.padEnd(7)} ${'QUAL'.padEnd(6)} ${'AGE'}`,
    `  ${'─'.repeat(94)}`,
  ];

  signals
    .sort((a, b) => b._compositeScore - a._compositeScore)
    .forEach(s => {
      const id       = String(s.id || '—').padEnd(6);
