      const score    = String(s._compositeScore).padEnd(7);
      const qual     = String(safeNum(s.quality_score)).padEnd(6);
      const age      = s._daysAgo !== null ? `${s._daysAgo}d ago` : '—';
      lines.push(`  ${id} ${pri} ${domain} ${type} ${drug} ${sev} ${score} ${qual} ${age}`);
    });

  return lines.join('\n');
};

const buildDeepDiveSignals = (signals) => {
