    // Quality Flags
    lines.push(`  🏴 QUALITY FLAGS`);
    if (Array.isArray(s.qualityflags) && s.qualityflags.length > 0) {
      s.qualityflags.forEach(f => lines.push(`     ⚑ ${f}`));
    } else {
      lines.push(`     ✓ No quality flags`);
    }
    lines.push(``);

    // Alert Channels
    lines.push(`  📢 ALERT CHANNELS`);
    lines.push(`     ${channels || 'No channels configured'}`);
    lines.push(``);

    // Override Status
    lines.push(`  🔧 OVERRIDE / REVIEW STATUS`);
    lines.push(`     Override Status   : ${safe(s.override_status, 'None')}`);
    lines.push(`     Override By       : ${safe(s.override_by, 'N/A')}`);
    lines.push(`     Override Reason   : ${safe(s.override_reason, 'N/A')}`);
    lines.push(``);

    // Timeline
    lines.push(`  🕐 TIMELINE`);
    lines.push(`     First Seen        : ${formatDate(s.first_seen_at)}  (${s._daysAgo !== null ? s._daysAgo + ' days ago' : '—'})`);
    lines.push(`     Last Seen         : ${formatDate(s.last_seen_at)}`);
    lines.push(`     Ingested At       : ${formatDate(s.ingested_at)}`);
    lines.push(`     Normalized At     : ${formatDate(s._normalizedAt)}`);
