    // Summary & Raw Intelligence
    lines.push(`  📝 INTELLIGENCE SUMMARY`);
    lines.push(`  ${'─'.repeat(75)}`);
    (safe(s.summary, '').match(/.{1,80}/g) || []).forEach(l => lines.push(`  ${l}`));
    lines.push(``);
  });

  return lines.join('\n');
};

const buildAnalyticsReport = (a) => {
  const lines = [
    ``,
    `  ┌─────────────────────────────────────────────────────────────────────────┐`,
    `  │                    📈  ANALYTICS & INTELLIGENCE METRICS                 │`,
    `  └─────────────────────────────────────────────────────────────────────────┘`,
    ``,
    `  ── SIGNAL TYPE BREAKDOWN ──────────────────────────────────────────────────`,
  ];

  Object.entries(a.byType).sort((x, y) => y[1] - x[1]).forEach(([type, count]) => {
    const pct = Math.round((count / a.total) * 100);
    lines.push(`  ${(SIGNAL_EMOJI[type] || '📎')} ${type.padEnd(18)} ${'█'.repeat(Math.round(pct/3))} ${count} (${pct}%)`);
  });

  lines.push(``);
  lines.push(`  ── SOURCE CHANNEL BREAKDOWN ───────────────────────────────────────────────`);
  Object.entries(a.bySource).sort((x, y) => y[1] - x[1]).forEach(([src, count]) => {
    lines.push(`  📡 ${src.padEnd(25)} ${count} signal(s)`);
  });

  lines.push(``);
  lines.push(`  ── SEVERITY DISTRIBUTION ──────────────────────────────────────────────────`);
  const sevOrder = ['CRITICAL', 'HIGH', 'MODERATE', 'LOW', 'UNKNOWN'];
  sevOrder.forEach(sev => {
    if (a.bySeverity[sev]) {
      const count = a.bySeverity[sev];
      const pct   = Math.round((count / a.total) * 100);
      const emoji = { CRITICAL: '🔴', HIGH: '🟠', MODERATE: '🟡', LOW: '🟢', UNKNOWN: '⚪' }[sev];
      lines.push(`  ${emoji} ${sev.padEnd(12)} ${'█'.repeat(Math.round(pct/4))} ${count} (${pct}%)`);
    }
  });

  lines.push(``);
  lines.push(`  ── QUALITY TIER DISTRIBUTION ──────────────────────────────────────────────`);
  Object.entries(a.byQualityTier).sort((x, y) => y[1] - x[1]).forEach(([tier, count]) => {
    lines.push(`  ◈ ${tier.padEnd(15)} ${count} signal(s)`);
  });

  lines.push(``);
  lines.push(`  ── MERGE STATUS ────────────────────────────────────────────────────────────`);
  Object.entries(a.byMergeStatus).sort((x, y) => y[1] - x[1]).forEach(([status, count]) => {
    lines.push(`  ◉ ${status.padEnd(15)} ${count} signal(s)`);
  });

  lines.push(``);
  lines.push(`  ── GEOGRAPHIC DISTRIBUTION ─────────────────────────────────────────────────`);
  Object.entries(a.byGeo).sort((x, y) => y[1] - x[1]).slice(0, 15).forEach(([geo, count]) => {
    lines.push(`  🌍 ${geo.padEnd(8)} ${count} signal(s)`);
  });

  lines.push(``);
  lines.push(`  ── TOP DRUGS BY COMPOSITE RISK SCORE ──────────────────────────────────────`);
  lines.push(`  ${'DRUG'.padEnd(25)} ${'SIGNALS'.padEnd(10)} ${'AVG SCORE'.padEnd(12)} SIGNAL TYPES`);
  lines.push(`  ${'─'.repeat(75)}`);
  a.topDrugs.forEach(d => {
    lines.push(`  ${d.drug.padEnd(25)} ${String(d.count).padEnd(10)} ${String(d.avgScore).padEnd(12)} ${d.types.join(', ')}`);
  });

  return lines.join('\n');
};

const buildActionItems = (signals) => {
  const lines = [
    ``,
    `  ┌─────────────────────────────────────────────────────────────────────────┐`,
    `  │                    ⚡  ACTION ITEMS & RECOMMENDATIONS                   │`,
    `  └─────────────────────────────────────────────────────────────────────────┘`,
    ``,
  ];

  // Immediate escalations
  const immediate = signals.filter(s => s.is_urgent || s.notif_priority === 'P1');
  if (immediate.length) {
    lines.push(`  🚨 IMMEDIATE ESCALATION REQUIRED`);
    immediate.forEach(s => {
      lines.push(`  ▸ [${s.notif_priority}] ${truncate(s.title, 80)}`);
      lines.push(`    → Drug: ${safe(s.drug_name)} | Domain: ${s.signal_domain} | Route: ${s.route_tier}`);
      lines.push(`    → Action: ${safe(s.recommended_action, 'Review and assign recommended action')}`);
      lines.push(``);
    });
  }

  // P2 review
  const p2 = signals.filter(s => s.notif_priority === 'P2' && !s.is_urgent);
  if (p2.length) {
    lines.push(`  🟠 P2 — HIGH PRIORITY REVIEW (within 24h)`);
    p2.slice(0, 5).forEach(s => {
      lines.push(`  ▸ ${truncate(s.title, 80)}`);
      lines.push(`    → Drug: ${safe(s.drug_name)} | Score: ${s._compositeScore}`);
    });
    lines.push(``);
  }

  // Quality issues
  const qualityIssues = signals.filter(s =>
    Array.isArray(s.qualityflags) && s.qualityflags.length > 2
  );
  if (qualityIssues.length) {
    lines.push(`  🏴 DATA QUALITY — SIGNALS REQUIRING ENRICHMENT`);
    qualityIssues.slice(0, 5).forEach(s => {
      lines.push(`  ▸ ID ${s.id}: ${truncate(s.title, 60)}`);
      lines.push(`    → Flags: ${s.qualityflags.join(', ')}`);
    });
    lines.push(``);
  }

  // Competitor flags
  const competitors = signals.filter(s => s.competitor_flag);
  if (competitors.length) {
    lines.push(`  🎯 COMPETITOR INTELLIGENCE ALERTS`);
    competitors.forEach(s => {
      lines.push(`  ▸ ${truncate(s.title, 80)}`);
      lines.push(`    → Drug: ${safe(s.drug_name)} | Sponsor: ${safe(s.sponsor)} | Domain: ${s.signal_domain}`);
    });
    lines.push(``);
  }

  // Needs review
  const reviewNeeded = signals.filter(s => s.triagehints?.needsreview === true);
  if (reviewNeeded.length) {
    lines.push(`  🔍 MANUAL REVIEW QUEUE`);
    reviewNeeded.slice(0, 5).forEach(s => {
      lines.push(`  ▸ ID ${s.id}: ${truncate(s.title, 70)}`);
    });
    lines.push(``);
  }

  // Unprocessed by AI
  const unprocessed = signals.filter(s => !s.ai_processed);
  if (unprocessed.length) {
    lines.push(`  🤖 AI PROCESSING QUEUE — ${unprocessed.length} signal(s) pending AI analysis`);
    unprocessed.slice(0, 3).forEach(s => {
      lines.push(`  ▸ ID ${s.id}: ${truncate(s.title, 70)}`);
    });
    lines.push(``);
  }

  return lines.join('\n');
};

