const items = $input.all();

// ─── HELPERS ──────────────────────────────────────────────────────────────────
const safe      = (v, fb = '—')  => (v === null || v === undefined || v === '') ? fb : v;
const safeNum   = (v, fb = 0)    => isNaN(Number(v)) ? fb : Number(v);
const pct       = (n, t)         => t ? Math.round((n / t) * 100) : 0;
const clamp     = (v, lo, hi)    => Math.min(hi, Math.max(lo, v));
const parseJ    = (v)            => { if (typeof v === 'object' && v !== null) return v; try { return JSON.parse(v); } catch { return {}; } };
const parseArr  = (v)            => { if (Array.isArray(v)) return v; try { const p = JSON.parse(v); return Array.isArray(p) ? p : []; } catch { return []; } };
const esc       = (s)            => String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const trunc     = (s, n = 120)   => { const str = String(s || ''); return str.length > n ? str.slice(0, n) + '…' : str; };
const fmtDate   = (iso)          => { if (!iso) return '—'; const d = new Date(iso); return isNaN(d) ? String(iso) : d.toLocaleDateString('en-US', { year:'numeric', month:'short', day:'2-digit' }); };
const fmtFull   = (iso)          => { if (!iso) return '—'; const d = new Date(iso); return isNaN(d) ? String(iso) : d.toLocaleString('en-US', { year:'numeric', month:'short', day:'2-digit', hour:'2-digit', minute:'2-digit', timeZoneName:'short' }); };
const daysAgo   = (iso)          => { if (!iso) return null; const diff = Date.now() - new Date(iso).getTime(); return Math.floor(diff / 86400000); };

const severityColor = (sev) => ({ CRITICAL:'#ef4444', HIGH:'#f97316', MODERATE:'#eab308', LOW:'#22c55e', MINIMAL:'#22c55e' }[(sev||'').toUpperCase()] || '#64748b');
const priorityColor = (p)   => ({ P1:'#ef4444', P2:'#f97316', P3:'#3b82f6', P4:'#64748b' }[p] || '#64748b');
const impactColor   = (i)   => ({ HIGH:'#ef4444', MED:'#f97316', LOW:'#eab308', MINIMAL:'#22c55e' }[i] || '#64748b');
const tierColor     = (t)   => ({ T1_URGENT:'#ef4444', T2_REVIEW:'#f97316', T3_MONITOR:'#3b82f6', T4_LOG:'#64748b' }[t] || '#94a3b8');

