const scoreBarHtml = (score, max, color = '#3b82f6', label = '', showNum = true) => {
  const p = clamp(Math.round((safeNum(score) / max) * 100), 0, 100);
  return `
  <div style="margin:4px 0;">
    ${label ? `<div style="display:flex;justify-content:space-between;margin-bottom:3px;">
