    </div>` : ''}
    <div style="height:6px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;">
      <div style="height:100%;width:${p}%;background:${color};border-radius:3px;transition:width 0.3s;"></div>
    </div>
  </div>`;
};

