// ─── DISTRIBUTION BAR ─────────────────────────────────────────────────────────
const distBar = (label, count, total, color = '#3b82f6') => {
  const p = clamp(Math.round((count / (total || 1)) * 100), 0, 100);
  return `
  <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;">
    <span style="font-size:9px;color:#64748b;width:110px;flex-shrink:0;font-family:'IBM Plex Mono',monospace;letter-spacing:0.5px;">${esc(label)}</span>
    <div style="flex:1;height:8px;background:rgba(255,255,255,0.05);border-radius:4px;overflow:hidden;">
      <div style="height:100%;width:${p}%;background:linear-gradient(90deg,${color},${color}99);border-radius:4px;"></div>
    </div>
    <span style="font-size:9px;color:${color};font-family:'IBM Plex Mono',monospace;font-weight:700;width:36px;text-align:right;">${count} <span style="color:#334155;">(${p}%)</span></span>
  </div>`;
};

// ─── ENRICH SIGNAL ────────────────────────────────────────────────────────────
const enrich = (s) => {
  const r = { ...s };
  r._meta    = parseJ(r._triage_meta);
  r._hints   = parseJ(r.triagehints);
  r._aiCls   = parseJ(r.ai_classification);
  r._scores  = parseJ(r.score_breakdown);
  r._flags   = parseArr(r.qualityflags);
  r._chans   = parseArr(r.alert_channels);
  r._rect    = r._meta?.rectification || {};
  r._sev     = (r._aiCls?.safetyseverity || r.safety_severity || 'UNKNOWN').toUpperCase();
  r._impact  = (r._aiCls?.patientimpact || r.patient_impact_estimate || 'UNKNOWN').toUpperCase();
  r._qtier   = r._meta?.qualitytier || r._hints?.qualitytier || 'UNKNOWN';
  r._normAt  = r._meta?.normalized_at || r._rect?.normalizedat;
  r._pver    = r._rect?.pipelineversion || r.pipelineversion || '—';
  r._days    = daysAgo(r.first_seen_at);
  r._sevCol  = severityColor(r._sev);
  r._priCol  = priorityColor(r.notif_priority);
  r._impCol  = impactColor(r.impact_level);
  r._tierCol = tierColor(r.route_tier);
  r._composite = (() => {
    const sevR  = { CRITICAL:4, HIGH:3, MODERATE:2, LOW:1, UNKNOWN:0 }[r._sev] || 0;
    const impR  = { WIDESPREAD:4, SIGNIFICANT:3, LIMITED:2, MINIMAL:1, UNKNOWN:0 }[r._impact] || 0;
    const priR  = { P1:4, P2:3, P3:2, P4:1 }[r.notif_priority] || 0;
    const tierR = { T1_URGENT:4, T2_REVIEW:3, T3_MONITOR:2, T4_LOG:1 }[r.route_tier] || 0;
    return Math.round(((sevR*2)+(impR*2)+(priR*1.5)+(tierR*1)+safeNum(r.impact_score)+(safeNum(r.quality_score)*0.5))*10)/10;
  })();
  return r;
};

