  <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(100,116,139,0.15);border-radius:4px;padding:16px;margin-bottom:16px;">
    <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">🔧 OVERRIDE & GOVERNANCE</div>
    ${fieldRow('Override Status', safe(s.override_status, 'None'), false, s.override_status ? '#f97316' : '#475569')}
    ${fieldRow('Override By',     safe(s.override_by, 'N/A'), false, '#94a3b8')}
    ${fieldRow('Override Reason', safe(s.override_reason, 'N/A'), false, '#94a3b8')}
    ${s.override_status ? `<div style="margin-top:8px;padding:8px;background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.2);border-radius:3px;font-size:9px;color:#fb923c;">
      ⚠ This signal has been manually overridden. Review override reason before acting.
    </div>` : `<div style="margin-top:8px;padding:6px 10px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:3px;font-size:9px;color:#4ade80;">
      ✓ No overrides — signal reflects original pipeline output
    </div>`}
  </div>`;

  const timelineSection = `
  <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.12);border-radius:4px;padding:16px;margin-bottom:16px;">
    <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">🕐 SIGNAL TIMELINE & LIFECYCLE</div>
    ${[
      { label:'First Seen At',    val: s.first_seen_at,  note: s._days !== null ? `${s._days} days ago` : '' },
      { label:'Last Seen At',     val: s.last_seen_at,   note: '' },
      { label:'Ingested At',      val: s.ingested_at,    note: '' },
      { label:'Merged At',        val: s.mergeat,        note: '' },
      { label:'Normalized At',    val: s._normAt,        note: '' },
    ].map(t => `
    <div style="display:flex;align-items:flex-start;gap:10px;padding:6px 0;border-bottom:1px solid rgba(255,255,255,0.03);">
      <div style="width:8px;height:8px;background:#3b82f6;border-radius:50%;margin-top:4px;flex-shrink:0;"></div>
      <div style="flex:1;">
        <div style="font-size:8px;color:#475569;letter-spacing:1.5px;text-transform:uppercase;font-family:'IBM Plex Mono',monospace;">${esc(t.label)}</div>
        <div style="font-size:10px;color:#94a3b8;font-family:'IBM Plex Mono',monospace;margin-top:1px;">${esc(fmtFull(t.val))} ${t.note ? `<span style="color:#60a5fa;">(${t.note})</span>` : ''}</div>
      </div>
    </div>`).join('')}
  </div>`;

  const summarySection = `
  <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.12);border-radius:4px;padding:16px;margin-bottom:16px;">
    <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">📝 INTELLIGENCE SUMMARY</div>
    <div style="font-size:11px;color:#cbd5e1;line-height:1.8;padding:12px;background:rgba(0,0,0,0.2);border-radius:3px;border-left:3px solid #3b82f6;">
      ${esc(safe(s.summary, 'No summary available for this signal.'))}
    </div>
  </div>`;

  const rawTextSection = s.raw_text ? `
  <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.12);border-radius:4px;padding:16px;margin-bottom:16px;">
    <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">📄 RAW SIGNAL TEXT (FULL)</div>
    <div style="font-size:9px;color:#64748b;line-height:1.7;font-family:'IBM Plex Mono',monospace;white-space:pre-wrap;background:rgba(0,0,0,0.3);padding:12px;border-radius:3px;max-height:400px;overflow-y:auto;">${esc(s.raw_text)}</div>
  </div>` : '';

  return `
  <div style="background:rgba(10,14,26,0.9);border:1px solid rgba(59,130,246,0.2);border-radius:6px;margin-bottom:30px;overflow:hidden;page-break-inside:avoid;">
    <!-- Signal Card Header -->
    <div style="background:linear-gradient(135deg,rgba(15,23,42,0.95) 0%,rgba(17,24,39,0.95) 100%);padding:20px 24px;border-bottom:1px solid rgba(59,130,246,0.2);">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:16px;">
        <div style="flex:1;">
          <div style="font-size:10px;color:#475569;font-family:'IBM Plex Mono',monospace;letter-spacing:1px;margin-bottom:6px;">
            SIGNAL #${idx + 1} &nbsp;·&nbsp; ID: ${esc(safe(s.id))} &nbsp;·&nbsp; ${esc(safe(s.source_id))}
          </div>
          <div style="font-size:13px;font-weight:700;color:#f1f5f9;line-height:1.4;margin-bottom:10px;">${esc(trunc(safe(s.title), 150))}</div>
          <div style="display:flex;gap:6px;flex-wrap:wrap;">
            ${badge(safe(s.notif_priority), priorityColor(s.notif_priority))}
            ${badge(safe(s.signal_domain), '#34d399')}
            ${badge(safe(s.signal_type), '#60a5fa')}
            ${badge(safe(s.impact_level), impactColor(s.impact_level))}
            ${badge(safe(s.route_tier), tierColor(s.route_tier))}
            ${s.is_urgent ? badge('🚨 URGENT', '#ef4444') : ''}
            ${s.competitor_flag ? badge('🎯 COMPETITOR', '#fbbf24') : ''}
            ${s.ai_processed ? badge('🤖 AI PROCESSED', '#a78bfa') : badge('⏳ AI PENDING', '#64748b')}
          </div>
        </div>
        <div style="text-align:right;flex-shrink:0;">
          <div style="font-size:28px;font-weight:700;color:${s._composite > 14 ? '#ef4444' : s._composite > 8 ? '#f97316' : '#22c55e'};font-family:'IBM Plex Mono',monospace;line-height:1;">${s._composite}</div>
          <div style="font-size:8px;color:#334155;letter-spacing:1.5px;text-transform:uppercase;font-family:'IBM Plex Mono',monospace;">COMPOSITE<br/>RISK SCORE</div>
          <div style="margin-top:8px;font-size:9px;color:#475569;font-family:'IBM Plex Mono',monospace;">${s._days !== null ? s._days + 'd ago' : '—'}</div>
        </div>
      </div>
    </div>

    <!-- Signal Card Body -->
    <div style="padding:20px 24px;">
      ${urgentBanner}
      ${competitorBanner}
      ${scoreSection}
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
        <div>
          ${coreIdentity}
          ${riskAssessment}
          ${overrideSection}
          ${timelineSection}
        </div>
        <div>
          ${drugAsset}
          ${aiSection}
          ${triageSection}
        </div>
      </div>
      ${qualitySection}
      ${summarySection}
      ${rawTextSection}
    </div>
  </div>`;
};

