// ANALYTICS PAGE
// ══════════════════════════════════════════════════════════════════════════════
const analyticsPage = (a, signals) => {
  if (!a) return '';
  const total = a.total_signals || signals.length;
  const by = (obj, color) => Object.entries(obj || {}).sort((x,y)=>y[1]-x[1]).map(([k,v]) => distBar(k, v, total, color)).join('');

  return `
  <div style="padding:30px 40px;page-break-before:always;">
    ${sectionHeader('📈', 'Analytics & Intelligence Metrics', `${total} signals · ${Object.keys(a.by_domain||{}).length} domains · ${Object.keys(a.by_source||{}).length} sources`)}

    <!-- KPI Row -->
    <div style="display:grid;grid-template-columns:repeat(5,1fr);gap:0;border:1px solid rgba(59,130,246,0.2);border-radius:4px;overflow:hidden;margin-bottom:24px;">
      ${[
        { label:'Total Signals',    val: total,                      col:'#3b82f6' },
        { label:'Urgent / P1',      val: a.urgent_count ?? 0,        col:'#ef4444' },
        { label:'Competitor Flags', val: a.competitor_hits ?? 0,     col:'#fbbf24' },
        { label:'AI Coverage',      val: (a.ai_coverage_pct??0)+'%', col:'#a78bfa' },
        { label:'Avg Risk Score',   val: a.avg_composite ?? '—',     col:'#f97316' },
      ].map((k,i) => `
      <div style="padding:18px 14px;background:rgba(15,23,42,0.8);${i<4?'border-right:1px solid rgba(59,130,246,0.15);':''}text-align:center;">
        <div style="font-size:24px;font-weight:700;color:${k.col};font-family:'IBM Plex Mono',monospace;line-height:1;">${esc(String(k.val))}</div>
        <div style="font-size:8px;color:#334155;letter-spacing:1.5px;text-transform:uppercase;font-family:'IBM Plex Mono',monospace;margin-top:4px;">${k.label}</div>
      </div>`).join('')}
    </div>

    <!-- Additional KPIs -->
    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:0;border:1px solid rgba(59,130,246,0.1);border-radius:4px;overflow:hidden;margin-bottom:24px;">
      ${[
        { label:'Avg Quality Score', val: a.avg_quality ?? '—',        col:'#3b82f6' },
        { label:'Duplicate Risk High', val: a.high_dup_risk ?? 0,      col:'#ef4444' },
        { label:'Needs Review',      val: a.needs_review ?? 0,         col:'#f97316' },
        { label:'P2 Signals',        val: signals.filter(s=>s.notif_priority==='P2').length, col:'#f97316' },
      ].map((k,i) => `
      <div style="padding:14px;background:rgba(10,14,26,0.6);${i<3?'border-right:1px solid rgba(59,130,246,0.1);':''}text-align:center;">
        <div style="font-size:20px;font-weight:700;color:${k.col};font-family:'IBM Plex Mono',monospace;">${esc(String(k.val))}</div>
        <div style="font-size:7px;color:#334155;letter-spacing:1.5px;text-transform:uppercase;font-family:'IBM Plex Mono',monospace;margin-top:3px;">${k.label}</div>
      </div>`).join('')}
    </div>

    <!-- Distribution grids -->
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:24px;">
      <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;">
        <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">BY DOMAIN</div>
        ${by(a.by_domain, '#34d399')}
      </div>
      <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;">
        <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">BY SIGNAL TYPE</div>
        ${by(a.by_type, '#60a5fa')}
      </div>
      <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;">
        <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">BY SAFETY SEVERITY</div>
        ${Object.entries(a.by_severity||{}).sort((x,y)=>y[1]-x[1]).map(([k,v]) => distBar(k, v, total, severityColor(k))).join('')}
      </div>
      <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;">
        <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">BY SOURCE CHANNEL</div>
        ${by(a.by_source, '#a78bfa')}
      </div>
      <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;">
        <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">BY QUALITY TIER</div>
        ${by(a.by_quality_tier, '#fbbf24')}
      </div>
      <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;">
        <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">BY MERGE STATUS</div>
        ${by(a.by_merge_status, '#34d399')}
      </div>
    </div>

    <!-- Top Drugs Table -->
    ${(a.top_drugs||[]).length ? `
    <div style="background:rgba(15,23,42,0.6);border:1px solid rgba(59,130,246,0.15);border-radius:4px;padding:16px;margin-bottom:24px;">
      <div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#475569;font-family:'IBM Plex Mono',monospace;margin-bottom:12px;">TOP DRUGS BY COMPOSITE RISK SCORE</div>
      <table style="width:100%;border-collapse:collapse;font-size:9px;">
        <thead>
          <tr style="background:rgba(59,130,246,0.08);">
            ${['DRUG','SIGNALS','AVG SCORE','SIGNAL TYPES'].map(h => `<th style="padding:8px 10px;text-align:left;color:#334155;font-family:'IBM Plex Mono',monospace;letter-spacing:1.5px;font-size:8px;border-bottom:1px solid rgba(59,130,246,0.15);">${h}</th>`).join('')}
          </tr>
        </thead>
        <tbody>
          ${(a.top_drugs||[]).map((d,i) => `
          <tr style="border-bottom:1px solid rgba(255,255,255,0.03);">
            <td style="padding:8px 10px;color:#f1f5f9;font-weight:600;">${esc(d.drug)}</td>
            <td style="padding:8px 10px;color:#60a5fa;font-family:'IBM Plex Mono',monospace;">${d.count}</td>
            <td style="padding:8px 10px;color:${d.avgScore > 12 ? '#ef4444' : d.avgScore > 7 ? '#f97316' : '#22c55e'};font-family:'IBM Plex Mono',monospace;font-weight:700;">${d.avgScore}</td>
            <td style="padding:8px 10px;color:#64748b;font-size:8px;">${esc((d.types||[]).join(', '))}</td>
          </tr>`).join('')}
        </tbody>
      </table>
    </div>` : ''}
  </div>`;
};

