// ACTION ITEMS PAGE
// ══════════════════════════════════════════════════════════════════════════════
const actionItemsPage = (signals) => {
  const urgent     = signals.filter(s => s.is_urgent || s.notif_priority === 'P1');
  const p2         = signals.filter(s => s.notif_priority === 'P2' && !s.is_urgent);
  const competitor = signals.filter(s => s.competitor_flag);
  const noAction   = signals.filter(s => !s.recommended_action);
  const noAI       = signals.filter(s => !s.ai_processed);
  const highDup    = signals.filter(s => s.duplicaterisk === 'HIGH');
  const review     = signals.filter(s => s._hints?.needsreview === true);

  const actionGroup = (title, icon, color, items, renderFn) => items.length ? `
  <div style="margin-bottom:20px;">
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
      <span style="font-size:14px;">${icon}</span>
      <span style="font-size:11px;font-weight:700;color:${color};letter-spacing:1px;font-family:'IBM Plex Mono',monospace;">${esc(title)}</span>
      <span style="background:${color}22;border:1px solid ${color}44;color:${color};font-size:9px;padding:1px 7px;border-radius:10px;font-family:'IBM Plex Mono',monospace;">${items.length}</span>
    </div>
    ${items.map(renderFn).join('')}
  </div>` : '';

  return `
  <div style="padding:30px 40px;page-break-before:always;">
    ${sectionHeader('⚡', 'Action Items & Recommendations', 'Auto-generated from signal intelligence engine')}

    ${!urgent.length && !p2.length && !competitor.length ? `
    <div style="padding:20px;background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.2);border-radius:4px;text-align:center;color:#4ade80;font-family:'IBM Plex Mono',monospace;margin-bottom:20px;">
      ✓ No urgent escalations at this time — all signals within normal processing thresholds
    </div>` : ''}

    ${actionGroup('IMMEDIATE ESCALATION — Action within 2 hours', '🚨', '#ef4444', urgent, s => `
    <div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.25);border-radius:3px;padding:12px 14px;margin-bottom:8px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;">
        <div style="flex:1;">
          <div style="font-size:10px;font-weight:700;color:#fca5a5;margin-bottom:4px;">${esc(trunc(safe(s.title), 100))}</div>
          <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:6px;">
            ${badge(safe(s.notif_priority), '#ef4444')}
            ${badge(safe(s.signal_domain), '#34d399')}
            ${badge(safe(s.signal_type), '#60a5fa')}
          </div>
          <div style="font-size:9px;color:#64748b;">Drug: <span style="color:#94a3b8;">${esc(safe(s.drug_name))}</span> &nbsp;|&nbsp; Source: <span style="color:#94a3b8;">${esc(safe(s.source))}</span> &nbsp;|&nbsp; Score: <span style="color:#ef4444;font-weight:700;">${s._composite}</span></div>
          <div style="font-size:9px;color:#64748b;margin-top:3px;">Action: <span style="color:${s.recommended_action ? '#4ade80' : '#f87171'}">${esc(safe(s.recommended_action, '⚠ No recommended action — assign immediately'))}</span></div>
        </div>
        <div style="flex-shrink:0;text-align:right;">
          <div style="font-size:18px;font-weight:700;color:#ef4444;font-family:'IBM Plex Mono',monospace;">${s._composite}</div>
          <div style="font-size:7px;color:#475569;font-family:'IBM Plex Mono',monospace;">RISK</div>
        </div>
      </div>
    </div>`)}

    ${actionGroup('P2 HIGH PRIORITY — Review within 24 hours', '🟠', '#f97316', p2, s => `
    <div style="background:rgba(249,115,22,0.06);border:1px solid rgba(249,115,22,0.2);border-radius:3px;padding:10px 14px;margin-bottom:6px;">
      <div style="font-size:10px;font-weight:600;color:#fdba74;margin-bottom:3px;">${esc(trunc(safe(s.title), 100))}</div>
      <div style="font-size:9px;color:#64748b;">Drug: <span style="color:#94a3b8;">${esc(safe(s.drug_name))}</span> &nbsp;|&nbsp; Domain: <span style="color:#94a3b8;">${esc(safe(s.signal_domain))}</span> &nbsp;|&nbsp; Score: <span style="color:#f97316;font-weight:700;">${s._composite}</span></div>
    </div>`)}

    ${actionGroup('COMPETITOR INTELLIGENCE — Portfolio Impact Assessment', '🎯', '#fbbf24', competitor, s => `
    <div style="background:rgba(251,191,36,0.06);border:1px solid rgba(251,191,36,0.2);border-radius:3px;padding:10px 14px;margin-bottom:6px;">
      <div style="font-size:10px;font-weight:600;color:#fde68a;margin-bottom:3px;">${esc(trunc(safe(s.title), 100))}</div>
      <div style="font-size:9px;color:#64748b;">Drug: <span style="color:#94a3b8;">${esc(safe(s.drug_name))}</span> &nbsp;|&nbsp; Sponsor: <span style="color:#94a3b8;">${esc(trunc(safe(s.sponsor), 50))}</span></div>
    </div>`)}

    ${actionGroup('MISSING RECOMMENDED ACTION — Assign Before Routing', '📌', '#3b82f6', noAction, s => `
    <div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);border-radius:3px;padding:8px 12px;margin-bottom:5px;">
      <div style="font-size:9px;color:#93c5fd;">ID ${esc(safe(s.id))}: ${esc(trunc(safe(s.title), 80))}</div>
    </div>`)}

    ${actionGroup('AI PROCESSING QUEUE — Pending Analysis', '🤖', '#a78bfa', noAI, s => `
    <div style="background:rgba(139,92,246,0.06);border:1px solid rgba(139,92,246,0.15);border-radius:3px;padding:8px 12px;margin-bottom:5px;">
      <div style="font-size:9px;color:#c4b5fd;">ID ${esc(safe(s.id))}: ${esc(trunc(safe(s.title), 80))}</div>
    </div>`)}

    ${actionGroup('HIGH DUPLICATE RISK — Dedup Verification Required', '⚠️', '#ef4444', highDup, s => `
    <div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:3px;padding:8px 12px;margin-bottom:5px;">
      <div style="font-size:9px;color:#fca5a5;">ID ${esc(safe(s.id))}: ${esc(trunc(safe(s.title), 80))} <span style="color:#475569;">· Hash: ${esc(safe(s.deduphash))}</span></div>
    </div>`)}

    ${actionGroup('MANUAL REVIEW QUEUE', '🔍', '#64748b', review, s => `
    <div style="background:rgba(100,116,139,0.06);border:1px solid rgba(100,116,139,0.15);border-radius:3px;padding:8px 12px;margin-bottom:5px;">
      <div style="font-size:9px;color:#94a3b8;">ID ${esc(safe(s.id))}: ${esc(trunc(safe(s.title), 80))}</div>
    </div>`)}
  </div>`;
};

