const matrixTable = (signals) => `
  <div style="padding:30px 40px;page-break-before:always;">
    ${sectionHeader('📡', 'Signal Intelligence Matrix', `All ${signals.length} signals sorted by composite risk score`)}
    <div style="overflow-x:auto;">
      <table style="width:100%;border-collapse:collapse;font-size:8px;">
        <thead>
          <tr style="background:rgba(59,130,246,0.1);">
            ${['ID','PRI','DOMAIN','TYPE','DRUG','GEOGRAPHY','SEVERITY','IMPACT','SCORE','QUALITY','DUP RISK','MERGE','AI','AGE'].map(h =>
              `<th style="padding:8px 8px;text-align:left;color:#334155;font-family:'IBM Plex Mono',monospace;letter-spacing:1px;font-size:7px;border-bottom:1px solid rgba(59,130,246,0.2);white-space:nowrap;">${h}</th>`
            ).join('')}
          </tr>
        </thead>
        <tbody>
          ${[...signals].sort((a,b) => b._composite - a._composite).map((s,i) => `
          <tr style="border-bottom:1px solid rgba(255,255,255,0.03);${i%2===0?'background:rgba(255,255,255,0.01);':''}">
            <td style="padding:7px 8px;color:#60a5fa;font-family:'IBM Plex Mono',monospace;">${esc(safe(s.id))}</td>
            <td style="padding:7px 8px;"><span style="color:${priorityColor(s.notif_priority)};font-weight:700;font-family:'IBM Plex Mono',monospace;">${esc(safe(s.notif_priority))}</span></td>
            <td style="padding:7px 8px;color:#34d399;">${esc(safe(s.signal_domain))}</td>
            <td style="padding:7px 8px;color:#94a3b8;font-family:'IBM Plex Mono',monospace;">${esc(safe(s.signal_type))}</td>
            <td style="padding:7px 8px;color:#f1f5f9;font-weight:600;">${esc(trunc(safe(s.drug_name || s.entity_name), 16))}</td>
            <td style="padding:7px 8px;color:#fbbf24;">${esc(safe(s.geography))}</td>
            <td style="padding:7px 8px;color:${s._sevCol};font-weight:600;">${esc(s._sev)}</td>
            <td style="padding:7px 8px;color:${s._impCol};">${esc(safe(s.impact_level))}</td>
            <td style="padding:7px 8px;color:${s._composite > 14 ? '#ef4444' : s._composite > 8 ? '#f97316' : '#22c55e'};font-weight:700;font-family:'IBM Plex Mono',monospace;">${s._composite}</td>
            <td style="padding:7px 8px;color:#3b82f6;font-family:'IBM Plex Mono',monospace;">${esc(safe(s.quality_score))}</td>
            <td style="padding:7px 8px;color:${s.duplicaterisk==='HIGH'?'#ef4444':'#475569'};">${esc(safe(s.duplicaterisk))}</td>
            <td style="padding:7px 8px;color:${s.merge_status==='READY'?'#34d399':'#f97316'};font-family:'IBM Plex Mono',monospace;">${esc(safe(s.merge_status))}</td>
            <td style="padding:7px 8px;text-align:center;">${s.ai_processed ? '✅' : '⏳'}</td>
            <td style="padding:7px 8px;color:#475569;font-family:'IBM Plex Mono',monospace;">${s._days !== null ? s._days+'d' : '—'}</td>
          </tr>`).join('')}
        </tbody>
      </table>
    </div>
  </div>`;

// ══════════════════════════════════════════════════════════════════════════════
// MAIN HTML ASSEMBLY
// ══════════════════════════════════════════════════════════════════════════════
const buildHTML = (signals, firstItem) => {
