  <div>
    <div style="display:inline-block;background:rgba(59,130,246,0.1);border:1px solid rgba(59,130,246,0.35);color:#60a5fa;font-family:'DM Mono',monospace;font-size:9px;letter-spacing:3px;text-transform:uppercase;padding:7px 18px;border-radius:2px;margin-bottom:40px;">
      ⬡ PharmaOS · Signal Intelligence Platform · Confidential
    </div>

    <div style="font-size:52px;font-weight:800;color:#ffffff;line-height:1.05;letter-spacing:-2px;margin-bottom:12px;font-family:'Syne',sans-serif;">
