    </div>
    <div style="font-size:14px;color:#334155;letter-spacing:4px;text-transform:uppercase;font-family:'DM Mono',monospace;margin-bottom:50px;">
      Signals · Safety · Regulatory · Pipeline
    </div>

    <!-- Cover KPIs -->
    <div style="display:grid;grid-template-columns:repeat(4,1fr);border:1px solid rgba(59,130,246,0.2);border-radius:4px;overflow:hidden;margin-bottom:30px;">
