        { label:'Total Signals',    val: a?.total_signals ?? signals.length, col:'#3b82f6', desc:'Across all channels' },
        { label:'Urgent / P1',      val: a?.urgent_count ?? signals.filter(s=>s.is_urgent||s.notif_priority==='P1').length, col:'#ef4444', desc:'Immediate action' },
        { label:'Competitor Flags', val: a?.competitor_hits ?? signals.filter(s=>s.competitor_flag).length, col:'#fbbf24', desc:'Portfolio impact' },
        { label:'AI Coverage',      val: (a?.ai_coverage_pct ?? Math.round((signals.filter(s=>s.ai_processed).length/signals.length)*100))+'%', col:'#a78bfa', desc:'Signals AI-analyzed' },
      ].map((k,i) => `
      <div style="padding:22px 18px;background:rgba(15,23,42,0.8);${i<3?'border-right:1px solid rgba(59,130,246,0.15);':''}">
        <div style="font-size:36px;font-weight:800;color:${k.col};font-family:'DM Mono',monospace;line-height:1;margin-bottom:4px;">${esc(String(k.val))}</div>
        <div style="font-size:10px;font-weight:700;color:#e2e8f0;margin-bottom:2px;">${k.label}</div>
        <div style="font-size:8px;color:#334155;letter-spacing:1px;">${k.desc}</div>
      </div>`).join('')}
    </div>

    <!-- Risk gauge row -->
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:30px;">
      ${[
        { label:'Avg Composite Risk', val: a?.avg_composite ?? '—', max:20, col:'#f97316' },
        { label:'Avg Data Quality',   val: a?.avg_quality   ?? '—', max:10, col:'#3b82f6' },
