        <div style="height:4px;background:rgba(255,255,255,0.05);border-radius:2px;overflow:hidden;">
          <div style="height:100%;width:${clamp(Math.round((safeNum(k.val)/k.max)*100),0,100)}%;background:${k.col};border-radius:2px;"></div>
