<!-- ══════════════════════ FOOTER ══════════════════════ -->
<div style="background:rgba(6,11,20,0.98);border-top:1px solid rgba(59,130,246,0.2);padding:14px 50px;display:flex;justify-content:space-between;align-items:center;">
