</html>`;
};

// ══════════════════════════════════════════════════════════════════════════════
// EXECUTE
// ══════════════════════════════════════════════════════════════════════════════
const signals    = items.map(item => enrich(item.json));
const firstItem  = items[0]?.json || {};
const digestHtml = buildHTML(signals, firstItem);

return [{ json: { ...firstItem, digest_html: digestHtml, digest_html_length: digestHtml.length } }];
